-- Poems batch 94
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('750507f6-e3a0-4c58-83cc-eb3ab58b82f9','和李參政頌示鑒禪者','釋曇華','宋','宋诗','song-poetry','','[]','清源居士頂門著，從本已來自寥廓。',64,'全唐诗/poet.song.112000.json','["清源居士頂門著，從本已來自寥廓。", "更透吾家向上關，活鱍鱍地難收捉。", "風塵草動鑒來端，臨機八面初無作。", "纔起分毫取與心，即被邪師籠罩却。"]'),
('13a1bb2f-7fda-4e54-83a7-faef96f702e3','贈別俗兄','釋曇華','宋','宋诗','song-poetry','','[]','此行安忍泛輕舟，無奈官差不自由。',32,'全唐诗/poet.song.112000.json','["此行安忍泛輕舟，無奈官差不自由。", "痛望老人修浄業，莫教容易度春秋。"]'),
('d14b9d61-2bf6-4ffd-b6ab-45c9f7a596bd','題劉民用居士藏六庵  其一','釋曇華','宋','宋诗','song-poetry','','[]','西溪縛屋稱幽居，坐對松窗與世疏。',32,'全唐诗/poet.song.112000.json','["西溪縛屋稱幽居，坐對松窗與世疏。", "到眼青山千萬疊，此生安樂更無如。"]'),
('7ec5d731-fc1a-41f4-a4ca-d152ceff04c6','題劉民用居士藏六庵  其二','釋曇華','宋','宋诗','song-poetry','','[]','虛空正體沒邊涯，藏六如何蓋覆伊。',32,'全唐诗/poet.song.112000.json','["虛空正體沒邊涯，藏六如何蓋覆伊。", "要聽少林無孔笛，從來多是逆風吹。"]'),
('d967ce83-31d6-4fdd-b948-d71fe0737417','辭此庵和尚塔','釋曇華','宋','宋诗','song-poetry','','[]','道韵如山重，冰懷有紀綱。',48,'全唐诗/poet.song.112000.json','["道韵如山重，冰懷有紀綱。", "一拳成活業，千古更無雙。", "松竹森森老，雲山疊疊長。", "洛陽無限意，對此一爐香。"]'),
('bff9367b-2315-4f23-852b-942fef0ca174','示智道者','釋曇華','宋','宋诗','song-poetry','','[]','少室門庭冷似灰，長年不見一人來。',32,'全唐诗/poet.song.112000.json','["少室門庭冷似灰，長年不見一人來。", "汝今若解知慚愧，那取工夫到一回。"]'),
('48f727c9-4e05-440a-8736-04df468c4830','贈成主簿','釋曇華','宋','宋诗','song-poetry','','[]','同是崇寧癸未生，公爲官長我爲僧。',32,'全唐诗/poet.song.112000.json','["同是崇寧癸未生，公爲官長我爲僧。", "大家履踐通天路，共踏毗盧頂上行。"]'),
('c42957ec-0327-4934-ac0e-9247394b2d42','禪人之梅陽','釋曇華','宋','宋诗','song-poetry','','[]','此行不憚三千里，况是江天欲雪時。',32,'全唐诗/poet.song.112000.json','["此行不憚三千里，况是江天欲雪時。", "問道身心如不昧，梅陽老子已先知。"]'),
('45a206e4-818f-4c54-b0c7-2dfcb77d57cf','與鑄鍾道者','釋曇華','宋','宋诗','song-poetry','','[]','野店小橋外，黄昏欲雪時。',24,'全唐诗/poet.song.112000.json','["野店小橋外，黄昏欲雪時。", "一聲誰側耳，千古喚愚癡。"]'),
('2931a05d-5fdf-45a5-a56a-36eaecf460e1','德彬修雙陽塔求頌','釋曇華','宋','宋诗','song-poetry','','[]','九層塔聳青霄外，七佛靈蹤在上方。',32,'全唐诗/poet.song.112000.json','["九層塔聳青霄外，七佛靈蹤在上方。", "山冷雲寒當午夜，唯聞仙樂散天香。"]'),
('9c594549-a65e-4c1f-a449-2dff08224052','送僧化蓆','釋曇華','宋','宋诗','song-poetry','','[]','窮心何必在三椽，直透歸宗一味禪。',32,'全唐诗/poet.song.112000.json','["窮心何必在三椽，直透歸宗一味禪。", "翻憶當年曾卷起，無端又展與人眠。"]'),
('28d655c5-842c-4e07-a297-9d26dc8e12be','吳必東請小參後說偈','釋曇華','宋','宋诗','song-poetry','','[]','百草頭邊千聖眼，一毫端上萬重關。',32,'全唐诗/poet.song.112000.json','["百草頭邊千聖眼，一毫端上萬重關。", "更無佛法并玄妙，堪與知音共往還。"]'),
('18938c9c-b178-4fea-8d60-21f9bfad2ab4','送六人禪者隨宏長老住大智','釋曇華','宋','宋诗','song-poetry','','[]','大智荒凉久，中興六上人。',48,'全唐诗/poet.song.112000.json','["大智荒凉久，中興六上人。", "機前施遠略，句下要通津。", "事理無兼带，偏圓有主賓。", "風雲今際會，彈指一番新。"]'),
('d01ac1e2-12b4-435b-9856-5a511caf2e1e','贈悟上人造華嚴塔','釋曇華','宋','宋诗','song-poetry','','[]','山前馬廐普光殿，門外牛欄正覺場。',32,'全唐诗/poet.song.112000.json','["山前馬廐普光殿，門外牛欄正覺場。", "五十三人同日葬，善財走得脚生瘡。"]'),
('49a1ae64-0d66-49d7-a038-99b02397f5bc','術人求頌','釋曇華','宋','宋诗','song-poetry','','[]','造化付誰手，君來聊解顔。',48,'全唐诗/poet.song.112000.json','["造化付誰手，君來聊解顔。", "欲游天上路，先破鬼門關。", "禍福行藏內，高低方寸間。", "毫芒差錯處，過犯重如山。"]'),
('73f73edb-7570-4a7f-8064-64c34560b244','行者求頌','釋曇華','宋','宋诗','song-poetry','','[]','了身不若了心休，了得心時身不愁。',32,'全唐诗/poet.song.112000.json','["了身不若了心休，了得心時身不愁。", "若也身心俱了了，神仙何必更封侯。"]'),
('cac3b7c8-6c67-45ee-93ed-4299199d7031','觀道人求頌','釋曇華','宋','宋诗','song-poetry','','[]','學佛從來境界多，不能降伏便成魔。',32,'全唐诗/poet.song.112000.json','["學佛從來境界多，不能降伏便成魔。", "降魔能用無心法，六賊傾城盡倒戈。"]'),
('58309677-babc-401f-bf7b-0e0758f03760','題仲逸宣教三境圖','釋曇華','宋','宋诗','song-poetry','','[]','太清之雲，鏡中之塵。',60,'全唐诗/poet.song.112000.json','["太清之雲，鏡中之塵。", "從無住本，廓應如春。", "妙玄不動，示現無垠。", "三世普入，孰妄孰真。", "現成公案，豈費精神。", "當頭一著，坐斷要津。"]'),
('8deb961b-5ef2-4e9c-902a-673817ff9508','莞山浄明庵小參示衆','釋曇華','宋','宋诗','song-poetry','','[]','三十三州七十僧，馿腮馬頷得人憎。',32,'全唐诗/poet.song.112000.json','["三十三州七十僧，馿腮馬頷得人憎。", "諸方若具羅籠手，今日無因到浄明。"]'),
('232a2421-02d1-42a0-b996-4070c0faa15e','題永寧小軒','釋曇華','宋','宋诗','song-poetry','','[]','我行重到清凉地，小室軒窗分外明。',32,'全唐诗/poet.song.112000.json','["我行重到清凉地，小室軒窗分外明。", "不是山家占春色，大都物理自舒情。"]'),
('bcf415c1-7fdd-4a41-972b-49e69fb2fbbf','贈晦叔秀才二首  其一','釋曇華','宋','宋诗','song-poetry','','[]','處世從教眼似眉，自然心地絕支離。',32,'全唐诗/poet.song.112000.json','["處世從教眼似眉，自然心地絕支離。", "翻身更透龍門浪，頭角崢嶸宇宙低。"]'),
('26c34b0b-ce8d-46ae-8931-2f7cab48f3cd','贈晦叔秀才二首  其二','釋曇華','宋','宋诗','song-poetry','','["\u897f\u6e56"]','少室巖前路不遥，毫芒纔擬便迢迢。',32,'全唐诗/poet.song.112000.json','["少室巖前路不遥，毫芒纔擬便迢迢。", "西湖湖上晚來看，小艇輕風落畫橈。"]'),
('7eecc120-57d1-45b5-b291-b316be5315c0','西蜀祖正道者還鄉求頌','釋曇華','宋','宋诗','song-poetry','','[]','西川五十四軍州，幾箇男兒會點頭。',32,'全唐诗/poet.song.112000.json','["西川五十四軍州，幾箇男兒會點頭。", "透得劍門關子過，不風流處也風流。"]'),
('db8e4482-09f2-49d0-9266-ec735e13269c','夜宿解田偶成','釋曇華','宋','宋诗','song-poetry','','[]','夜宿西山居士家，圍爐相對話生涯。',32,'全唐诗/poet.song.112000.json','["夜宿西山居士家，圍爐相對話生涯。", "從來無一絲頭許，自是勞生眼裏花。"]'),
('756b7dac-44ef-4104-8aba-7ce18a3f4844','送宏監寺開海田','釋曇華','宋','宋诗','song-poetry','','[]','軒昂氣宇要爭先，及早乘時痛著鞭。',32,'全唐诗/poet.song.112000.json','["軒昂氣宇要爭先，及早乘時痛著鞭。", "翻轉江皋千頃浪，靈苗從此秀桑田。"]'),
('b5103789-6a18-4fa0-9073-a0d0fe02cff8','送珣禪還鄉','釋曇華','宋','宋诗','song-poetry','','[]','極目澄澄水照空，白蘋紅蓼戰西風。',32,'全唐诗/poet.song.112000.json','["極目澄澄水照空，白蘋紅蓼戰西風。", "三千里外深深意，鐵券誰將累祖翁。"]'),
('25a6915d-b5e9-44bd-90c3-413634a329c7','送祥禪人二首  其一','釋曇華','宋','宋诗','song-poetry','','[]','子是慈明家畔人，直須超卓要驚羣。',32,'全唐诗/poet.song.112000.json','["子是慈明家畔人，直須超卓要驚羣。", "騰身快入洪波裏，始見曹源正脈分。"]'),
('114a1112-0630-4535-a818-8fc4da5011f0','送祥禪人二首  其二','釋曇華','宋','宋诗','song-poetry','','[]','濁港江頭送別時，碧雲秋水淡依依。',32,'全唐诗/poet.song.112000.json','["濁港江頭送別時，碧雲秋水淡依依。", "莫嫌老拙疏慵甚，它日重來扣竹扉。"]'),
('14c74f24-59d0-4617-b798-764132eb78fc','謝楊善才道友惠數珠','釋曇華','宋','宋诗','song-poetry','','[]','南詢初不失程途，收得金剛腦後珠。',32,'全唐诗/poet.song.112000.json','["南詢初不失程途，收得金剛腦後珠。", "兩手持來親獻我，光明烱烱破昏衢。"]'),
('734fd29e-39c6-48f1-9668-8ce261dcad90','胡氏妙圓求頌','釋曇華','宋','宋诗','song-poetry','','[]','八年伏枕今安樂，安樂常思病苦時。',32,'全唐诗/poet.song.112000.json','["八年伏枕今安樂，安樂常思病苦時。", "苦樂本來真實義，要須猛省力扶持。"]'),
('60b5beec-f4f8-4577-b4f8-47a23d97ea96','送傑侍者還鄉','釋曇華','宋','宋诗','song-poetry','','[]','大徹投機句，當陽廓頂門。',72,'全唐诗/poet.song.112000.json','["大徹投機句，當陽廓頂門。", "相從今四載，徵詰洞無痕。", "雖未付鉢袋，氣宇吞乾坤。", "却把正法眼，喚作破沙盆。", "此行將省覲，切忌便垛根。", "吾有末後著，待歸要汝遵。"]'),
('ee784d12-d7a8-4c88-9da7-1ef405ec090c','爲南書記下火','釋曇華','宋','宋诗','song-poetry','','[]','東湖莞嶺及歸宗，燁燁騰輝爐鞴中。',32,'全唐诗/poet.song.112000.json','["東湖莞嶺及歸宗，燁燁騰輝爐鞴中。", "鐵眼銅睛烹不破，衲僧巴鼻好流通。"]'),
('d9105669-7181-4e58-b1bb-bc3332857ab7','偈','釋曇華','宋','宋诗','song-poetry','','[]','五百力士揭石義，萬仞崖頭撒手行。',32,'全唐诗/poet.song.112000.json','["五百力士揭石義，萬仞崖頭撒手行。", "十方世界一團鐵，虛空背上白毛生。"]'),
('30fb1578-3a19-49b5-99bb-646e324b2ae7','偶作','釋曇華','宋','宋诗','song-poetry','','[]','黄檗堂前行正令，天童今日驗疏親。',32,'全唐诗/poet.song.112000.json','["黄檗堂前行正令，天童今日驗疏親。", "老來拄杖思分付，未見當年喫棒人。"]'),
('082e5204-1a3b-4aa2-9cc9-a7c79ce5ec32','頌古','釋曇華','宋','宋诗','song-poetry','','[]','居士倒地，靈照扶起。',20,'全唐诗/poet.song.112000.json','["居士倒地，靈照扶起。", "乞兒伎倆，討甚巴鼻。"]'),
('25b9453a-cef4-4a2e-9311-3be6419f0ec5','七夕','王之望','宋','宋诗','song-poetry','','[]','西風吹繁暑，夜氣初宜秋。',168,'全唐诗/poet.song.112000.json','["西風吹繁暑，夜氣初宜秋。", "所居稍虛豁，得以消我憂。", "獨眠堂中央，一榻無衾裯。", "開軒敞南北，涼飈入翛翛。", "是日七月七，三星已西流。", "殘雲不成雨，縹緲當空浮。", "雲行忽中斷，月彩爛不收。", "影落庭樹間，枝葉如雕鎪。", "草根有小蟲，微吟作啾啾。", "豈復厭喧聒，更覺窗戶幽。", "我欲終今夕，飛蚊不相謀。", "喧我復齧我，驅去嗟無由。", "但當我自屏，豈與汝輩仇。", "閉門歸下帷，蝶夢尋莊周。"]'),
('c8efcf5b-3c66-4b7e-9f50-e356124136b0','雜詩四首  其一','王之望','宋','宋诗','song-poetry','','[]','有憂烏啼門，有喜鵲噪廬。',96,'全唐诗/poet.song.112000.json','["有憂烏啼門，有喜鵲噪廬。", "主人聞啼噪，喜鵲唾老烏。", "吉凶實由人，烏鵲何與乎。", "但知預相報，其智各有餘。", "人智不如鳥，貪喜忌憂虞。", "遂於烏鵲間，憎愛乃爾殊。", "福至自福至，禍來貴先圖。", "二鳥孰有益，嗟哉主人愚。"]'),
('0079f7e0-80e2-43c5-ae34-168452c050b0','雜詩四首  其二','王之望','宋','宋诗','song-poetry','','[]','春蠶口吐絲，生人皆仰供。',96,'全唐诗/poet.song.112000.json','["春蠶口吐絲，生人皆仰供。", "蜘蛛絲滿腹，祇能打飛蟲。", "衣服與網羅，利害豈可同。", "蠶生旬月老，蜘蛛無春冬。", "蠶食惟草木，蜘蛛肉食豐。", "蠶以繭自縛，蜘蛛掛青空。", "蜘蛛有餘毒，春蠶有餘功。", "受報乃如此，天理不可窮。"]'),
('60bb7bfc-238e-4d5b-ab28-a996b31b4696','雜詩四首  其三','王之望','宋','宋诗','song-poetry','','[]','龜肉不可食，蟹螯不中卜。',72,'全唐诗/poet.song.112000.json','["龜肉不可食，蟹螯不中卜。", "龜以殻自戕，蟹以味見戮。", "所養殊毅豹，所亡等臧穀。", "一足致患害，內外皆鴆毒。", "嵇康坐才死，霍禹以勢族。", "樂哉蟹螯中，貯此老龜肉。"]'),
('0033bc22-6200-4c52-9750-918ef45759ef','雜詩四首  其四','王之望','宋','宋诗','song-poetry','','[]','江發岷山陽，河出崑崙趾。',84,'全唐诗/poet.song.112000.json','["江發岷山陽，河出崑崙趾。", "淵源既洪深，浩浩并衆水。", "東流至渤澥，曲折萬餘里。", "經山無重數，過郡不知幾。", "海邊有小溪，近出海山裏。", "未能數里間，已接潮波起。", "到海雖則同，難與江河比。"]'),
('b1ee3499-af51-45de-aa1e-a3680100cf85','書懷  其一','王之望','宋','宋诗','song-poetry','','[]','羣山岸東海，茲地真斗絕。',72,'全唐诗/poet.song.112000.json','["羣山岸東海，茲地真斗絕。", "洪濤渺翻天，朝夕吐日月。", "雖同一宇宙，迥與朝市別。", "三山在咫尺，芝草吾欲擷。", "未能仙骨輕，稍浣衷腸熱。", "從我其誰歟，乘桴曉當發。"]'),
('b97bd8f0-0116-4f12-8fb2-a13145fb7884','書懷  其二','王之望','宋','宋诗','song-poetry','','[]','百年胡爲哉，萬事聊復爾。',72,'全唐诗/poet.song.112000.json','["百年胡爲哉，萬事聊復爾。", "功名早有意，貧賤昔所恥。", "歲月忽蹉跎，少壯何足恃。", "身外非我有，毫髮不可致。", "惟有一寸心，俯仰要無愧。", "歸去來山中，高人未吾鄙。"]'),
('38389b9f-dbde-420e-a8cd-9a73bf590ae8','書懷  其三','王之望','宋','宋诗','song-poetry','','[]','村居何所樂，春至木欣欣。',72,'全唐诗/poet.song.112000.json','["村居何所樂，春至木欣欣。", "夜睇海上月，晝瞻嶺頭雲。", "東家有勝士，杖屨日相親。", "山行共采蕨，野步仍班荆。", "初見氣已合，久游意彌真。", "劇談復痛飲，相對有餘情。"]'),
('dd37b932-f100-4b76-a2ab-26b47a2a37b4','書懷  其四','王之望','宋','宋诗','song-poetry','','[]','海邊寂寞村，春半芳菲月。',72,'全唐诗/poet.song.112000.json','["海邊寂寞村，春半芳菲月。", "東風所至處，陋境亦佳絕。", "壠麥已翻芒，山花自成列。", "愁腸不堪斷，預畏柳飛雪。", "更憂鶗鴂鳴，坐使衆芳歇。", "白日不可留，請試餐玉訣。"]'),
('699c92f8-9451-47fd-a76e-1c30c35f6cbf','山居','王之望','宋','宋诗','song-poetry','','[]','山居入長夏，草樹繞我屋。',156,'全唐诗/poet.song.112000.json','["山居入長夏，草樹繞我屋。", "微風披拂之，有聲來肅肅。", "葳蕤摇散影，掩冉飄暗馥。", "百合開數花，孤芳更清淑。", "我卧北窗下，午枕睡方足。", "挹此一襟凉，泠然若堪掬。", "坐使萬慮空，樂哉謝羈束。", "有同顔氏子，坐忘遺耳目。", "又如慧可師，安心得歸宿。", "落日行庭前，披衣自捫腹。", "閒扶舊僵石，細數新上竹。", "小禽時下來，相鳴入叢簇。", "見我不驚飛，人禽兩幽獨。"]'),
('f57a5edf-7326-4f9f-adbb-15aab03b725e','登第後投魏侍郎','王之望','宋','宋诗','song-poetry','','[]','空山學仙子，舊識安期生。',96,'全唐诗/poet.song.112000.json','["空山學仙子，舊識安期生。", "青霄許相接，凡骨難爲輕。", "一朝行業滿，九轉丹砂成。", "安期忽東來，從帝遊玉京。", "下視一笑莞，依然有餘情。", "借我白雲車，導以虹蜺旌。", "攝身出塵土，隨君凌紫清。", "機會倘一失，千載何由丁。"]'),
('49021ceb-5434-4925-af7a-ac307f23d0b7','漢南晤魏侯彥誠魏侯贈詩期依韵和已而荆門受代歸鄉襄務冗甚未果答既離襄陽舟中追和','王之望','宋','宋诗','song-poetry','','[]','白頭有如新，傾蓋或如故。',144,'全唐诗/poet.song.112000.json','["白頭有如新，傾蓋或如故。", "乃知意氣間，投分自有處。", "魏公使漢南，風采聳一路。", "凋殘濡膏澤，冤訟廓氛霧。", "游刃若發硎，調琴不膠柱。", "平生不相識，見我國士遇。", "杯盤倒箱篋，笑語雜巵寓。", "豈惟傾肺腑，便可託嬰孺。", "慰我疇昔心，何啻封萬戶。", "離觴峴山曲，握手惜歡聚。", "江風吹行色，短棹不得住。", "臨岐亦何言，加餐納多祜。"]'),
('8ad045b7-3cf0-4083-bcde-d83cd18e396b','道中寄丹丘親舊','王之望','宋','宋诗','song-poetry','','[]','別處日已遠，別情轉綢繆。',120,'全唐诗/poet.song.112000.json','["別處日已遠，別情轉綢繆。", "行行千里餘，脈脈無時休。", "夜與夢相隨，晝與淚俱流。", "山高恨不斷，水闊遮無由。", "欲吞不下咽，欲吐不出喉。", "戟我胸肺間，有如魚掛鈎。", "尋端無從來，了知在心頭。", "翻疑一寸心，能容如許愁。", "平生丈夫氣，愧此鬚髯虬。", "朝來看蓬鬢，滿鑑雪霜浮。"]'),
('d27688e1-b90e-460d-a280-995dfc325773','上李丈尚書  其一','王之望','宋','宋诗','song-poetry','','[]','天孫司經緯，專巧上帝旁。',72,'全唐诗/poet.song.112000.json','["天孫司經緯，專巧上帝旁。", "星縷日月針，幾經補蒼蒼。", "弭節遊人間，帝服無文章。", "寒女一機素，未知作衣裳。", "再拜願祈巧，精神通渺茫。", "但恐雲車回，虛無往路長。"]'),
('aea21aa5-f33e-4daa-8fcd-8832fe52395e','上李丈尚書  其二','王之望','宋','宋诗','song-poetry','','[]','亭亭澗阿松，冰雪何青青。',60,'全唐诗/poet.song.112000.json','["亭亭澗阿松，冰雪何青青。", "千歲已枯死，流膏生茯苓。", "雖無歲寒姿，氣味猶典刑。", "塵土久埋沒，誰能驗仙經。", "置君藥籠中，儻可延年齡。"]'),
('df7b57e5-21b1-4701-93de-22f4d8c9e46c','上李丈尚書  其三','王之望','宋','宋诗','song-poetry','','[]','蓬室有姝女，顔色耀朝暉。',84,'全唐诗/poet.song.112000.json','["蓬室有姝女，顔色耀朝暉。", "幽獨人未識，嬋娟心自知。", "高堂懸寶鑑，美醜良不欺。", "借君一寸光，爲妾照蛾眉。", "念當有所適，辭親結羅衣。", "常恐妾命薄，失身輕薄兒。", "安得嬿婉人，白頭同所歸。"]'),
('e8883381-d31c-43cf-9035-2654a71dea20','魏彥誠見示出守廣德朝士送行詩用韵追賦','王之望','宋','宋诗','song-poetry','','[]','肅肅松柏姿，春月慚蒲柳。',72,'全唐诗/poet.song.112000.json','["肅肅松柏姿，春月慚蒲柳。", "但看霜雪後，何者能不朽。", "君昔辭鴛鸞，出爲小邦守。", "治行達明聽，眷知從此厚。", "至今兩郡碑，德政刊瓊玖。", "九醖熟雖遲，要成宗廟酒。"]'),
('d3941b3c-486e-4b67-afad-35c9638b3fc9','食橄欖有感','王之望','宋','宋诗','song-poetry','','[]','余初食橄欖，眉蹙口欲吐。',120,'全唐诗/poet.song.112000.json','["余初食橄欖，眉蹙口欲吐。", "稍稍滋味之，久乃見媚嫵。", "曲終喜奏雅，先病得後愈。", "功成老大時，亦足酬嘬咀。", "余生足憂患，備已嘗險阻。", "猶如蓼中蟲，自習蓼中苦。", "不知苦盡處，回味有幾許。", "古人倒啖蔗，佳境貴漸取。", "但問有與無，遲暮不猶愈。", "君看道傍李，棄置終泥土。"]'),
('64b2ba2f-dde4-4a23-99ff-dcdb50170d75','書白氏長慶集','王之望','宋','宋诗','song-poetry','','[]','我愛樂天文，平易更精切。',120,'全唐诗/poet.song.112000.json','["我愛樂天文，平易更精切。", "筆端應有口，心事無不說。", "游戲供日用，工巧疑天設。", "述情悉毫釐，辯理窮曲折。", "如我本欲言，挽我開齒頰。", "如人病瘖啞，代我傳喉舌。", "駑駘擬舉步，駿足過如瞥。", "弱弧未及彎，强弩已穿札。", "撫才初自愧，適意還深愜。", "讀盡一編詩，胸懷消百結。"]'),
('d2ed8508-f133-4485-a73d-58361f63659c','移竹','王之望','宋','宋诗','song-poetry','','[]','借宅開小軒，自移一叢竹。',156,'全唐诗/poet.song.112000.json','["借宅開小軒，自移一叢竹。", "悠然北窗下，意色都不俗。", "晴影終日幽，風聲杪秋肅。", "最憐疏雨過，會有白雲宿。", "深培畏不壽，靜對殊未足。", "主人已虛心，坐客亦青目。", "四村多修篁，玉立森如束。", "不爲人所愛，况復困斤斸。", "天姿奚優劣，地遠懸榮辱。", "物情豈固然，世事同一躅。", "何當尋怪石，小壘傍寒綠。", "要收山林趣，密置軒檻曲。", "西峰謾多奇，吾方倦遐矚。"]'),
('17f16e98-5948-4c45-b3fa-b5a77807f881','吳傳朋遊絲書','王之望','宋','宋诗','song-poetry','','[]','鳥迹既茫昧，文字幾變更。',204,'全唐诗/poet.song.112000.json','["鳥迹既茫昧，文字幾變更。", "達者擅所長，各就一世名。", "衆體森大備，造化無留情。", "獨此遊絲法，千古祕未呈。", "右軍露消息，筆墨無成形。", "偉哉延陵老，三紀常研精。", "絕藝本天得，非假學力成。", "應手快揮灑，援毫謝經營。", "奮迅風雨疾，飄浮鬼神驚。", "風狂蛛網轉，春老蠶咽明。", "直如朱弦急，曲若卷髮縈。", "飛梭遞往復，折藕分縱橫。", "獨繭繰不斷，風鳶騰更輕。", "希微破餘地，妙絕無容聲。", "飛白笑冗長，堆墨慚彭亨。", "可憐太纖瘦，不受鎸瑶瓊。", "咨爾百代後，若爲求典刑。"]'),
('02f4ccf6-4746-4bbf-a469-3a166e55d55a','病後戲贈同官蔣子權','王之望','宋','宋诗','song-poetry','','[]','吾衰謬養生，任運常坦坦。',288,'全唐诗/poet.song.112000.json','["吾衰謬養生，任運常坦坦。", "每嬰相如病，漸作叔夜懶。", "昨因觸大暑，留熱在鬲脘。", "醫師戒飲酒，所嗜不可斷。", "寒熱一朝作，水火互濯熯。", "地偏無藥餌，伏枕但憂悺。", "同僚有蔣子，爽俊流輩罕。", "作詩宗徐庾，巧語如繡纂。", "間有少陵風，醇音調玉琯。", "豈惟詩家秀，從政今可算。", "牢盆有出納，曉夕親授筦。", "琴瑟費更張，君能時急緩。", "公餘治方書，今昔多所纘。", "有來謁疾病，手自施湯散。", "買藥輟俸錢，爲民已痌痯。", "我昨病在床，君來問尤款。", "教我煮橘皮，湯熱過冰碗。", "繼送桔梗湯，一杯去煩懣。", "柴胡作引子，汗出如被趲。", "所投立有效，病去若水浣。", "乃知才藝多，所蓄非窽窽。", "又聞善騎射，長箭必引滿。", "設侯六十步，所發無虛簳。", "觀君精悍姿，此語不其亶。"]'),
('8e086a4e-b634-4124-9a7a-cb1bb948e48d','贈范覺民','王之望','宋','宋诗','song-poetry','','["\u534e\u5c71"]','范子廊廟器，至寶非凡璞。',288,'全唐诗/poet.song.112000.json','["范子廊廟器，至寶非凡璞。", "胸懷吞雲夢，豪氣低華嶽。", "昔在童稚時，樹立已卓卓。", "曳裾橋門內，嶄然見頭角。", "歲行在辛丑，帝策詢民瘼。", "造庭百千人，衣带矜褒博。", "平居議執政，至此舌爲括。", "獨餘子范子，雅志不可奪。", "吐辭如湧泉，一發孰能遏。", "揮毫不停綴，盈卷無點抹。", "漢廷執戟郎，環顧皆錯莫。", "縱橫五千字，字字醫國藥。", "期於必伐病，非徒事迂闊。", "怪言一驚衆，士論歎且愕。", "皆云布衣流，志在縻好爵。", "乃爾張危言，身謀胡太錯。", "當時羣宗匠，其間多齷齪。", "指言爲沽直，欲使趨鼎鑊。", "堂堂春官臣，主張獨何確。", "讜議既冰釋，衆口不能鑠。", "乙科忽大闡，秋天一鵰鶚。", "傳誦爭取先，紙價爲翔躍。", "聲華頓輝赫，藹然暨南朔。", "憶昔客東都，猥厠英遊數。"]'),
('c7e03935-1a68-4eeb-b0d3-212d34d8aedd','送黄叔愚赴平江教授','王之望','宋','宋诗','song-poetry','','[]','人生水中萍，泛泛隨波瀾。',180,'全唐诗/poet.song.112000.json','["人生水中萍，泛泛隨波瀾。", "偶然成聚散，誰使爲悲歡。", "伊余從君遊，兩見歲履端。", "相得恨不早，相見常苦難。", "今又舍我去，覺我肝腸酸。", "君誠湖海士，豪氣老不刓。", "劇談憤世俗，怒髮時衝冠。", "向來對宣室，見晚帝興歎。", "落落不苟合，棲遲猶冷官。", "高才徒白首，未許陪鴛鸞。", "蘇臺今輔郡，舉頭見長安。", "會看有追詔，祝君且加餐。", "吾衰釣滄溟，羊裘侶魚黿。", "逍遥各有適，快覩扶摇摶。", "尺書倘見存，慰此離憂寬。"]'),
('d0c28793-40f4-4055-ae26-e0a47bd89020','初至鴻祐成二百字','王之望','宋','宋诗','song-poetry','','[]','我生何悠悠，飄摇若懸旌。',240,'全唐诗/poet.song.112000.json','["我生何悠悠，飄摇若懸旌。", "已破龍華夢，復成鴻祐行。", "鴻祐在何許，海闊山崢嶸。", "地侵魚龍窟，路與猿猱爭。", "曉日見初出，潮波無時平。", "我來秋薄暮，寒雨紛縱橫。", "狂飈振林麓，窗戶皆有聲。", "山鬼夜中號，怪禽籬外鳴。", "我衰不能寐，起行遲天明。", "欻然念身世，百感襟抱盈。", "仲宣昔遭亂，避地之蠻荆。", "登樓賦懷土，悽傷欲無生。", "况我滯甌越，八見秋風驚。", "憧憧一州間，蕭寺六易名。", "已去還復來，如魚被鈎嬰。", "去既無所之，來亦何所營。", "藜藿誠不充，萍蓬甘所丁。", "茲地實樂土，浮生聊耦耕。", "鴒原喜在眼，蠹簡能娛情。", "九夷亦何陋，四海皆弟兄。"]'),
('6267eb93-8eca-43bb-9dfa-a402c97108a0','舟至都昌初見廬阜連日陰雨忽爾晚晴雲氣頓收巖巒盡出截然蒼翠立乎巨浸之中真天下之奇觀也遥望欣然酌酒賦詩','王之望','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','久思廬山遊，忽至左蠡曲。',120,'全唐诗/poet.song.112000.json','["久思廬山遊，忽至左蠡曲。", "倚船初一望，秀色溢我目。", "百里堆翠黛，千峰矗寒玉。", "陰雲知我來，收歛入山腹。", "須臾變光景，盡出一山綠。", "宛如几案間，青銅鑄巖谷。", "又如牆壁上，古畫挂圖軸。", "水光晚蒼茫，風氣秋肅穆。", "明朝南康岸，艤棹陟山麓。", "歡喜不自持，一杯醉醽醁。"]'),
('dc7f5561-196f-44b5-a9c9-b226295301ff','和許總卿  其一','王之望','宋','宋诗','song-poetry','','[]','孔明屢出師，常苦糧食少。',48,'全唐诗/poet.song.112000.json','["孔明屢出師，常苦糧食少。", "公今主邊計，積粟丘阜小。", "卧龍志空大，流馬功竟杳。", "當時若得公，大事指顧了。"]'),
('c2e2831c-e7c4-4847-abdb-5f941b87c83f','和許總卿  其二','王之望','宋','宋诗','song-poetry','','[]','從來方面貴，體尊吟詠少。',48,'全唐诗/poet.song.112000.json','["從來方面貴，體尊吟詠少。", "君侯七尺軀，詩膽看更小。", "句如星斗爛，氣與雲天杳。", "詞源倒三江，傾瀉何時了。"]'),
('b0f662ce-b579-4433-b72f-89509b8bd45d','和許總卿  其三','王之望','宋','宋诗','song-poetry','','["\u5ce8\u7709\u5c71"]','我登峨嵋山，偉觀天下少。',48,'全唐诗/poet.song.112000.json','["我登峨嵋山，偉觀天下少。", "觀公驚俗句，更覺眉山小。", "短章鋒斬絕，大篇氣深杳。", "紙敝墨色渝，讀誦不能了。"]'),
('61b0c3eb-0a06-40ee-a784-c52a605872c5','贈襄陽帥吳彥猷','王之望','宋','宋诗','song-poetry','','[]','令威千歲歸，城郭尚如故。',144,'全唐诗/poet.song.112000.json','["令威千歲歸，城郭尚如故。", "我今還故鄉，陵谷亦易處。", "荆榛荒舊蹊，溪壑改新路。", "城中十萬家，碧瓦生煙霧。", "茅茨變閭閻，舊屋無一柱。", "相逢訪親舊，十百不一遇。", "豈無新人民，往往皆旅寓。", "元帥念疲瘵，撫養若稚孺。", "近聞田裏間，稍稍復逃戶。", "會當一二年，功效見生聚。", "但恐鋒車來，追詔不容住。", "努力慰斯民，望公若羊祜。"]'),
('3f401a30-a6a8-4103-b9da-650894a9dd53','出疆次副使淮陰舟行','王之望','宋','宋诗','song-poetry','','[]','丁年慕請纓，白首翻攘袂。',180,'全唐诗/poet.song.112000.json','["丁年慕請纓，白首翻攘袂。", "輶軒遽憑軾，魏闕頻回睇。", "兩淮經戰爭，萬物皆憔悴。", "雲繁雪霰舞，風猛波濤沸。", "椎凌僅通航，鼓夜無停枻。", "依檣聞喜鵲，酌斚烹鮮鱖。", "出塞那復古，涉川今已利。", "一節誰與持，同舟心靡異。", "奮身徇主憂，圖國忘私計。", "昌黎去懷妾，定遠老思妹。", "高情獨無戚，慧眼不留翳。", "豈惟詩酒豪，抑亦文武備。", "開館昔登瀛，奉車元起沛。", "君遭功名迫，我堪閒散置。", "他年洛下吟，憶君徒擁鼻。"]'),
('7dbfd175-76bb-4954-b616-dfd6f47b22f5','投座主張子猷給事','王之望','宋','宋诗','song-poetry','','[]','東風入雕檻，百卉無不花。',83,'全唐诗/poet.song.112000.json','["東風入雕檻，百卉無不花。", "一經造化手，各若矜春華。", "主人最好事，護養從萌芽。", "澆灌與封植，恩光無等差。", "其間一本尤所喜，欲售千金貴無比。", "君不見洛陽好事丞相家，曾剪姚黄貢天子。"]'),
('7b4cf955-a150-4452-bd6d-cba47b086e1d','送賈可封隨郭帥還西城三十韵','王之望','宋','宋诗','song-poetry','','[]','峴山之陽漢江浦，黄花九月迷村塢。',384,'全唐诗/poet.song.112000.json','["峴山之陽漢江浦，黄花九月迷村塢。", "故人船上初識君，白酒黄鷄對樽俎。", "坐中意氣最相親，便許論交輸肺腑。", "君時方壯我尚少，杯酒相逢各豪舉。", "欲傾滄海入壺觴，不覺風雲先笑語。", "煙塵回首暗鄉縣，避地偷生兩羈旅。", "西城邂逅正春風，南鄭流離共秋暑。", "扁舟東下一沾巾，漢陰渡頭天欲雨。", "君留蜀漢我甌越，關塞悠悠路修阻。", "每悔昔日但酸辛，欲寄好音誰付與。", "日邊失喜雙眼明，一笑恍然相勞苦。", "久經喪亂喜强健，語及艱難更悽楚。", "離合悲歡二十載，往事傷心那可數。", "酒後清狂不復能，鬢邊白髮今如許。", "向來驥子未總角，今與爺長秀而膴。", "文學嶄然已老成，吾徒之衰固其所。", "君材磊磊多大略，胸次縱橫雜文武。", "當年上疏請長纓，欲以忠信爲干櫓。", "馳驅慷慨感知己，十年上佐留邊圉。", "一從捧檄傍紅蓮，幾爲臨戎揮白羽。", "元戎入覲載輜車，策勳進秩光賓主。", "王卿合作水衡丞，庾杲復入將軍府。", "胡爲側翅尚隨人，千里長城頼裨補。", "汾陽僚吏多將相，家聲盛事今猶古。"]'),
('c09cb7c7-08ab-413f-ac3b-7bfc8c62666c','次韵陳庭藻赴天申燕詩二首  其一','王之望','宋','宋诗','song-poetry','','[]','紹興聖主垂衣裳，倬然文治昭天章。',192,'全唐诗/poet.song.112000.json','["紹興聖主垂衣裳，倬然文治昭天章。", "已聞華封祝堯帝，豈但畏壘歌庚桑。", "千秋此日紀佳節，萬歲羣臣稱壽觴。", "簾前宮扇交翡翠，仗下寶馬屯飛黄。", "昭容引儀近日月，御史執法嚴風霜。", "九賓無譁臚句肅，劍佩儼雅趨侯王。", "一聲鳴蹕傳朱輦，千官賜宴趨文昌。", "湛露尊罍均渥澤，薰風絃管迓休祥。", "浩唱充庭雲不動，繁花壓帽春風光。", "可憐歡聲正四合，不覺暮色來蒼蒼。", "軒騶散去九衢閙，朝衣醉瀝餘淋浪。", "小臣病著不能起，但聽廣樂風聲長。"]'),
('d9ff57e5-5805-4e28-bb61-5e41dca81e7e','次韵陳庭藻赴天申燕詩二首  其二','王之望','宋','宋诗','song-poetry','','[]','天申上壽開明堂，羣公祝聖多新章。',193,'全唐诗/poet.song.112000.json','["天申上壽開明堂，羣公祝聖多新章。", "不論文南山成带礪，要看東海生禾桑。", "君恩中臺燕百辟，金罍兕觥雕玉觴。", "飯抄香粳雲子白，酒瀉法釀鵝兒黄。", "宮衣拜賜近端午，輕疊香羅如雪霜。", "功臣彯甲奉朝請，貂冠峩峩來异王。", "中興盛事須記述，樂府宜得張文昌。", "感寓諸孫今列宿，詩鳴省戶爲時祥。", "每逢朝家有慶瑞，輒以篇詠賡休光。", "腐儒白首謬通籍，博士一經慚后蒼。", "敢陪詩人論風雅，祇與漁父歌滄浪。", "昇平頌聲還大手，白傅才力兼諸長。"]'),
('028ec8fe-e7a5-4f98-bacd-63fcaa11df9c','詞源圖','王之望','宋','宋诗','song-poetry','','[]','著作之廳屏十幅，怪石滄江莽相束。',128,'全唐诗/poet.song.112000.json','["著作之廳屏十幅，怪石滄江莽相束。", "恍然坐我三峽旁，洶洶奔流欲頹屋。", "不知狂瀾何處回，壯哉萬頃納一杯。", "自從此畫出名手，海潮不復聲如雷。", "一時文士羅東觀，波濤入筆驅河漢。", "逍遥捫腹日來看，更得丹青助揮翰。", "我本儒中山澤癯，烟蓑祇合老江湖。", "煩將一段好東絹，畫箇漁舟釣雪圖。"]'),
('42bff311-f955-4428-8f32-fa363be53518','王鈐轄出示乃祖兩令公畫像求詩爲賦長句','王之望','宋','宋诗','song-poetry','','[]','藝祖開基登九五，駕馭羣雄走龍虎。',224,'全唐诗/poet.song.112000.json','["藝祖開基登九五，駕馭羣雄走龍虎。", "五十餘年到章聖，將帥名臣猶接武。", "王家再世蒙休光，父子繼踵仍騰驤。", "我從諸孫見畫像，絕世風骨何堂堂。", "隋國令公溫如玉，方口豐頤秀眉目。", "典刑猶在想可知，骨肉都勻肥不俗。", "小令公爲隋國兒，比之乃父加瓌奇。", "凜然滿面英豪氣，猶有酣戰驍雄姿。", "百年神雋今已矣，貌向丹青尚如此。", "虎頭不用著三毫，燕頷須教飛萬里。", "屹然立向廟堂間，可使邊人毛骨寒。", "千載長存麒麟閣，當年肯著鵔鸃冠。", "人物於今寧復有，奇龐誰是功名手。", "麞頭鼠目休求官，歸作山中耦耕叟。"]'),
('7266d627-edbb-43f1-80d3-ac62ad4e745f','登大峨絕頂睹圓相佛光成長句二十韵','王之望','宋','宋诗','song-poetry','','[]','峨眉峻極西南著，萬景莊嚴諸佛住。',320,'全唐诗/poet.song.112000.json','["峨眉峻極西南著，萬景莊嚴諸佛住。", "高標天柱八紘張，雄鎮坤維百靈赴。", "我來雨霽羣峰出，正值春暄三月暮。", "上方解凍僧入巖，遠俗來遊客填路。", "籃輿牽挽六十里，梯棧高低三萬步。", "魚貫攀緣筋力疲，鳥騰陡絕神魂懼。", "行經崖坂幾縈曲，望極堪輿莽回互。", "錦里遥看井底迷，雪山忽認屏間誤。", "幽巖得照石發彩，陰洞有聲雷蓄怒。", "楞伽仙音好鳥語，兜羅綿界神龍護。", "滄海潮回波浪平，藍田日暖煙霏布。", "長虹欻放白毫光，淡墨俄瞻紫金聚。", "應真飛錫衆共覩，圓相攝身人自顧。", "六牙白象恍當空，三足赤烏潛隠霧。", "琉璃瓶瑩秋月白，優曇花浄含曉露。", "瑞境旁連瓦屋起，合成一界如相附。", "神燈夜從九頂朝，散作千山無盡炷。", "肉眼親觀佛會開，凡軀恐逐仙風騖。", "欲尋傅說箕尾間，休訪君平斗牛度。", "便排閶闔陟高圓，擾擾人寰何足寓。"]'),
('7490e55f-b854-4245-bec8-6a41625d7067','次制帥所和前韵','王之望','宋','宋诗','song-poetry','','[]','聖主憂勤躬萬務，英豪寧許山林住。',320,'全唐诗/poet.song.112000.json','["聖主憂勤躬萬務，英豪寧許山林住。", "弓旌號召士無留，竹帛功名公所赴。", "天表對揚咨見晚，坤維鎮撫歌來暮。", "雪山增重絕紛埃，蜀道非難履平路。", "分陝聊煩攄妙略，秉鈞已歎迂高步。", "朱轓撫俗遠民懷，玉帳折衝荒服懼。", "羽檄不飛烽堠滅，駿骨多收邊市互。", "孔明七縱詎非長，戶牖六奇真不誤。", "農狎其野無外憂，馬騰於槽有餘怒。", "三陲絕徼皆妥安，諸將雄師今盡護。", "九重益友思直諒，四蜀新聲詠宣布。", "帥閫方觀勳業成，廟堂行看精神聚。", "嗟我衰遲託末契，辱公敦篤傾殊顧。", "當年獻賦誦凌雲，上國承顔悅披霧。", "禹門親覩躍風雷，堯陛初驚承雨露。", "龍顔下矚頓生光，鳳翼高翔從此附。", "稱身朝服曳青雲，滿袖天香携寶炷。", "九霄變化冥鵬升，一紀光陰隙駒騖。", "綈袍雅意念張祿，襦袴餘波依叔度。", "他時入覲對金蓮，伴直應隨玉堂寓。"]'),
('e053a1e1-d3ca-4652-a940-0b064fcc9fd9','再和','王之望','宋','宋诗','song-poetry','','[]','年將六秩諸衰具，漏盡鐘鳴行不住。',320,'全唐诗/poet.song.112000.json','["年將六秩諸衰具，漏盡鐘鳴行不住。", "一身許國銖兩輕，萬里携家斗升赴。", "五羊大夫習勞苦，三鱣先生嗟晚暮。", "分爲一世數奇人，踏遍九州多半路。", "早歲嘗爲梁甫吟，中途已失邯鄲步。", "窮通有命常自樂，幽顯無慚方不懼。", "每讀商書戒十愆，不憂漢法干三互。", "奔走頻驚使節光，叨逾敢歎儒冠誤。", "車下奪牛任客疑，水中見蟹從人怒。", "怨恩肯效兒女語，正直猶希鬼神護。", "平生事業在方冊，將老精神弊泉布。", "九重德意日邊遠，十萬師徒關外聚。", "不令聖澤皆下霑，寧免吾皇尚西顧。", "上爲朝廷廣霖雨，下令郡邑清蒙霧。", "乘軺無術漫觀風，分陝維賢倚行露。", "青天雲霧昔曾披，綠水芙蓉今密附。", "郊坰小隊連後乘，燕寢清香同妙炷。", "鳥雀難偕鴻鵠飛，駑駘暫逐驊騮騖。", "自憐落落王平子，遇此汪汪黄叔度。", "但憂溫詔趣公歸，蔭宇不容孤迹寓。"]'),
('57d6dc41-9f87-4ec6-84b0-84abed56d581','再和','王之望','宋','宋诗','song-poetry','','[]','珠璣百斛何人付，公有詩筒來不住。',320,'全唐诗/poet.song.112000.json','["珠璣百斛何人付，公有詩筒來不住。", "出塵秀句若霞摛，走筆豪篇逾響赴。", "吟安一字不知老，朝作千篇猶未暮。", "秋天鴻鵠翥浮雲，平地驊騮驅熟路。", "分憂制節綿萬里，餘事文章兼七步。", "千軍獨掃人共驚，八面俱來我何懼。", "力扛九鼎更妥帖，胸蟠萬卷森差互。", "千言未困見縱橫，一點不加無謬誤。", "音諧律呂鳳凰鳴，勢薄雲天鵬鳥怒。", "流傳應有賈客售，在處豈無神物護。", "公詩光焰千丈錦，我詩粗窘一尺布。", "公詩雄富百雉都，我詩窮陋三家聚。", "行經北海恍自失，出見西施羞反顧。", "殘膏祇欲借鄰光，餘潤有如蒙曉霧。", "君侯雅志和薰風，聖主恩光深湛露。", "事業終期白日懸，功名已見青雲附。", "願公歸侍玉皇案，天香復與金童炷。", "願公西取王母環，雲車直指瑶池騖。", "要當都俞廟堂上，豈久淹留井參度。", "顧我塵埃不足論，屈曲世間隨所寓。"]'),
('af1413f5-dc69-408c-ba79-54d3fec8586a','許總卿見和再用韵','王之望','宋','宋诗','song-poetry','','[]','四紀才名淹世務，七年符節坤維住。',320,'全唐诗/poet.song.112000.json','["四紀才名淹世務，七年符節坤維住。", "褒功屢有璽書來，趨詔尚遲軺傳赴。", "男兒功多投老遂，烈士心豈隨年暮。", "松杉頂禿始干雲，駿駔齒長方識路。", "所臨遺迹紀蕭規，相繼小巫窺禹步。", "補公舊處信有幸，顧我非才深自懼。", "轉粟飛芻驅蜀阪，摘山市馬司邊互。", "伐柯執斧固非難，依樣畫葫終少誤。", "解牛毋歎妙肯綮，養虎尤工時喜怒。", "騋牝三千歸圉師，貔貅十萬安都護。", "公家遺利悉桑孔，閫將歡心收戍布。", "關信增屯烽燧遠，邊儲入粟舟車聚。", "未歸左右展論思，端爲西南重憂顧。", "漠北齊盟尋皦日，斗間王氣纏非霧。", "坐鎮全消玉塞塵，召還應及金莖露。", "佳句忽貽韶濩作，正音乃許巴渝附。", "晝哦蔬飯費三吐，夜誦葦燈殘一炷。", "欲隨驥尾强爭馳，暨到蟻封難並騖。", "囊收甚謹加十襲，筆舉復停知幾度。", "試將風格比唐人，堪與拾遺參感寓。"]'),
('ff839cd3-5b9d-46ad-8ffc-292af16e747a','劉侍郎見和再用韵','王之望','宋','宋诗','song-poetry','','[]','大方廣佛三身具，境號華嚴普賢住。',320,'全唐诗/poet.song.112000.json','["大方廣佛三身具，境號華嚴普賢住。", "三千浄土毛孔吞，百億化身塵剎赴。", "底事眉山迹偏顯，端由象法時將暮。", "三乘不起正信心，一線頓開方便路。", "將欲神變驚凡目，故歛光芒歸窘步。", "示現雖同人異見，開遮未判誰無懼。", "臂力遥擎妙喜來，頂光近攝清凉互。", "我來親睹未曾有，方審傳聞元不誤。", "陽春正值風日好，陰雨不逢雷雹怒。", "入夢惟憂神鬼知，乘危暗有龍天護。", "招提問路方上征，世界當空已先布。", "千林寂歷鳥聲少，萬嶺奔騰雲氣聚。", "高峰初到甫休歇，圓相俄驚成指顧。", "一壺恍入物外天，五里知非世間霧。", "感通咫尺捷影響，變滅須臾嗟電露。", "公居福地寶巖對，身享耆年仙籍附。", "兩禁高辭法從班，一燈久續禪宗炷。", "正始餘風獨後凋，建安逸駕爭先騖。", "忽聆酬唱便隨喜，要與見聞俱得度。", "願公且見宰官身，一宅常與軒冕寓。"]'),
('177acd77-3cce-416d-a81b-08e3c6c046a9','和人元夕','王之望','宋','宋诗','song-poetry','','[]','長安百尺朱樓高，傳籌夜醉聞雞號。',128,'全唐诗/poet.song.112000.json','["長安百尺朱樓高，傳籌夜醉聞雞號。", "金吾弛禁玉漏永，九衢遍走狂歡遨。", "訪尋三曲選清唱，交結五陵皆大豪。", "笑將千金買斗酒，輕若九牛亡一毛。", "賦詩更作文字飲，止酒一篇羞和陶。", "筆端百韵鬭奇險，坐上幾人推俊髦。", "萬事轉頭成短夢，十年屈指如奔濤。", "祇今衰老但悲感，長歌終日彈豪曹。"]'),
('f1ae789d-18a7-4699-b99a-fc2fc96fa884','和關子東鐵尺歌','王之望','宋','宋诗','song-poetry','','[]','先生平生無俗嗜，博取珍奇自娛戲。',160,'全唐诗/poet.song.112000.json','["先生平生無俗嗜，博取珍奇自娛戲。", "案間雙尺本蛟龍，怪底雄雌俱出地。", "含精古鐵色沈沈，質白玉兮價黄金。", "有時風雨暗堂室，直恐雷電相搜尋。", "浄業知君專筆硯，白首殘編天眼見。", "一朝出此瑞文房，神物化成非鍛鍊。", "閲遍千人誰得將，主人比德端且方。", "永供黄卷鎮邊幅，明窗浄几生輝光。", "先生歌成驚傑句，助發鏗鏘得君故。", "何人似與郭代公，寶劍豪篇不須賦。"]'),
('6785cc2b-ee96-415c-910c-9b74df698a12','乙巳四月自都下省歐陽氏姊於封丘時河朔流移滿道即事有作寄范覺民','王之望','宋','宋诗','song-poetry','','[]','北出都門道，紅塵污客襟。',48,'全唐诗/poet.song.112000.json','["北出都門道，紅塵污客襟。", "號蟬如有意，高柳自成陰。", "轍亂思良馬，林幽慕逸禽。", "據鞍回首處，愈覺帝閽深。"]'),
('07d9da88-ff6b-402b-b85d-a814f4cd2014','龍華山寺寓居十首  其一','王之望','宋','宋诗','song-poetry','','[]','抱病雲山遠，興懷節物新。',48,'全唐诗/poet.song.112000.json','["抱病雲山遠，興懷節物新。", "林紅紛過雨，嶺翠鬰堆春。", "猿鳥時相狎，烟霞日自親。", "可憐成底事，半世走風塵。"]'),
('3fd13dea-4ec0-4221-9fff-265874f5f0dd','龍華山寺寓居十首  其二','王之望','宋','宋诗','song-poetry','','[]','齋飯來香積，鐘聲出翠筠。',48,'全唐诗/poet.song.112000.json','["齋飯來香積，鐘聲出翠筠。", "僧投松徑遠，鳥下石壇馴。", "茶摘春山嫩，泉烹雨澗新。", "蕭然烟篆室，處處喜留人。"]'),
('4d6db3f6-7d78-4660-b985-5dd39335d8b7','龍華山寺寓居十首  其三','王之望','宋','宋诗','song-poetry','','[]','嗜好非前日，顛狂減少年。',48,'全唐诗/poet.song.112000.json','["嗜好非前日，顛狂減少年。", "久疏長夜飲，新學小乘禪。", "覓句驅春恨，翻書引晝眠。", "朝來山鳥閙，驚破睡中天。"]'),
('cacf05a1-6a76-4a09-affb-b254424207ac','龍華山寺寓居十首  其四','王之望','宋','宋诗','song-poetry','','[]','作客他鄉久，宜人此界稀。',48,'全唐诗/poet.song.112000.json','["作客他鄉久，宜人此界稀。", "身閒長挾策，地僻慣披衣。", "妻有虀鹽樂，兒因筍蕨肥。", "出門何所適，終日掩荆扉。"]'),
('e5255b4e-5fa6-4691-9ec0-761383f7f6d3','龍華山寺寓居十首  其五','王之望','宋','宋诗','song-poetry','','[]','海國幽棲地，春風欲暮時。',48,'全唐诗/poet.song.112000.json','["海國幽棲地，春風欲暮時。", "病憂梅雨逼，貧歎麥秋遲。", "併日終無愧，逢年會有期。", "饑寒寧苟免，吾道諱磷緇。"]'),
('ab7d1491-133e-48d1-ac40-7d1911d5cc7f','龍華山寺寓居十首  其六','王之望','宋','宋诗','song-poetry','','[]','時節清明過，溪山晴霽初。',48,'全唐诗/poet.song.112000.json','["時節清明過，溪山晴霽初。", "出遊偕婦子，相識半樵漁。", "稼穡歸寧遂，經綸計已疏。", "淵明至窮約，三徑亦吾廬。"]'),
('8b311e8b-c977-4c39-a3bd-8c7acd7fd981','龍華山寺寓居十首  其七','王之望','宋','宋诗','song-poetry','','[]','羊乳莖猶嫩，豬牙葉未殘。',48,'全唐诗/poet.song.112000.json','["羊乳莖猶嫩，豬牙葉未殘。", "呼童聊小摘，爲爾得加餐。", "仗馬卑三品，山雌慕一簞。", "朝來食指動，苦菜入春盤。"]'),
('b9a472e7-b5a7-4755-9cd0-ae6587eb34e0','龍華山寺寓居十首  其八','王之望','宋','宋诗','song-poetry','','[]','有客過松徑，呼兒下竹關。',48,'全唐诗/poet.song.112000.json','["有客過松徑，呼兒下竹關。", "張燈深夜語，沽酒遠村還。", "醇異交公瑾，清非醉景山。", "劇談自有理，不在濁醪間。"]'),
('a7bee16e-bd74-4ba0-ae4d-82e53edd10bd','龍華山寺寓居十首  其九','王之望','宋','宋诗','song-poetry','','[]','杜宇來何處，天涯又復鳴。',48,'全唐诗/poet.song.112000.json','["杜宇來何處，天涯又復鳴。", "空山聽更激，寒夜窈難明。", "故國三千里，春風第一聲。", "年年羈旅地，愁絕不勝情。"]'),
('84f3114d-c3bf-457b-8f00-b1a900f0dd38','龍華山寺寓居十首  其一○','王之望','宋','宋诗','song-poetry','','[]','水鄉經月雨，潮海暮春天。',48,'全唐诗/poet.song.112000.json','["水鄉經月雨，潮海暮春天。", "芒種嗟無日，來牟失有年。", "人多逢菜色，村或斷炊烟。", "誰謂山中樂，憂來百慮煎。"]'),
('d48dc09b-e4ab-43b7-a9ee-ab1da022635b','送別祝得之','王之望','宋','宋诗','song-poetry','','[]','倦遊淹海上，得子意彌敦。',48,'全唐诗/poet.song.112000.json','["倦遊淹海上，得子意彌敦。", "文彩與春秀，性情如玉溫。", "相從不知久，欲別更何言。", "努力功名會，飛騰入帝閽。"]'),
('b3f35ae2-df87-426f-947c-e3921b2b27da','別友人','王之望','宋','宋诗','song-poetry','','[]','此日天涯別，春風斷客魂。',48,'全唐诗/poet.song.112000.json','["此日天涯別，春風斷客魂。", "綠楊初暗路，芳草欲迷村。", "祖帳前山遠，驪歌落日昏。", "相思今夜月，不復對清樽。"]'),
('3b51ec74-be5b-4db9-a2ca-49b2dc34d8d6','豁然亭','王之望','宋','宋诗','song-poetry','','[]','何處開軒檻，凌虛香靄間。',48,'全唐诗/poet.song.112000.json','["何處開軒檻，凌虛香靄間。", "胸中吞百粵，眼界抵三山。", "曉日賓滄海，秋潮俯碧灣。", "登臨一舒嘯，宇宙頓寬閒。"]'),
('24f5c67b-e181-4658-aefc-148973b9e483','同諸鄉人泛臨安西湖','王之望','宋','宋诗','song-poetry','','["\u897f\u6e56"]','短棹夷猶處，湖平酒滿觴。',48,'全唐诗/poet.song.112000.json','["短棹夷猶處，湖平酒滿觴。", "荷深迷去路，波淺澀歸航。", "落日山頭暗，西風水面凉。", "今朝一尊共，相對恍江鄉。"]'),
('c6b1461a-8435-4dbd-ab51-1ba386e23e61','坐中贈朱尉慶長','王之望','宋','宋诗','song-poetry','','[]','君尉襄陽日，吾方首善游。',48,'全唐诗/poet.song.112000.json','["君尉襄陽日，吾方首善游。", "素交微半面，青顧乃雙眸。", "有喜一樽共，相期三徑幽。", "溪山許分老，爲我繕菟裘。"]'),
('75499156-b631-40b0-a686-3a68e29b02fe','懷李相之','王之望','宋','宋诗','song-poetry','','[]','李子通家舊，人門孰與侔。',48,'全唐诗/poet.song.112000.json','["李子通家舊，人門孰與侔。", "胸中足今古，皮裏貯陽秋。", "尊酒懷清致，關山隔俊游。", "江城携手地，春色黯離憂。"]'),
('56f39704-86a8-4ce0-9836-d47e6e91eb55','相之見和有真能乘興之句再次韵','王之望','宋','宋诗','song-poetry','','[]','一月如三歲，懷君未足侔。',48,'全唐诗/poet.song.112000.json','["一月如三歲，懷君未足侔。", "情親頻入夢，句好欲生秋。", "真有山陰興，聊尋河表遊。", "翻愁江上別，心事不堪憂。"]'),
('071f2bc2-cf2c-4345-a21b-c77653a2f166','齊堯佐寄詩許予授代歸穀城日相過次韵','王之望','宋','宋诗','song-poetry','','[]','故人千里去，猶記別時歌。',48,'全唐诗/poet.song.112000.json','["故人千里去，猶記別時歌。", "衰鬢禁愁得，狂懷可奈何。", "南枝春意動，西望夕陽多。", "三徑荒凉外，高軒詎肯過。"]'),
('a3acc45b-ec48-4bef-969f-988c554af286','和李士舉陪提刑徽猷遊中梁山臨秀遠軒以望江中平陸之勝承示佳句且敘故舊離合之感次韵二首  其一','王之望','宋','宋诗','song-poetry','','[]','空翠浮軒檻，嵐光拂棟梁。',48,'全唐诗/poet.song.112000.json','["空翠浮軒檻，嵐光拂棟梁。", "江隨平野曲，林擁暮山蒼。", "城郭猶平日，田疇本樂鄉。", "呻吟未休息，衰病意空長。"]'),
('27af72f7-e01e-4b08-87f0-e0fde8f62922','和李士舉陪提刑徽猷遊中梁山臨秀遠軒以望江中平陸之勝承示佳句且敘故舊離合之感次韵二首  其二','王之望','宋','宋诗','song-poetry','','[]','京口追遊地，錢塘執別年。',48,'全唐诗/poet.song.112000.json','["京口追遊地，錢塘執別年。", "飄流恍如夢，聚散豈其天。", "夙駕行趨詔，當朝正急賢。", "紫荷持從橐，去去入林泉。"]'),
('f5a35f58-244d-48ea-8eb6-5b955f932526','次韵賀子忱春事','王之望','宋','宋诗','song-poetry','','[]','老境流年速，春風幾日晴。',48,'全唐诗/poet.song.112000.json','["老境流年速，春風幾日晴。", "清尊花下怯，白髮鏡中明。", "蝴蝶迷幽夢，倉庚愧好聲。", "良辰一尊酒，鐘鼎可忘情。"]'),
('602b6341-7842-4cd5-8990-8c471939739b','挽林給事中母柳夫人詞三首  其一','王之望','宋','宋诗','song-poetry','','[]','聯德成偕老，和鳴六十春。',48,'全唐诗/poet.song.112000.json','["聯德成偕老，和鳴六十春。", "休聲傳孝婦，餘慶産名臣。", "人去虛韋幔，哀深泣孟鄰。", "千年憑直筆，圖史播芳塵。"]'),
('e6541686-2ba3-435f-918f-a0fffd06992c','挽林給事中母柳夫人詞三首  其二','王之望','宋','宋诗','song-poetry','','[]','作配歸華族，生賢瑞國朝。',48,'全唐诗/poet.song.112000.json','["作配歸華族，生賢瑞國朝。", "升堂拜王導，窺牖識房喬。", "綵服金龜重，安輿駟馬驕。", "慶門今鼎盛，環珮忽蕭蕭。"]'),
('e9c63180-1b3c-45e8-a77d-c9cfbe3b087e','挽林給事中母柳夫人詞三首  其三','王之望','宋','宋诗','song-poetry','','[]','方喜門施戟，俄驚容奠芻。',48,'全唐诗/poet.song.112000.json','["方喜門施戟，俄驚容奠芻。", "孤鸞空對影，老鳳獨將雛。", "祖送傾朝士，哀榮震帝都。", "祇應歸葬處，千兩擁山隅。"]'),
('f2dbf8c4-e082-4c31-9aa6-a7c1cae2ac74','張和公母秦國太夫人輓詞','王之望','宋','宋诗','song-poetry','','[]','誓比共姜早，貧如翟母希。',48,'全唐诗/poet.song.112000.json','["誓比共姜早，貧如翟母希。", "三遷功可大，五福報無違。", "衮繡供兒綵，風旛契祖機。", "千秋憑直筆，圖史播芳徽。"]'),
('fd463ad1-9365-4b7e-b762-ce0643d7af54','贈元觀正字','王之望','宋','宋诗','song-poetry','','[]','才名四紀藹簪紳，王謝風流信絕倫。',64,'全唐诗/poet.song.112000.json','["才名四紀藹簪紳，王謝風流信絕倫。", "雲路舊遊羣玉府，山城初見謫仙人。", "八龍漂泊知餘幾，三爵追隨莫厭頻。", "此會未應輕作別，梅花且醉臘前春。"]'),
('b49a12ba-3134-44bb-855c-3d749c72bfbd','和曾丈贈光化令趙元質','王之望','宋','宋诗','song-poetry','','[]','奔波朝士覓官忙，獨買扁舟去意長。',64,'全唐诗/poet.song.112000.json','["奔波朝士覓官忙，獨買扁舟去意長。", "汲黯舊聞羞作令，馮唐今愧老爲郎。", "鵷鴻引去知何慕，鷗鷺歸來不亂行。", "竊食端輸厠中鼠，驚餘猶得飽饑腸。"]'),
('511d17f6-f33d-4d08-962d-92ea338bc2ec','關子東約中秋遊天竺再用前韵有詩和之','王之望','宋','宋诗','song-poetry','','[]','湖光盡處兩山開，夾道蒼松鬰壯哉。',64,'全唐诗/poet.song.112000.json','["湖光盡處兩山開，夾道蒼松鬰壯哉。", "水過冷泉雙澗合，石飛天竺一峰來。", "勝遊喜有幽人約，佳句俄催爽氣回。", "桂子中秋正芬馥，流霞好泛月邊杯。"]'),
('39914167-7429-456e-acdd-75af87012d8d','文監丞出關子東西湖春遊倡和且約爲重九之遊次韵','王之望','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖爛醉踏青天，秀句重尋未隔年。',64,'全唐诗/poet.song.112000.json','["西湖爛醉踏青天，秀句重尋未隔年。", "已約清樽携九日，要將黄菊薦三賢。", "深秋風日明寒水，宿雨波瀾起畫船。", "佳氣葱蘢如有待，曉粧濃淡抹非烟。"]'),
('424a0ace-277e-43c0-9a6a-f6bd516658be','題龍華寺','王之望','宋','宋诗','song-poetry','','[]','孤枕僧庵夢不成，披衣推戶竹軒明。',64,'全唐诗/poet.song.112000.json','["孤枕僧庵夢不成，披衣推戶竹軒明。", "一天月色連秋色，萬樹風聲似水聲。", "小檻沉沉青嶂合，脩簷冉冉白雲行。", "今宵佇立情何限，曉鑑霜毛兩鬢生。"]'),
('67919860-241c-4533-a59f-847574ebe9a2','同年十人會於湖上巫子先拘臺制不來有詩次韵','王之望','宋','宋诗','song-poetry','','[]','曲江一散各西東，杯酒重來氣尚雄。',64,'全唐诗/poet.song.112000.json','["曲江一散各西東，杯酒重來氣尚雄。", "才薄愧參龍虎榜，會難常歎馬牛風。", "弟兄半已顛毛白，賓主休辭醉頰紅。", "底事坐中猶未樂，車公不遂一尊同。"]'),
('4fbbc4f5-ae5f-4389-b936-a1ba95b2b5bf','與同舍遊浄明是日大寒予獨乘馬諸公以孟浩然相戲以其鄉人故也關丈有詩次韵','王之望','宋','宋诗','song-poetry','','[]','慘淡陰風暗廣川，衝寒直到白雲邊。',64,'全唐诗/poet.song.112000.json','["慘淡陰風暗廣川，衝寒直到白雲邊。", "寒馿苦憶長安道，古寺深行小有天。", "峴首詩人窮入畫，孤山處士句堪傳。", "疑君便是林君復，妙字清題故宛然。"]'),
('22c7b97d-6c66-4f63-8a60-b710c2651406','丈人觀設醮留題','王之望','宋','宋诗','song-poetry','','[]','翠麓丹崖敞洞天，瓊宮珠殿照雲烟。',64,'全唐诗/poet.song.112000.json','["翠麓丹崖敞洞天，瓊宮珠殿照雲烟。", "森羅壁繪推前輩，縹緲樓居見列仙。", "朝斗壇邊星象冷，步虛聲內月華圓。", "塵埃迥隔人間世，骨悚魂清夜不眠。"]'),
('86089309-71a7-49e7-b2ff-09d10a2152ef','再用前二詩韵  其一','王之望','宋','宋诗','song-poetry','','[]','洞府仙扃本不關，凡蹤長墮世塵間。',64,'全唐诗/poet.song.112000.json','["洞府仙扃本不關，凡蹤長墮世塵間。", "勝遊得得今須遍，俗駕遲遲肯遽還。", "絕巘晨光收雨脚，羣峰春色嚲烟鬟。", "感通珍重神靈意，詩思雖荒詎敢慳。"]'),
('696a05fb-81f1-412a-9a93-05a7bbc453b8','再用前二詩韵  其二','王之望','宋','宋诗','song-poetry','','[]','勝境名標第五天，殊庭佳氣藹非烟。',64,'全唐诗/poet.song.112000.json','["勝境名標第五天，殊庭佳氣藹非烟。", "鼓鐘與看千人會，玉石難分十種仙。", "幽壑舊傳靈藥富，蒼崖曾現寶光圓。", "塵勞未决丹梯急，只得虛堂一夜眠。"]'),
('319fc99a-54c7-4bc0-9905-b686c24280af','棲賢三峽橋次南康守晏德基韵','王之望','宋','宋诗','song-poetry','','[]','古寺深藏紫翠間，清風夾道凜蒼官。',64,'全唐诗/poet.song.112000.json','["古寺深藏紫翠間，清風夾道凜蒼官。", "千尋秋色巖巒凈，十里雷聲澗谷寒。", "此去洗心應少累，從來蓄眼未經看。", "使君健筆題佳句，一首新詩倒醉瀾。"]'),
('59e2fd12-f51f-404f-9bd8-91771d7488fb','題胥解元成美堂','王之望','宋','宋诗','song-poetry','','[]','當年英妙曳青衿，曾習王褒盛德吟。',64,'全唐诗/poet.song.112000.json','["當年英妙曳青衿，曾習王褒盛德吟。", "驥騄作駒期萬里，鸞凰振翼便千尋。", "馳聲場屋誰勍敵，好事侯邦盡賞音。", "古語美成須在久，願君長保歲寒心。"]'),
('7c1e7def-6aef-4594-bc7f-3192ac462c86','贈元運使','王之望','宋','宋诗','song-poetry','','[]','使節東來炯繡衣，蒙泉景色動旌旗。',64,'全唐诗/poet.song.112000.json','["使節東來炯繡衣，蒙泉景色動旌旗。", "官曹傳檄清風肅，老稚隨車淑氣移。", "趙日可能兼畏愛，蘇天那復間公私。", "鴒原更遇蓬瀛客，好駐幨帷十日期。"]'),
('dc68ba0a-d29c-4489-8540-88d6eceeb733','缺題','王之望','宋','宋诗','song-poetry','','[]','霜晴愛日曉生東，蕭寺山茶賞歲豐。',64,'全唐诗/poet.song.112000.json','["霜晴愛日曉生東，蕭寺山茶賞歲豐。", "錦里出遨驅小隊，雪山納堠狎諸戎。", "葉連油幕侵天碧，花倚朱旗特地紅。", "美景良辰萬人喜，不妨行樂一尊同。"]'),
('30e05109-0949-4a69-90ae-be48ff5495df','還鮮于蹈夫詩編','王之望','宋','宋诗','song-poetry','','[]','百首新詩句句妍，追還江左一千年。',64,'全唐诗/poet.song.112000.json','["百首新詩句句妍，追還江左一千年。", "春歸池草難專美，冷入江楓稱所傳。", "一字人知吟不到，八分我喜錄成編。", "西來所得真多矣，滿篋今藏錦繡篇。"]'),
('7104da00-3779-4c32-a5b3-3b0f3cbcac21','溫原廟神御北還和謝景思韵','王之望','宋','宋诗','song-poetry','','[]','靈輿歸路肅班班，帳殿秋風響珮環。',64,'全唐诗/poet.song.112000.json','["靈輿歸路肅班班，帳殿秋風響珮環。", "九廟向來連北闕，五陵依舊對南山。", "玉衣不受清塵涴，風馬應隨綵仗還。", "行起奉常陪薦享，天威咫尺侍懸間。"]'),
('8dbac8c7-6e2a-4d11-a56d-d1dbd99dc8c9','賀劉侍郎三首  其一','王之望','宋','宋诗','song-poetry','','[]','早歲儒林俊譽流，中年持橐侍宸遊。',64,'全唐诗/poet.song.112000.json','["早歲儒林俊譽流，中年持橐侍宸遊。", "論思清禁三朝遇，閒散殊庭二紀投。", "迹與香山齊出處，詩將彭澤盡賡酬。", "似聞璧水求三老，行起蒲輪慰九州。"]'),
('8b26c613-ff04-40c4-bfe9-df60f4c1e870','賀劉侍郎三首  其二','王之望','宋','宋诗','song-poetry','','[]','漢嘉平日想風流，喜作凌雲載酒遊。',64,'全唐诗/poet.song.112000.json','["漢嘉平日想風流，喜作凌雲載酒遊。", "塵土何時公事了，林泉聊與故人投。", "心期濟物衰難强，志在求田老未酬。", "官滿便當投劾去，一航從此下揚州。"]'),
('6a58b3dd-4797-45ae-b797-49676ffbcbb0','賀劉侍郎三首  其三','王之望','宋','宋诗','song-poetry','','[]','萬景樓頭盡日留，烏尤嶺上及春遊。',64,'全唐诗/poet.song.112000.json','["萬景樓頭盡日留，烏尤嶺上及春遊。", "谿潭杳渺游魚樂，林木陰森倦鳥投。", "千尺梵身名不謬，半輪山月句難酬。", "爭流競秀君休問，更有江聲撼一州。"]'),
('784652c7-e5c4-4704-b35e-8028aedfef1f','題上清宮','王之望','宋','宋诗','song-poetry','','[]','一徑緣雲徹上臺，玉樓銀闕冠崔嵬。',64,'全唐诗/poet.song.112000.json','["一徑緣雲徹上臺，玉樓銀闕冠崔嵬。", "連峰衮衮從天下，迥野茫茫匝地開。", "曉日重溟紅浪湧，夜燈千嶺瑞光來。", "却歸下土人應怪，身自瑶池閬苑回。"]'),
('0cb6c785-ef4d-4216-960f-3d9398e71c85','留題修覺山絕勝亭','王之望','宋','宋诗','song-poetry','','[]','古寺幽巖萬木稠，蜀川一覽盡西州。',64,'全唐诗/poet.song.112000.json','["古寺幽巖萬木稠，蜀川一覽盡西州。", "依微遠樹低平野，散漫清江吐亂洲。", "老眼乍明疑峴首，歸心忽動憶槎頭。", "當年風物悲游子，子美應同故國愁。"]'),
('70f8a0e9-1fb5-4ec6-9f08-48884d88b82f','題廣利院','王之望','宋','宋诗','song-poetry','','[]','翠嶺蒼巖带落霞，水雲平野一川斜。',64,'全唐诗/poet.song.112000.json','["翠嶺蒼巖带落霞，水雲平野一川斜。", "二山相距無千里，數口俱仙有兩家。", "仇穴便當營草屋，武陵何必訪桃花。", "擇鄉試復詢風俗，善政人人令尹誇。"]'),
('61c3d676-c7e4-499a-aeaf-4ddb09e88ad0','寄題謝景思藥寮仍用其韵','王之望','宋','宋诗','song-poetry','','[]','城府年來怪迹疏，端因藥圃滯巾車。',64,'全唐诗/poet.song.112000.json','["城府年來怪迹疏，端因藥圃滯巾車。", "芒鞋入谷親尋種，野服巡欄自把鋤。", "室藹芝蘭無俗物，房深花木稱僧居。", "他時猿鶴休驚怨，安石寧終老一墟。"]'),
('1ef67f22-e998-4a6c-98d7-67d8f497f9b1','同鮮于蹈夫管養正飲衛氏雲亭','王之望','宋','宋诗','song-poetry','','[]','誰結危亭古岸頭，雲容水態入簾鈎。',64,'全唐诗/poet.song.112000.json','["誰結危亭古岸頭，雲容水態入簾鈎。", "數峰嵐翠欲排闥，半夜溪聲礙枕流。", "入坐烟霞終日秀，對床風雨一燈幽。", "那知戎馬紛紜際，杖屨相陪得勝遊。"]'),
('077a7d8a-fda2-499c-98a0-9c39ab1c1cc5','同龐彥才晚酌於涵翠軒','王之望','宋','宋诗','song-poetry','','[]','登臨到處久徘徊，水色山光滾滾來。',64,'全唐诗/poet.song.112000.json','["登臨到處久徘徊，水色山光滾滾來。", "百頃烟村抱城郭，數峰雲水擁樓臺。", "千篇取足詩材剩，萬軸橫陳畫笥開。", "清興窮探猶未厭，更投涵翠舉餘杯。"]'),
('88adfd8a-dc6c-4157-8a9e-5c9a796dd632','上曾二丈仲成  其一','王之望','宋','宋诗','song-poetry','','[]','湖海元龍氣尚豪，笑談誰料已霜毛。',64,'全唐诗/poet.song.112000.json','["湖海元龍氣尚豪，笑談誰料已霜毛。", "文章家法西京在，兄弟才名北斗高。", "欲取功名酬老大，豈將州縣歎徒勞。", "登壇不獨風騷將，出幕他年看節旄。"]'),
('171a3c3e-b5c2-41af-a300-b0d8c261cc79','上曾二丈仲成  其二','王之望','宋','宋诗','song-poetry','','[]','憶拜冰壺日下時，先君未老我方兒。',64,'全唐诗/poet.song.112000.json','["憶拜冰壺日下時，先君未老我方兒。", "庭闈一閟成今昔，世路重來太險巘。", "風義肯忘三益友，姓名願入八哀詩。", "遺孤么麽何能報，泉下幽魂儻有知。"]'),
('14f4521f-6e4c-432c-adc3-98124592a6fd','上曾二丈仲成  其三','王之望','宋','宋诗','song-poetry','','[]','患難餘生二十年，一身孤苦百憂纏。',64,'全唐诗/poet.song.112000.json','["患難餘生二十年，一身孤苦百憂纏。", "文章昔謂古可到，蹤跡今爲人所憐。", "憔悴形容勳業鏡，歸依空寂祖師禪。", "不孤雖有山公在，恐逐龍舒下九泉。"]'),
('5a5524fc-69aa-47a7-bd3b-f797a2516554','和關子東笻杖','王之望','宋','宋诗','song-poetry','','[]','老境生涯正倚君，周旋夷險共悲欣。',64,'全唐诗/poet.song.112000.json','["老境生涯正倚君，周旋夷險共悲欣。", "最憐磊磊多高節，未肯斑斑出異文。", "漢閣燈來徒照夜，葛陂龍去謾拏雲。", "願爲靈壽扶黄髮，廊廟他年看勒勳。"]'),
('70e612ab-0dba-4140-a13a-6fcf35b2bb11','落梅  其一','王之望','宋','宋诗','song-poetry','','[]','春意枝間忽暗驚，乘風作陣去縱橫。',64,'全唐诗/poet.song.112000.json','["春意枝間忽暗驚，乘風作陣去縱橫。", "蒼苔可忍欺香骨，粉蝶無端亂舞英。", "有恨應羞霜月照，鍾情猶頼晚風輕。", "夢回一夜頻搔首，腸斷空階驟雨聲。"]'),
('1c8defb0-50b3-47d5-9974-2816e4c9740f','落梅  其二','王之望','宋','宋诗','song-poetry','','[]','香殘粉暗若爲情，寂寞空餘瘦影橫。',64,'全唐诗/poet.song.112000.json','["香殘粉暗若爲情，寂寞空餘瘦影橫。", "雨後園林無玉樹，朝來庭院滿瓊英。", "浮雲冉冉當風盡，飛雪飄飄落砌輕。", "廣武爲君聊一歎，羣花從此擅名聲。"]'),
('d7877cfc-51f4-466d-acd6-cc412ccf6b86','挽季通判','王之望','宋','宋诗','song-poetry','','[]','六藝潛心老益尊，此邦耆舊衆推賢。',64,'全唐诗/poet.song.112000.json','["六藝潛心老益尊，此邦耆舊衆推賢。", "高文早出諸儒右，清節宜書獨行篇。", "白首可憐纔半刺，朱衣猶得貴重泉。", "佳城一閟成千古，寂寞哀笳慘暮烟。"]'),
('cc7e701b-2f33-4a92-b52c-a0c312e16f6b','挽王教授子節父','王之望','宋','宋诗','song-poetry','','[]','綵衣方喜奉安輿，丹旐俄驚返故居。',64,'全唐诗/poet.song.112000.json','["綵衣方喜奉安輿，丹旐俄驚返故居。", "已作善人稱里閈，固宜陰德大門閭。", "悟超庭柏心無礙，香茁階蘭慶有餘。", "哀挽一聲寒日外，蕭蕭風樹鎖郊墟。"]'),
('4901050c-b089-4702-a2d8-e89403c19eac','題蒙泉','王之望','宋','宋诗','song-poetry','','[]','西北峩峩疊嶂來，濤奔浪湧勢難回。',64,'全唐诗/poet.song.112000.json','["西北峩峩疊嶂來，濤奔浪湧勢難回。", "忽臨城郭千峰住，下有源泉萬斛開。", "魚鼈寧容腥沼沚，蛟龍曾是起風雷。", "平時寂寞何靈響，歲旱方知濟物才。"]'),
('829835de-49f7-4e9d-a95b-1bc311630bcc','和友人  其一','王之望','宋','宋诗','song-poetry','','[]','弟兄南渡各馳驅，幾奉君王尺一除。',64,'全唐诗/poet.song.112000.json','["弟兄南渡各馳驅，幾奉君王尺一除。", "黄耳音書寄懷抱，烏衣門巷惜丘墟。", "澄清孟博榮持節，雅量玄平靜著書。", "五桂家風殊未艾，黄山佳氣藹如初。"]'),
('d9cc237b-65ef-42e4-a8fb-96f90142b1bd','和友人  其二','王之望','宋','宋诗','song-poetry','','[]','坐閲江城歲月遷，心勞政拙豈能賢。',64,'全唐诗/poet.song.112000.json','["坐閲江城歲月遷，心勞政拙豈能賢。", "昔遊泉石迷尋訪，故里風烟喜接連。", "聊假頒宣行素學，敢將遲暮歎華顛。", "他年良史徵佳什，會入西京循吏篇。"]'),
('161ef09a-6881-4b47-8800-dbdf85e3400b','和眉守王郎中','王之望','宋','宋诗','song-poetry','','[]','驚風鴻鵠各翻飛，同落西南蜀一維。',64,'全唐诗/poet.song.112000.json','["驚風鴻鵠各翻飛，同落西南蜀一維。", "一日三秋雙鬢改，兩鄉千里寸心馳。", "清香燕寢多佳致，遠景樓臺發妙詞。", "只恐江山留不得，賜環聞已下丹墀。"]'),
('4cf11668-17d0-4a4b-8584-cd873ee9a122','壽台州黄守','王之望','宋','宋诗','song-poetry','','[]','千載初平慶未窮，本支今復見仙翁。',64,'全唐诗/poet.song.112000.json','["千載初平慶未窮，本支今復見仙翁。", "當年郜鼎爭尤力，此日于門報已隆。", "政尚寬和承祖烈，量涵清濁稱家風。", "賜金增秩知非晚，行看絲綸下禁中。"]'),
('94082194-6b75-417a-a178-c36f2f62fdb1','壽處州徐守三首  其一','王之望','宋','宋诗','song-poetry','','[]','僕射文章六百春，人間又見石麒麟。',64,'全唐诗/poet.song.112000.json','["僕射文章六百春，人間又見石麒麟。", "朱顔白髮古仙伯，和氣清風今德人。", "出處三朝常守道，承宣千里更宜民。", "聖時共政須耆舊，歸去千秋輔紫宸。"]'),
('0e4d60df-4460-4e38-8a96-4896f39892f8','壽處州徐守三首  其二','王之望','宋','宋诗','song-poetry','','[]','共理經年惠利豐，此邦歌頌藹提封。',64,'全唐诗/poet.song.112000.json','["共理經年惠利豐，此邦歌頌藹提封。", "仙都洞府春風好，處士星躔瑞氣濃。", "道向偓佺傳口訣，禪從摩詰悟心宗。", "世間功業公餘事，平日高情薄萬鍾。"]'),
('140ed5fb-daaa-469d-a79b-78f748298807','壽處州徐守三首  其三','王之望','宋','宋诗','song-poetry','','[]','赤矢朱弓祖慶綿，五雲吉夢世生賢。',64,'全唐诗/poet.song.112000.json','["赤矢朱弓祖慶綿，五雲吉夢世生賢。", "嘉時浹日迎重九，景運中天恰半千。", "律播金商資爽氣，露和瓊屑引遐年。", "壽觴莫負專城貴，好對西風醉管弦。"]'),
('e25d2966-c6bf-4d83-a8fe-5140c336aa53','留題光相寺','王之望','宋','宋诗','song-poetry','','[]','至人悲念攝冥頑，倏見光明指顧間。',64,'全唐诗/poet.song.112000.json','["至人悲念攝冥頑，倏見光明指顧間。", "億劫未曾親見佛，一宵今得暫棲山。", "從來葉障須除結，此去功名直等閒。", "欲以殘年奉香火，塵勞無計戀松關。"]'),
('618eba89-d439-4b78-a059-422825a66481','挽張直講','王之望','宋','宋诗','song-poetry','','[]','早歲英聲已絕塵，暮年高節更殊倫。',64,'全唐诗/poet.song.112000.json','["早歲英聲已絕塵，暮年高節更殊倫。", "絳帷久擅詩書樂，朱邸頻釃酒醴醇。", "不許功名書竹帛，祇將文行照簪紳。", "鄉鄰若欲存遺範，祭社端宜配古今。"]'),
('32d6e4f5-89c7-4fba-8c84-cfd9e2b40a82','和李清卿雪','王之望','宋','宋诗','song-poetry','','[]','浩蕩天花弄曉光，春風未轉忽芬芳。',64,'全唐诗/poet.song.112000.json','["浩蕩天花弄曉光，春風未轉忽芬芳。", "人躋物外紅塵遠，境墮壺中白晝長。", "風柳冷飄三月絮，寒梅幽寄一枝香。", "朝來暴喜家風貴，圓璧方圭滿舍旁。"]'),
('5494ec36-5e9f-43c1-a942-b4f4e7ea61d5','吳明可寄詩次韵爲答','王之望','宋','宋诗','song-poetry','','["\u8861\u5c71"]','兩地相望百舍强，相思空結九回腸。',64,'全唐诗/poet.song.112000.json','["兩地相望百舍强，相思空結九回腸。", "君家滄海賓初日，我戍衡山俯夕陽。", "情話何當傾肺腑，倦遊聊復信行藏。", "求田問舍真長策，捧檄榮親道更光。"]'),
('619cdab8-e0b1-432b-89f3-6ab6b1546e49','房公湖','王之望','宋','宋诗','song-poetry','','[]','金雁橋南二頃湖，房公遺迹未湮蕪。',64,'全唐诗/poet.song.112000.json','["金雁橋南二頃湖，房公遺迹未湮蕪。", "人遊杜牧晚晴賦，境對王維別墅圖。", "經始林泉心自巧，折衝廊廟術何迂。", "當時只作幽人計，留得陳陶四萬夫。"]'),
('f96743a8-753f-45e1-8ce0-9f76f7025217','皇華館以上巳落成因修禊事題詩紀之','王之望','宋','宋诗','song-poetry','','[]','泉上新臺紫翠環，暮春修禊俯潺湲。',64,'全唐诗/poet.song.112000.json','["泉上新臺紫翠環，暮春修禊俯潺湲。", "漢流尚带桃花水，雲氣初披杏子山。", "柳絮輕颺晴日暖，竹光不動午陰閒。", "時和歲稔游人樂，一醉聊開病守顔。"]'),
('5ff24def-59db-447a-97d1-0d5d4bd7906a','呂叔恭運使和題皇華館詩復次韵','王之望','宋','宋诗','song-poetry','','[]','何處溪聲響佩環，洗心堂下轉潺湲。',64,'全唐诗/poet.song.112000.json','["何處溪聲響佩環，洗心堂下轉潺湲。", "數株古柳枯臨水，百畝叢篁翠倚山。", "歲久刊題多泯滅，時清景物自幽閒。", "軺軒登覽留佳句，頓覺林泉發妙顔。"]'),
('c13385cb-157e-41ac-9c05-8c774d691c66','帥漕復次韵再和','王之望','宋','宋诗','song-poetry','','[]','二豪詩律晉江東，迭倡更酬卷軸豐。',64,'全唐诗/poet.song.112000.json','["二豪詩律晉江東，迭倡更酬卷軸豐。", "狎主齊盟爭定霸，互爲勍敵銳臨戎。", "波瀾已得江流助，組麗仍依錦段紅。", "入蜀詞人多妙句，向來嚴杜一編同。"]'),
('7a70cafb-d18f-4042-8599-d5c3983496bd','中秋同兒姪登寶峰亭','王之望','宋','宋诗','song-poetry','','[]','絕頂憑欄思有餘，滄江下眺眇三隅。',64,'全唐诗/poet.song.112000.json','["絕頂憑欄思有餘，滄江下眺眇三隅。", "月光此夜十分滿，風色今朝一點無。", "鄉國不須悲楚蜀，庭階且喜集封胡。", "史君邂逅分鮮鯽，斫鱠還成逸少圖。"]'),
('c5b414fd-bbd5-4af5-8fd9-6725b2b670f2','缺題','王之望','宋','宋诗','song-poetry','','[]','天梯雲棧轉龍旗，細雨淒風暗路岐。',64,'全唐诗/poet.song.112000.json','["天梯雲棧轉龍旗，細雨淒風暗路岐。", "七夕難忘祈巧夜，三鄉不以望仙時。", "曲江若悟賢臣語，汾水寧傷才子詞。", "此日鈴聲腸斷處，後庭遺唱未爲悲。"]'),
('f02885b9-2aff-43aa-b7d7-8facd60c56fd','大龍湫','王之望','宋','宋诗','song-poetry','','[]','瀑水傳聞舊壯哉，飛流亭下久徘徊。',64,'全唐诗/poet.song.112000.json','["瀑水傳聞舊壯哉，飛流亭下久徘徊。", "玉龍鱗甲寒猶蟄，銀漢波瀾凍未開。", "斜日湫潭微濺雨，深冬天地不鳴雷。", "斯游未快平時意，更擬他年得得來。"]'),
('ff0b8f60-c8f8-4137-af1f-e8851804d55d','次韵劉南伯二首  其一','王之望','宋','宋诗','song-poetry','','[]','曉來庭竹碎秋聲，令我思君重愴情。',64,'全唐诗/poet.song.112000.json','["曉來庭竹碎秋聲，令我思君重愴情。", "三畫當年曾擅價，五言今去合知名。", "賦歸已荷因風寄，釃藇終期對月傾。", "但願官軍破驕敵，不妨淮海寄餘生。"]'),
('7963756e-9213-44a6-bba5-00357ffd8d9f','次韵劉南伯二首  其二','王之望','宋','宋诗','song-poetry','','[]','十年蹤跡困邅如，多謝韋郎肯寄書。',64,'全唐诗/poet.song.112000.json','["十年蹤跡困邅如，多謝韋郎肯寄書。", "千里漫尋苕水夢，一廛方對相山居。", "歸心不爲蒓鱸切，交契應閑簡牘疏。", "近向錢塘得嘉種，秋盤何日共新蔬。"]'),
('7e1d3064-532c-4d99-99fa-006eac6dfdd2','次韵王圜中二首  其一','王之望','宋','宋诗','song-poetry','','[]','網得金鱗不忍烹，一甌春菜眼偏明。',64,'全唐诗/poet.song.112000.json','["網得金鱗不忍烹，一甌春菜眼偏明。", "逢君强賦湖陰曲，顧我方趨日照城。", "散坐酴醿留客醉，過庭鵯鵊爲誰鳴。", "還朝密邇非輕別，知有蒲輪訪姓名。"]'),
('d020d6c3-2694-4d34-811e-e87cb077b1f5','次韵王圜中二首  其二','王之望','宋','宋诗','song-poetry','','[]','舟兀東風怯曉寒，綠楊堤畔見青山。',64,'全唐诗/poet.song.112000.json','["舟兀東風怯曉寒，綠楊堤畔見青山。", "遡流不礙朝天去，掉鞅何當拜命還。", "半世光陰憂患裏，他時勳業笑談間。", "兒童似覺吾衰老，只欲西歸便丐閒。"]'),
('f9e74755-dd0c-4693-aa5e-83d013de25b4','次韵制帥和王憲二首  其一','王之望','宋','宋诗','song-poetry','','[]','淮水綿綿不絕流，渡江龍化復東遊。',64,'全唐诗/poet.song.112000.json','["淮水綿綿不絕流，渡江龍化復東遊。", "宗盟尚詫當年盛，交分還欣此日投。", "名並邛郲公等繼，政稱京兆我難酬。", "得時俱爲公家計，三窟寧當各一州。"]'),
('001cb186-d98f-4e9c-8c9c-b031bc211def','次韵制帥和王憲二首  其二','王之望','宋','宋诗','song-poetry','','[]','二麥初收堰水流，西園飛蓋使君遊。',64,'全唐诗/poet.song.112000.json','["二麥初收堰水流，西園飛蓋使君遊。", "羽旄每出邦人喜，壺矢閒同坐客投。", "膏雨應時和氣洽，豐年有兆頌聲酬。", "政成訟簡追胥息，鎮靜西南五十州。"]'),
('faecf36d-77f2-4b95-b230-f4934e392a0c','次韵陳勉仲見留之什','王之望','宋','宋诗','song-poetry','','[]','新詩俊逸走風雷，愧我馳驅欲强陪。',64,'全唐诗/poet.song.112000.json','["新詩俊逸走風雷，愧我馳驅欲强陪。", "花外疏篁青掩映，門前流水綠縈迴。", "高情好客長留客，勝賞傳杯莫放杯。", "老懶畏寒朝睡美，報章淹緩莫相催。"]'),
('f383d8a7-49b2-4062-8fdc-eb8d62bcb972','寄制帥','王之望','宋','宋诗','song-poetry','','[]','五郡馳驅兩月忙，少城春事杳相忘。',64,'全唐诗/poet.song.112000.json','["五郡馳驅兩月忙，少城春事杳相忘。", "鷅鶹鳴處韶光老，鵜鴂聲中旅思長。", "曾爲青山迂客路，莫偕紅旆訪仙鄉。", "浣花時節歸期近，猶及遨頭共一觴。"]'),
('60eedec8-fdb0-47ad-846b-cd497e24f51c','和制帥','王之望','宋','宋诗','song-poetry','','[]','離索堪驚歲月忙，少城遺愛未曾忘。',64,'全唐诗/poet.song.112000.json','["離索堪驚歲月忙，少城遺愛未曾忘。", "西園尚記英遊並，南浦空嗟別恨長。", "壯志且窺勳業鏡，高情休憶水雲鄉。", "玉關柝靜邊烽息，漢殿歸稱萬歲觴。"]'),
('480fbc57-4ff3-4f85-9a6f-9864276e9d92','和制帥  其一','王之望','宋','宋诗','song-poetry','','[]','按部經時走四封，雲山有路寶巖通。',64,'全唐诗/poet.song.112000.json','["按部經時走四封，雲山有路寶巖通。", "普賢相對圓光裏，摩詰不離方丈中。", "喜有篇章交寄遠，恨無羽翼可凌空。", "來詩忽作蛟龍吼，三日能令兩耳聾。"]'),
('458df464-cbbf-48dd-a307-4099bcf32620','和制帥  其二','王之望','宋','宋诗','song-poetry','','[]','自憐麋鹿性疏頑，心在雲林迹世間。',64,'全唐诗/poet.song.112000.json','["自憐麋鹿性疏頑，心在雲林迹世間。", "每厭塵埃驅俗駕，不辭險阻訪名山。", "池魚得意時歸壑，廄馬長鳴暫出閑。", "萬仞峰頭曾進步，禪機一撥透三關。"]'),
('19225b9a-02ae-4def-a154-e8fd7e3a9e53','和制帥  其三','王之望','宋','宋诗','song-poetry','','[]','力求見佛上天梯，忽覩光明志意迷。',64,'全唐诗/poet.song.112000.json','["力求見佛上天梯，忽覩光明志意迷。", "華藏神通驚變現，臺山公案好拈提。", "太沖漫作三都賦，子美全無一字題。", "今日諸賢賡妙句，强驅駑駕力難齊。"]'),
('0b88fda8-14d6-4129-a18c-8bdb8d0f82d7','和制帥  其四','王之望','宋','宋诗','song-poetry','','[]','卿月中天照上流，使星入蜀久西遊。',64,'全唐诗/poet.song.112000.json','["卿月中天照上流，使星入蜀久西遊。", "蟠胸經緯開棋局，出手梟盧轉博投。", "學有淵源流不竭，詩如珠玉價難酬。", "詞章怪底猶雄健，棠蔭曾聯柳柳州。"]'),
('2456e385-5a95-4342-8612-b634d366d4b9','又和  其一','王之望','宋','宋诗','song-poetry','','[]','勝遊每恨不相同，郵遞猶欣日日通。',64,'全唐诗/poet.song.112000.json','["勝遊每恨不相同，郵遞猶欣日日通。", "玉帳未容佳境到，雲山已在好詩中。", "靈珠忽富千金贈，凡馬堪嗟萬古空。", "展卷高吟知幾過，大音一震耳根聾。"]'),
('57da6933-787c-45d1-a237-75ed862ed902','又和  其二','王之望','宋','宋诗','song-poetry','','[]','塵勞汩沒老尤頑，遍走岷峨杳靄間。',64,'全唐诗/poet.song.112000.json','["塵勞汩沒老尤頑，遍走岷峨杳靄間。", "筋力已疲難報國，田園有計即歸山。", "何期俗駕經時出，却得浮生數日閒。", "已請一麾江海去，故應生入玉門關。"]'),
('e2594981-1478-4f6e-90cf-673ef83c057b','又和  其三','王之望','宋','宋诗','song-poetry','','[]','新篇孤峻絕階梯，照眼光芒五色迷。',64,'全唐诗/poet.song.112000.json','["新篇孤峻絕階梯，照眼光芒五色迷。", "已向詩壇稱獨步，不妨祖令更全提。", "真空雅與高情契，絕景終希大手題。", "餘事文章暫遊戲，要將李杜與名齊。"]'),
('06cb3612-1005-443b-934e-b1a7593bb3c1','又和  其四','王之望','宋','宋诗','song-poetry','','[]','住因得坎去乘流，萬里西南更倦遊。',64,'全唐诗/poet.song.112000.json','["住因得坎去乘流，萬里西南更倦遊。", "三徑未成歸計晚，一尊猶喜故人投。", "小篇偶寓詩筒去，佳句還勞驛使酬。", "得與諸賢更倡和，故應盛事播西州。"]'),
('46300ee5-7c6a-4f5c-9bf3-25e10d6c631b','渾醉庵詩','王之望','宋','宋诗','song-poetry','','[]','人間歲月都幾許，醉裏光陰差較長。',64,'全唐诗/poet.song.112000.json','["人間歲月都幾許，醉裏光陰差較長。", "千日不醒終有盡，百年渾得要爲常。", "故人屢過無窮巷，一室能寬有醉鄉。", "好事不妨多酌我，老來無復次公狂。"]'),
('1506d25e-3768-4584-8663-7e98d3063379','又題鴻祐寺','王之望','宋','宋诗','song-poetry','','[]','石佛山頭日欲頹，尋僧不遇懶空回。',32,'全唐诗/poet.song.112000.json','["石佛山頭日欲頹，尋僧不遇懶空回。", "青鞋布襪雲門路，拄杖穿林歸去來。"]'),
('612c68df-abbf-4767-9333-496ab09efb31','戲景思  其一','王之望','宋','宋诗','song-poetry','','[]','明鏡佳期故未忘，月圓人缺恨何長。',32,'全唐诗/poet.song.112000.json','["明鏡佳期故未忘，月圓人缺恨何長。", "陽臺朝暮誰爲主，夢裏時時怨楚王。"]'),
('9d289099-0122-4451-ae29-515117aae214','戲景思  其二','王之望','宋','宋诗','song-poetry','','[]','顔色傾城藝更精，愛卿長是說卿卿。',32,'全唐诗/poet.song.112000.json','["顔色傾城藝更精，愛卿長是說卿卿。", "卷中昔日崔徽貌，重見應憐太瘦生。"]'),
('a8a114ee-a2ca-458a-a757-62619e62a123','題鄧寨周氏小園','王之望','宋','宋诗','song-poetry','','[]','徑草荒春綠作堆，東風深入小園來。',32,'全唐诗/poet.song.112000.json','["徑草荒春綠作堆，東風深入小園來。", "可憐幾陣嫣香裏，立盡庭前數樹梅。"]'),
('01fc2780-1f9f-4b93-a5e9-e0fd76fd2b18','病餘兀坐偶成二絕  其一','王之望','宋','宋诗','song-poetry','','[]','寂寂經旬病卧家，起來都不記年華。',32,'全唐诗/poet.song.112000.json','["寂寂經旬病卧家，起來都不記年華。", "一聲檐上驚秋晚，牆外初聞賣菊花。"]'),
('8f4e91ce-089e-4148-ac0d-e287dd61719b','病餘兀坐偶成二絕  其二','王之望','宋','宋诗','song-poetry','','[]','病骨欒欒瘦轉加，秋風怯傍小窗紗。',32,'全唐诗/poet.song.112000.json','["病骨欒欒瘦轉加，秋風怯傍小窗紗。", "蕭然丈室維摩觀，一炷清香到日斜。"]'),
('330e2777-aa7b-465e-9ee1-22c5196b3bc0','倚江亭會上虞伯逵送梅花并二絕句坐上次韵併調賀子忱  其一','王之望','宋','宋诗','song-poetry','','["\u897f\u6e56"]','腸斷江頭索笑花，三三兩兩逐枝斜。',32,'全唐诗/poet.song.112000.json','["腸斷江頭索笑花，三三兩兩逐枝斜。", "忽隨清絕驚人句，來自西湖處士家。"]'),
('da6c0177-6aa5-47e4-94f3-5970c7c54dec','倚江亭會上虞伯逵送梅花并二絕句坐上次韵併調賀子忱  其二','王之望','宋','宋诗','song-poetry','','[]','喜見江梅又著花，插來不怕帽簷斜。',32,'全唐诗/poet.song.112000.json','["喜見江梅又著花，插來不怕帽簷斜。", "高標幽韵誰真似，人在風流賀監家。"]'),
('31c83626-6492-4ec1-a0be-868468a485bd','和姚令威春陰四絕  其一','王之望','宋','宋诗','song-poetry','','[]','急雨顛風带海烟，白頭腸斷落花天。',32,'全唐诗/poet.song.112000.json','["急雨顛風带海烟，白頭腸斷落花天。", "東風爲買春光住，柳撒黄金榆擲錢。"]'),
('2ebc356a-1c58-447a-a1aa-3f6d62303ad4','和姚令威春陰四絕  其二','王之望','宋','宋诗','song-poetry','','[]','十日春陰晝景微，鳴鳩逐婦幾時歸。',32,'全唐诗/poet.song.112000.json','["十日春陰晝景微，鳴鳩逐婦幾時歸。", "柔桑細麥寧馨長，落絮遊絲可解飛。"]'),
('70745c67-838b-4316-b389-51a1c7af325f','和姚令威春陰四絕  其三','王之望','宋','宋诗','song-poetry','','[]','雨過山村綠滿陂，紅芳漸少翠陰低。',32,'全唐诗/poet.song.112000.json','["雨過山村綠滿陂，紅芳漸少翠陰低。", "春風吹草依然碧，潮水浮花却自西。"]'),
('eff7ee3b-d1ed-4963-8f16-eaf3ca7b8504','和姚令威春陰四絕  其四','王之望','宋','宋诗','song-poetry','','[]','休對風光感物華，且將春酒趁春賒。',32,'全唐诗/poet.song.112000.json','["休對風光感物華，且將春酒趁春賒。", "一聲杜宇芳菲晚，只有荼𧃲芍藥花。"]'),
('4daed05a-431e-4885-a080-b337b4c1a34b','題延慶觀六時泉','王之望','宋','宋诗','song-poetry','','[]','千尺高崖屏翠琰，六時甘露雨真珠。',32,'全唐诗/poet.song.112000.json','["千尺高崖屏翠琰，六時甘露雨真珠。", "梯巖穿壑身親到，始信仙靈境界殊。"]'),
('3676a5eb-bb3c-4029-b76d-53e9789ebd2a','和尚書李丈六絕  其一','王之望','宋','宋诗','song-poetry','','[]','丈人詩律照青春，句到諸郎副析薪。',32,'全唐诗/poet.song.112000.json','["丈人詩律照青春，句到諸郎副析薪。", "特許八分傳阿買，囊收珠玉破清貧。"]'),
('95f50b62-866d-459a-a08a-5d57453ac852','和尚書李丈六絕  其二','王之望','宋','宋诗','song-poetry','','[]','風光無頼惱詩翁，健筆凌雲思未慵。',32,'全唐诗/poet.song.112000.json','["風光無頼惱詩翁，健筆凌雲思未慵。", "長句數篇欺白雪，江山浩蕩發春容。"]'),
('c68edaf0-8e17-4f63-8d3d-c2966219b44f','和尚書李丈六絕  其三','王之望','宋','宋诗','song-poetry','','[]','近侍三朝捧御床，宮衣猶带內家香。',32,'全唐诗/poet.song.112000.json','["近侍三朝捧御床，宮衣猶带內家香。", "殊庭更得流霞助，杖屨春風步履强。"]'),
('add20e7c-1419-4dcf-bcf1-2cca8d59c46d','和尚書李丈六絕  其四','王之望','宋','宋诗','song-poetry','','[]','休論世事苦悲辛，龍卧南陽自有人。',32,'全唐诗/poet.song.112000.json','["休論世事苦悲辛，龍卧南陽自有人。", "指日承明却歸去，烟花紫禁及青春。"]'),
('e05d1ff2-f51f-4c4f-8cf3-42fa39581360','和尚書李丈六絕  其五','王之望','宋','宋诗','song-poetry','','[]','經旬山雨暗春輝，桃李成陰總未知。',32,'全唐诗/poet.song.112000.json','["經旬山雨暗春輝，桃李成陰總未知。", "試逐東風入城市，不妨尊酒暫娛嬉。"]'),
('4a39d57b-7745-4fe5-8cf9-136bae80bf89','和尚書李丈六絕  其六','王之望','宋','宋诗','song-poetry','','[]','雨過千山翠色重，羣花欲盡絮飛空。',32,'全唐诗/poet.song.112000.json','["雨過千山翠色重，羣花欲盡絮飛空。", "牡丹寂寞芬芳晚，日暮朱欄獨倚風。"]'),
('a9ed0f88-2c68-4c42-a8b6-388fdea6c2ab','題真符道中山寺','王之望','宋','宋诗','song-poetry','','[]','江路南風漲白沙，鐙馿來憩梵王家。',32,'全唐诗/poet.song.112000.json','["江路南風漲白沙，鐙馿來憩梵王家。", "片雲忽作蕭蕭雨，夢斷僧窗日未斜。"]'),
('2d18e26b-f3ba-4252-97f7-34b356c3df8d','題前詩已天忽作雨戲成一絕','王之望','宋','宋诗','song-poetry','','[]','歲暮靈泉水未饒，蒼崖無復舞飛蛟。',32,'全唐诗/poet.song.112000.json','["歲暮靈泉水未饒，蒼崖無復舞飛蛟。", "詩成不覺天零雨，料得神龍欲解嘲。"]'),
('4dac729f-f336-4de8-b9eb-ad73443f391b','鐘鼓山間久雨二絕  其一','王之望','宋','宋诗','song-poetry','','[]','山雨蕭蕭不肯住，天寒雲愁光景昏。',32,'全唐诗/poet.song.112000.json','["山雨蕭蕭不肯住，天寒雲愁光景昏。", "桃李紅白春風面，有恨無言空淚痕。"]'),
('9c413516-876d-4ed4-b053-d8c85a3245b0','鐘鼓山間久雨二絕  其二','王之望','宋','宋诗','song-poetry','','[]','高林縹緲强可見，茅屋半山烟雨昏。',32,'全唐诗/poet.song.112000.json','["高林縹緲强可見，茅屋半山烟雨昏。", "誰家一幅鵞溪絹，古畫猶存水墨痕。"]'),
('65f88a5a-3c58-4637-8339-ace439518414','次韵王司戶梅花五絕不得用古人意及比婦人玉雪并潔白等字  其一','王之望','宋','宋诗','song-poetry','','[]','牢落天涯邂逅逢，清愁幽恨與誰同。',32,'全唐诗/poet.song.112000.json','["牢落天涯邂逅逢，清愁幽恨與誰同。", "故園腸斷三千里，客裏看花歲又窮。"]'),
('cbf2fe5d-792e-48f7-bca0-98fa0a9fc9ab','次韵王司戶梅花五絕不得用古人意及比婦人玉雪并潔白等字  其二','王之望','宋','宋诗','song-poetry','','[]','溪外人家處處栽，三分蓓蕾一分開。',32,'全唐诗/poet.song.112000.json','["溪外人家處處栽，三分蓓蕾一分開。", "故教嫩萼參差發，似要幽人次第來。"]'),
('c798884d-411e-44dd-abc9-77df7c10b461','次韵王司戶梅花五絕不得用古人意及比婦人玉雪并潔白等字  其三','王之望','宋','宋诗','song-poetry','','[]','可耐幽花發較遲，殷勤爲倩曉風吹。',32,'全唐诗/poet.song.112000.json','["可耐幽花發較遲，殷勤爲倩曉風吹。", "朝來策杖探消息，香處初開一兩枝。"]'),
('d81d4588-c8f8-4d5a-8651-0c65e482c8f4','次韵王司戶梅花五絕不得用古人意及比婦人玉雪并潔白等字  其四','王之望','宋','宋诗','song-poetry','','[]','聞說江梅已惱人，衝寒著意去尋春。',32,'全唐诗/poet.song.113000.json','["聞說江梅已惱人，衝寒著意去尋春。", "枝枝細看枝枝好，歲歲相逢歲歲新。"]'),
('afa21001-a876-4604-88d1-e1145c15a01f','次韵王司戶梅花五絕不得用古人意及比婦人玉雪并潔白等字  其五','王之望','宋','宋诗','song-poetry','','[]','一歲都來幾日開，一開能得幾回來。',32,'全唐诗/poet.song.113000.json','["一歲都來幾日開，一開能得幾回來。", "清尊留待溪邊月，不怕山城晚鼓催。"]'),
('e2d9748b-e07c-4e9d-9289-c7b9efc2e8a9','和錢處和梅花五絕  其一','王之望','宋','宋诗','song-poetry','','[]','萬木歸根冷未滋，可憐孤絕發寒枝。',32,'全唐诗/poet.song.113000.json','["萬木歸根冷未滋，可憐孤絕發寒枝。", "心期本在冰霜後，占得隆冬未恨遲。"]'),
('410e9d3e-c4ef-4849-9ac2-443649154315','和錢處和梅花五絕  其二','王之望','宋','宋诗','song-poetry','','[]','枝上春風漸有涯，斷魂初見兩三花。',32,'全唐诗/poet.song.113000.json','["枝上春風漸有涯，斷魂初見兩三花。", "一尊盡日看無厭，要待參橫月影斜。"]'),
('06a6fdef-08dd-464c-a4d8-218b7908a3ca','和錢處和梅花五絕  其三','王之望','宋','宋诗','song-poetry','','[]','莫欺玉蕊瘦欒欒，中有江南長恨端。',32,'全唐诗/poet.song.113000.json','["莫欺玉蕊瘦欒欒，中有江南長恨端。", "白髮天涯歸未得，年年老眼淚中看。"]'),
('a56b7488-9d42-43f0-8e6e-06cb03c8ee30','和錢處和梅花五絕  其四','王之望','宋','宋诗','song-poetry','','[]','鐵心開府不妨狂，賦語清便獨擅唐。',32,'全唐诗/poet.song.113000.json','["鐵心開府不妨狂，賦語清便獨擅唐。", "堪笑離騷窮逐客，只知蘭蕙有幽香。"]'),
('04e60aa8-f7f3-49f9-9d6c-328dd7b463e3','和錢處和梅花五絕  其五','王之望','宋','宋诗','song-poetry','','[]','林下風神物外姿，閨房秀色鑑中奇。',32,'全唐诗/poet.song.113000.json','["林下風神物外姿，閨房秀色鑑中奇。", "兩家標韵誰兼得，會有多情識者知。"]'),
('789bd4a5-da01-457f-9f62-a8b2421138f3','以鼎爐遺關子東有詩相謝次韵  其一','王之望','宋','宋诗','song-poetry','','[]','君家聚古無不有，不腆敝器何足奇。',32,'全唐诗/poet.song.113000.json','["君家聚古無不有，不腆敝器何足奇。", "兩首新詩愧虛辱，恨無郜鼎爲君移。"]'),
('c055fcaf-3b38-4782-9370-8e8247c29db0','以鼎爐遺關子東有詩相謝次韵  其二','王之望','宋','宋诗','song-poetry','','[]','贈君劍川八卦鼎，一餠清泉終日然。',32,'全唐诗/poet.song.113000.json','["贈君劍川八卦鼎，一餠清泉終日然。", "浄几明窗讀周易，妙香時炷不論錢。"]'),
('511c91d4-adba-478c-bb85-bd8f89037b64','送海棠與姚令威','王之望','宋','宋诗','song-poetry','','[]','酣酣芳意不勝春，一笑嫣然惱殺人。',32,'全唐诗/poet.song.113000.json','["酣酣芳意不勝春，一笑嫣然惱殺人。", "分寄多情還解否，要教國色在東鄰。"]'),
('b9aef879-b647-4f16-a898-6b61bd09a794','謝景思惠酒并二絕時宗守邀看上元景思不至次韵  其一','王之望','宋','宋诗','song-poetry','','[]','戶外驚聞剝啄聲，東山消息到柴荆。',32,'全唐诗/poet.song.113000.json','["戶外驚聞剝啄聲，東山消息到柴荆。", "兩章著意撩衰白，風味相扶有麴生。"]'),
('daddbc10-bfea-4961-8419-0f78a68d1cea','謝景思惠酒并二絕時宗守邀看上元景思不至次韵  其二','王之望','宋','宋诗','song-poetry','','[]','使君高會著幽人，燈火元宵醉夜分。',32,'全唐诗/poet.song.113000.json','["使君高會著幽人，燈火元宵醉夜分。", "博士從來文字飲，不妨聊復醉紅裙。"]'),
('c24cb990-e9d9-4cef-b054-e14db1a21ff0','饒守陳粹中有詩見留次韵爲謝','王之望','宋','宋诗','song-poetry','','[]','相逢一笑又相離，腸斷登臨送別時。',32,'全唐诗/poet.song.113000.json','["相逢一笑又相離，腸斷登臨送別時。", "久占都亭慚重客，秋風回首片帆遲。"]'),
('a4823c05-1003-44d3-b5df-80b7044b35e8','郢守喬民瞻寄襄陽雪中三絕因追述前過石城杯酒登臨之勝爲和  其一','王之望','宋','宋诗','song-poetry','','[]','滄浪渡口莫愁鄉，萬頃寒烟木落霜。',32,'全唐诗/poet.song.113000.json','["滄浪渡口莫愁鄉，萬頃寒烟木落霜。", "珍重使君留客意，一尊芳酒醉斜陽。"]'),
('1a332040-ae2a-44cc-b2c8-1de1eac80c54','郢守喬民瞻寄襄陽雪中三絕因追述前過石城杯酒登臨之勝爲和  其二','王之望','宋','宋诗','song-poetry','','[]','江上危亭思黯然，追遊陳迹欲經年。',32,'全唐诗/poet.song.113000.json','["江上危亭思黯然，追遊陳迹欲經年。", "別來西望應相憶，郢樹荆門共一川。"]'),
('849d0490-3920-4b0e-8995-1c962187f1d9','郢守喬民瞻寄襄陽雪中三絕因追述前過石城杯酒登臨之勝爲和  其三','王之望','宋','宋诗','song-poetry','','[]','白雪樓傾不記秋，樓前江水自悠悠。',32,'全唐诗/poet.song.113000.json','["白雪樓傾不記秋，樓前江水自悠悠。", "多情猶憶湖南守，一曲陽春白盡頭。"]'),
('4dd1ba66-c54f-47e4-9358-88b8ff9ca835','浯溪中興頌碑','王之望','宋','宋诗','song-poetry','','[]','蜀日既衰洛日亡，前星靈武騰光芒。',208,'全唐诗/poet.song.113000.json','["蜀日既衰洛日亡，前星靈武騰光芒。", "元功百戰兩京復，萬里阿瞞歸故鄉。", "干戈紛紛遍四海，浯碑已立湘江旁。", "太師艱難喜粗定，作此大字龍鸞翔。", "紙摹縑搨四百載，家家傳寶踰琳琅。", "唐文中世未變古，燕許偶儷爲班揚。", "次山之文可也簡，此頌未追周魯商。", "祿山滔天等窮澆，春秋之法誅無將。", "騁兵二字斥邊將，此語豈足懲姦强。", "末篇三章頗辭費，筆力不復能鏗鏘。", "磨崖勒銘亦何有，反復自贊乃爾詳。", "向來各人過許與，舉世附和無雌黄。", "淮西仆碑無墨客，惜哉不得逢鍾王。"]'),
('ca4d9716-0078-4a65-b774-ea27799afbde','題王氏秀野堂','王之望','宋','宋诗','song-poetry','','[]','樹林陰翳鳥聲繁，下有幽人晝掩關。',64,'全唐诗/poet.song.113000.json','["樹林陰翳鳥聲繁，下有幽人晝掩關。", "五畝邱園傍城市，一堂花竹带雲山。", "留連風月真成趣，屏遠塵埃雅自閑。", "我訪一區無定所，卜鄰擬向翠微間。"]'),
('5fa9578f-9427-4e55-910c-93e75faf03dc','自公堂詩','王之望','宋','宋诗','song-poetry','','[]','叢石當軒峙，橫池傍砌深。',48,'全唐诗/poet.song.113000.json','["叢石當軒峙，橫池傍砌深。", "還將修竹繞，半入古榕陰。", "晝賞風瀾皺，宵憐月影侵。", "聊紓江海志，寄此小山林。"]'),
('9e396d0c-a5be-4312-934e-27bba5161415','再和制帥  其一','王之望','宋','宋诗','song-poetry','','[]','用盡登山力，方知行路難。',48,'全唐诗/poet.song.113000.json','["用盡登山力，方知行路難。", "孤峰寧久駐，半嶺敢求安。", "遠目窮千里，危腸攪百酸。", "川原忽開豁，歧路正平端。"]'),
('0db02004-8d92-4fc9-81f8-cf88fa98e38b','再和制帥  其二','王之望','宋','宋诗','song-poetry','','[]','露宿風餐走部封，要詢民瘼下情通。',64,'全唐诗/poet.song.113000.json','["露宿風餐走部封，要詢民瘼下情通。", "消磨光景驅馳裏，疲弊精神倥傯中。", "珠玉忽收千里贈，塵埃頓洗一襟空。", "病餘快覺心情爽，愈却頭風耳不聾。"]'),
('eaa3b900-6e99-49e2-a23b-2d30a4f70e98','再和制帥  其三','王之望','宋','宋诗','song-poetry','','[]','丘園養浩久懷安，忽侍天威咫尺間。',64,'全唐诗/poet.song.113000.json','["丘園養浩久懷安，忽侍天威咫尺間。", "草制方觀周誥命，籌邊聊重蜀江山。", "摶風已激三千水，掣電終歸十二閑。", "天遣詞人來作牧，勒銘重刻劍門關。"]'),
('91c4d2c7-e12e-4876-a50e-04f8b3523797','再和制帥  其四','王之望','宋','宋诗','song-poetry','','[]','羈懷感槩少多違，世路迍邅老更迷。',64,'全唐诗/poet.song.113000.json','["羈懷感槩少多違，世路迍邅老更迷。", "松檟十年乖種植，妻孥萬里困携提。", "龍門偶幸餘光借，雁塔曾同伯氏題。", "擁篲祇今知不晚，曹裝猶未去三齊。"]'),
('91fa902f-973a-4c19-a3ce-de39e5a21e3c','再和制帥  其五','王之望','宋','宋诗','song-poetry','','[]','武林一別幾經秋，誰料同爲錦里遊。',64,'全唐诗/poet.song.113000.json','["武林一別幾經秋，誰料同爲錦里遊。", "蒹葦已慚瑶樹倚，瓊琚仍愧木瓜投。", "小詩勉向忙中和，大白難禁醉裏酬。", "他日東南陪晤語，故應相對話刀州。"]'),
('fbb2eb19-1db1-4204-90e7-7d2d697441fb','再和制帥  其六','王之望','宋','宋诗','song-poetry','','[]','聖主不忘遠，惠懷堯所難。',48,'全唐诗/poet.song.113000.json','["聖主不忘遠，惠懷堯所難。", "如何吾所部，疲瘵未全安。", "詔條少宣布，牒訴多悲酸。", "撫節夜長歎，憂慚非一端。"]'),
('8274d937-ba82-4b8d-9a2b-e63ae7c8f64b','過石城  其一','王之望','宋','宋诗','song-poetry','','[]','滄浪渡口莫愁鄉，萬頃寒烟落木霜。',32,'全唐诗/poet.song.113000.json','["滄浪渡口莫愁鄉，萬頃寒烟落木霜。", "珍重使君留客意，一樽芳酒對斜陽。"]'),
('fc6e6797-4a12-4c68-b4bf-7ce4661833ca','過石城  其二','王之望','宋','宋诗','song-poetry','','[]','江上危亭思黯然，追遊陳跡欲經年。',32,'全唐诗/poet.song.113000.json','["江上危亭思黯然，追遊陳跡欲經年。", "別來西望應相憶，郢樹荆門共一川。"]'),
('3c52b59e-9e61-4284-afaf-9a4e214c934d','句  其一','王之望','宋','宋诗','song-poetry','','[]','雪班遠岫明蒼鬢，春秀奇峰擁翠鬟。',16,'全唐诗/poet.song.113000.json','["雪班遠岫明蒼鬢，春秀奇峰擁翠鬟。"]'),
('8a121cfc-a9ed-44cb-83c8-0d52f8dcf160','句  其二','王之望','宋','宋诗','song-poetry','','[]','神燈點點光可燭，星斗熒熒低欲捫。',16,'全唐诗/poet.song.113000.json','["神燈點點光可燭，星斗熒熒低欲捫。"]'),
('df2e621a-1554-4c60-af3e-6091f87ad6cd','偈頌一百零二首  其一','釋慧遠','宋','宋诗','song-poetry','','[]','千尺身中丈六衣，斬新拈出恰相宜。',32,'全唐诗/poet.song.113000.json','["千尺身中丈六衣，斬新拈出恰相宜。", "長針短線君看取，節角請訛我自知。"]'),
('86dfb593-6244-44e5-b434-1055b2de3091','偈頌一百零二首  其二','釋慧遠','宋','宋诗','song-poetry','','[]','龍幡勝槩落羣峰，水石清奇疊萬重。',32,'全唐诗/poet.song.113000.json','["龍幡勝槩落羣峰，水石清奇疊萬重。", "燕坐不辭提祖令，微軀那更繼前蹤。"]'),
('0f783db3-27ac-4600-b66b-5cac05737034','偈頌一百零二首  其三','釋慧遠','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','蝦蟇跳上梵天，蚯蚓驀過東海。',30,'全唐诗/poet.song.113000.json','["蝦蟇跳上梵天，蚯蚓驀過東海。", "洞庭湖頂門著地，龍蟠山腦後見腮。"]'),
('b0150270-dc4b-46c5-8fa0-c2c0d0b5fae1','偈頌一百零二首  其四','釋慧遠','宋','宋诗','song-poetry','','[]','隴麥青青春色過，嶺雲散盡楚天高。',32,'全唐诗/poet.song.113000.json','["隴麥青青春色過，嶺雲散盡楚天高。", "翻思歡喜園中事，八萬魔軍爭奈何。"]'),
('30aaf53e-c8d9-4b72-8363-4b561d934f20','偈頌一百零二首  其五','釋慧遠','宋','宋诗','song-poetry','','[]','如來不說無餘說，迦葉無聞無異聞。',62,'全唐诗/poet.song.113000.json','["如來不說無餘說，迦葉無聞無異聞。", "體得無聞無說說，玉石難分亦自分。", "國恩佛恩總報，人王法王道存。", "仰祝聖明逾日月，更祈睿筭等乾坤。"]'),
('20173e7a-a3d2-479a-bd2a-bf9c3681379b','偈頌一百零二首  其六','釋慧遠','宋','宋诗','song-poetry','','[]','黄面瞿曇，雖則分疏應口。',24,'全唐诗/poet.song.113000.json','["黄面瞿曇，雖則分疏應口。", "車不橫推，文殊仗劍逼佛。"]'),
('95034db8-d463-4415-97c1-59641962d73c','偈頌一百零二首  其七','釋慧遠','宋','宋诗','song-poetry','','[]','佛祖由來總是冤，電機旋處直如弦。',32,'全唐诗/poet.song.113000.json','["佛祖由來總是冤，電機旋處直如弦。", "金毛若解和聲拶，月裏麒麟笑揭天。"]'),
('3a6d2925-77fb-4bfd-99e5-f7affcb8cefb','偈頌一百零二首  其八','釋慧遠','宋','宋诗','song-poetry','','[]','掃盡衲僧蹤，裂破祖師印。',36,'全唐诗/poet.song.113000.json','["掃盡衲僧蹤，裂破祖師印。", "蹋翻香水海，透出威音前。", "生斷主人公，不落第二見。"]'),
('177661cc-5eda-489d-93a7-9f101de3a221','偈頌一百零二首  其九','釋慧遠','宋','宋诗','song-poetry','','[]','今朝九月初一，敗葉凋零滿室。',117,'全唐诗/poet.song.113000.json','["今朝九月初一，敗葉凋零滿室。", "鉢盂高挂懸崖，拄杖依前靠壁。", "幾許斸山風月，且無遮箇消息。", "諸祖不解提擲，久參那辨端的。", "雲黯黯兮胡漢何分，風蕭蕭兮鼻孔突出。", "自是捕盜無功，只管抱贓叫屈。", "捉得也，捉得也，在什麽處。", "晚風吹動小樓春，歸來一徑花狼藉。"]'),
('e2777511-d384-40d9-b387-42e341e51a73','偈頌一百零二首  其一○','釋慧遠','宋','宋诗','song-poetry','','[]','醉翁亭畔寒梅折，庶子泉邊瑞雪鋪。',32,'全唐诗/poet.song.113000.json','["醉翁亭畔寒梅折，庶子泉邊瑞雪鋪。", "不二法門從此入，更於何處覓文殊。"]'),
('6268c9bb-e1a5-457b-b7b9-c05f8705471b','偈頌一百零二首  其一一','釋慧遠','宋','宋诗','song-poetry','','[]','今朝四月八，邪師壞正法。',24,'全唐诗/poet.song.113000.json','["今朝四月八，邪師壞正法。", "累及釋迦文，死水裏淹殺。"]'),
('8a855c47-b575-411b-9624-d7cb655c6f94','偈頌一百零二首  其一二','釋慧遠','宋','宋诗','song-poetry','','[]','鶴立松梢月，魚行水底天。',24,'全唐诗/poet.song.113000.json','["鶴立松梢月，魚行水底天。", "風光都買盡，不費一文錢。"]'),
('f8d3c5f3-c0f6-474c-9117-e69823798cfa','偈頌一百零二首  其一三','釋慧遠','宋','宋诗','song-poetry','','[]','先師□住獨龍山，四十餘程自買船。',32,'全唐诗/poet.song.113000.json','["先師□住獨龍山，四十餘程自買船。", "今日琅瑘歸普濟，借婆裙子拜婆年。"]'),
('755d1e08-8272-4c0c-b420-b02f864c7cc6','偈頌一百零二首  其一四','釋慧遠','宋','宋诗','song-poetry','','[]','直下猶難會，尋言轉更賒。',40,'全唐诗/poet.song.113000.json','["直下猶難會，尋言轉更賒。", "若論佛與祖，特地隔天涯。", "看看，普濟拄杖子，化作天龍夜叉。"]'),
('d686097d-bf12-4de7-9b69-47a97d8bc80c','偈頌一百零二首  其一五','釋慧遠','宋','宋诗','song-poetry','','[]','南山匼匝雲遮日，西塢逡巡水滿塘。',32,'全唐诗/poet.song.113000.json','["南山匼匝雲遮日，西塢逡巡水滿塘。", "三日不來成話覇，葉公若在□郎當。"]'),
('0356fa98-f5ec-41c7-aafc-c37a9da15816','偈頌一百零二首  其一六','釋慧遠','宋','宋诗','song-poetry','','[]','白楓塢荆棘塞路，清潭山草莽纏身。',32,'全唐诗/poet.song.113000.json','["白楓塢荆棘塞路，清潭山草莽纏身。", "牛欄頭鱧魚𨁝跳，朱嶺榨出油三斤。"]'),
('2f217a69-2ca4-45a6-a7a5-b2927495d087','偈頌一百零二首  其一七','釋慧遠','宋','宋诗','song-poetry','','[]','掬水月在手，弄花香滿衣。',24,'全唐诗/poet.song.113000.json','["掬水月在手，弄花香滿衣。", "若作佛法會，永勸墮泥犁。"]'),
('0582f98a-f808-456e-9f02-51d4cae6dcbd','偈頌一百零二首  其一八','釋慧遠','宋','宋诗','song-poetry','','[]','元正啟祚舊時事，萬物咸新今日春。',100,'全唐诗/poet.song.113000.json','["元正啟祚舊時事，萬物咸新今日春。", "自是天機超妙化，何須更捋鬼頭巾。", "攀北斗，倚南辰，唱拍相隨特地新。", "引得水輪風輪火輪金輪相磨俱不動，執持世界等空手。", "面皮厚三寸，眉毛重八斤。", "有時無事倚門立，十字街頭等箇人。"]'),
('02d3b125-71a1-4c3a-82dc-d480fe010082','偈頌一百零二首  其一九','釋慧遠','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','五四三二一，日向東畔出。',48,'全唐诗/poet.song.113000.json','["五四三二一，日向東畔出。", "照見洞庭湖，烏龜眼睛赤。", "天無門，地無壁。", "一陣任風倒射回，吹起兩須無孔笛。"]'),
('44616f24-0912-4e08-a818-e647d978b982','偈頌一百零二首  其二○','釋慧遠','宋','宋诗','song-poetry','','[]','竹杖輕携離婺女，雲衣高捲上仙霞。',32,'全唐诗/poet.song.113000.json','["竹杖輕携離婺女，雲衣高捲上仙霞。", "五湖四海休云別，南北東西六一家。"]'),
('b4dc70b6-3297-427a-86e3-46ed5e98ddad','偈頌一百零二首  其二一','釋慧遠','宋','宋诗','song-poetry','','[]','愧我金鱗困守株，誤佗禪寂遠招呼。',32,'全唐诗/poet.song.113000.json','["愧我金鱗困守株，誤佗禪寂遠招呼。", "中途再領賢使命，定業難逃住子湖。"]'),
('9876e33a-9dec-47f0-8c20-dae56fc312a3','偈頌一百零二首  其二二','釋慧遠','宋','宋诗','song-poetry','','[]','年年正月一，鼻孔長三尺。',36,'全唐诗/poet.song.113000.json','["年年正月一，鼻孔長三尺。", "箇箇賀新春，眉毛重八斤。", "但□平正事，天道自分明。"]'),
('98f523c0-3c7a-4f45-822b-9f31e6aac969','偈頌一百零二首  其二三','釋慧遠','宋','宋诗','song-poetry','','[]','昨夜三更風起，吹皺一池春水。',42,'全唐诗/poet.song.113000.json','["昨夜三更風起，吹皺一池春水。", "魚龍頭角崢嶸，露柱振腮擺尾。", "蝦蟆㪍跳上天，鴨兒驚得匾觜。"]'),
('e838895a-cc51-4b49-9002-0c7ecceaeb8f','偈頌一百零二首  其二四','釋慧遠','宋','宋诗','song-poetry','','[]','迦葉不聞聞，如來無說說。',43,'全唐诗/poet.song.113000.json','["迦葉不聞聞，如來無說說。", "父子不相傳，神仙無秘訣。", "君不見謝豹花開雨後春，杜鵑啼破梢頭月。"]'),
('42699c59-9787-4245-afb0-c2808664f95d','偈頌一百零二首  其二五','釋慧遠','宋','宋诗','song-poetry','','[]','老胡誕生四月八，韶陽亂棒打不殺。',32,'全唐诗/poet.song.113000.json','["老胡誕生四月八，韶陽亂棒打不殺。", "如今縱得十分全，頂門正眼依前瞎。"]'),
('62c9e1ce-1c38-4428-ac49-d02222f3c04b','偈頌一百零二首  其二六','釋慧遠','宋','宋诗','song-poetry','','[]','大道忘情絕去留，天倫何處覓蹤由。',32,'全唐诗/poet.song.113000.json','["大道忘情絕去留，天倫何處覓蹤由。", "七星利劍當鋒按，八臂那吒輥繡毬。"]'),
('2e336f83-9f94-432c-9338-50877fae4838','偈頌一百零二首  其二七','釋慧遠','宋','宋诗','song-poetry','','[]','如是如是，腦門著地。',44,'全唐诗/poet.song.113000.json','["如是如是，腦門著地。", "不是不是，叉手長跪。", "是與不是，轉無巴鼻。", "北人運至南方，貨易獲其厚利。"]'),
('720e5184-8842-455f-adf4-8fd1c96cc01a','偈頌一百零二首  其二八','釋慧遠','宋','宋诗','song-poetry','','[]','新羅國裏打齋鍾，穩泛靈槎到月宮。',32,'全唐诗/poet.song.113000.json','["新羅國裏打齋鍾，穩泛靈槎到月宮。", "仙侶不知何處去，秋聲依舊著梧桐。"]'),
('77b407d8-d851-4831-9cc0-b6173f0cc5a7','偈頌一百零二首  其二九','釋慧遠','宋','宋诗','song-poetry','','[]','一塵入正受，諸塵三昧起。',76,'全唐诗/poet.song.113000.json','["一塵入正受，諸塵三昧起。", "諸塵入正受，一塵三昧起。", "三昧與正受，門檈作碓觜。", "起滅無定時，恰如眼見鬼。", "正受非正受，云何作道理。", "一去寥寥七百年，下載清風今未已。"]'),
('d50162dd-40c6-4abb-8930-2cfe4500e91a','偈頌一百零二首  其三○','釋慧遠','宋','宋诗','song-poetry','','[]','十月今朝又初一，叢林正值開爐日。',115,'全唐诗/poet.song.113000.json','["十月今朝又初一，叢林正值開爐日。", "打齋賣飯也尋常，殘杯冷炙誰能喫。", "天無門，地無壁。", "葫蘆棚上種冬瓜，兩手扶犁水過膝。", "跳金圈，吞栗棘，氈拍板對無孔笛。", "屈屈，獨脚山魈解雙踢。", "去年冬裏無炭燒，今年定是無火炙。", "饑時饑到眼睛黄，窮時窮至赤骨力。"]'),
('87543ceb-8be9-41f8-babe-e6d08865131b','偈頌一百零二首  其三一','釋慧遠','宋','宋诗','song-poetry','','[]','人天道大梅陽老，佛祖功恢臨濟宗。',32,'全唐诗/poet.song.113000.json','["人天道大梅陽老，佛祖功恢臨濟宗。", "赤手擘開無字印，冤家何處不相逢。"]'),
('6f5e763d-88e9-499c-a879-f99f808772fe','偈頌一百零二首  其三二','釋慧遠','宋','宋诗','song-poetry','','[]','梅陽老囑付此衣，遮護得山僧一半。',75,'全唐诗/poet.song.113000.json','["梅陽老囑付此衣，遮護得山僧一半。", "借問搭來何所宜，恰似當年賣柴漢。", "醤裏墮，雪中炭，留與叢林斫額看。", "君不見睦州嚴陵灘畔兜率寺裏有箇陳蒲鞵，解道秦時𨍏轢鑽。"]'),
('e0e7082a-76cc-4953-8c49-7695bcc4b952','偈頌一百零二首  其三三','釋慧遠','宋','宋诗','song-poetry','','[]','一二三，四五六，薩達麻繩難辨的。',32,'全唐诗/poet.song.113000.json','["一二三，四五六，薩達麻繩難辨的。", "翻身擲地向人前，鼻孔眼睛俱突出。"]'),
('0eb67c72-5aed-45aa-9939-b77f60c7a72a','偈頌一百零二首  其三四','釋慧遠','宋','宋诗','song-poetry','','[]','咄咄牯牛兒，森森頭角露。',165,'全唐诗/poet.song.113000.json','["咄咄牯牛兒，森森頭角露。", "恣貪肥膩草，脹殺孃生肚。", "憶昔未離羣，已作牛王步。", "今既離羣去，觸諱沒回互。", "沒回互病最堪憂，灌澉依前是好牛。", "有時喜，未跨門欄先撒𡱢。", "有時瞋，掉尾昂頭不顧人。", "有時好，舌端攬盡千峰草。", "有時惡，掣斷鼻頭雙服索。", "而今風和日暖，江南江北去何之，佇看深耕淺種拕犁拽杷正當時。", "稍乖角，覓便宜。", "老夫不惜操刀手，生捉歸來活剝皮。"]'),
('d66ffb55-6877-43cd-bf0a-00190e50be03','偈頌一百零二首  其三五','釋慧遠','宋','宋诗','song-poetry','','[]','彎彎初生如櫜弓，團團次第漾懸鏡。',64,'全唐诗/poet.song.113000.json','["彎彎初生如櫜弓，團團次第漾懸鏡。", "人間起舞爭清輝，影落秋江驗邪正。", "圓也缺也烏足論，體也用也誰能分。", "潦倒南泉沒碑記，夜隨流水繞孤村。"]'),
('e8d3a057-fd01-471a-8f84-c971810eac7c','偈頌一百零二首  其三六','釋慧遠','宋','宋诗','song-poetry','','[]','老婆二八少年時，羞向人前舞柘枝。',32,'全唐诗/poet.song.113000.json','["老婆二八少年時，羞向人前舞柘枝。", "而今要嫁便改嫁，誰管傍人說是非。"]'),
('edd83c41-13ca-4da4-90ca-83b72dd336b8','偈頌一百零二首  其三七','釋慧遠','宋','宋诗','song-poetry','','[]','良宵正月一，日從東畔出。',60,'全唐诗/poet.song.113000.json','["良宵正月一，日從東畔出。", "照見耆闍峰，回環指□中。", "坐斷石橋路，凡聖無回互。", "佛祖生冤家，相逢若稻麻。", "雪消春雨過，碓觜也生花。"]'),
('06cc2f0f-2bcd-4e9e-b63c-ddeafd75d39c','偈頌一百零二首  其三八','釋慧遠','宋','宋诗','song-poetry','','[]','一心不生，萬法無咎。',70,'全唐诗/poet.song.113000.json','["一心不生，萬法無咎。", "木匠带枷，自作自受。", "有心無法，受報好醜。", "有法無心，天長地久。", "心生法生，烏飛兔走。", "心滅法滅，倒翻筋斗。", "口似鼓椎，眉如掃箒。"]'),
('dc7ca8be-d4c8-4118-89bf-4cbbd1195418','偈頌一百零二首  其三九','釋慧遠','宋','宋诗','song-poetry','','[]','一粒紅稻飯，幾滴牛領血。',148,'全唐诗/poet.song.113000.json','["一粒紅稻飯，幾滴牛領血。", "憑君子細看，我亦難分雪。", "耕者耕未已，種者種不歇。", "目望九霄雲，誰顧三伏熱。", "秋收政其時，全在要精潔。", "升合等平分，彼我言詞絕。", "暗室不可欺，喫水也防噎。", "上人飽法味，道眼能昭徹。", "歸來滿鉢香，坐斷水雲舌。", "金毛恣翻躑，異獸潛深穴。", "栗棘金剛圈，略不通水泄。", "百草頭邊著眼看，七星用處當風截。"]'),
('dfa41ba4-99f3-44e7-a438-4a3cf907f459','偈頌一百零二首  其四○','釋慧遠','宋','宋诗','song-poetry','','[]','新歲有來由，烹茶上酒樓。',48,'全唐诗/poet.song.113000.json','["新歲有來由，烹茶上酒樓。", "一雙無兩脚，半箇有三頭。", "突出神難辨，相逢鬼見愁。", "倒吹無孔笛，促拍舞梁州。"]'),
('aba8f66e-561e-47e0-9e75-58d1523a53b8','偈頌一百零二首  其四一','釋慧遠','宋','宋诗','song-poetry','','[]','瞎堂也有三箇訣，靠倒雲門乾屎橛。',32,'全唐诗/poet.song.113000.json','["瞎堂也有三箇訣，靠倒雲門乾屎橛。", "一雙白大喫泥鰍，兩箇鷺鷥吞石蠮。"]'),
('e4b4ca84-1eea-4cf5-b514-5389c89e14b0','偈頌一百零二首  其四二','釋慧遠','宋','宋诗','song-poetry','','[]','堂前開飯店，屋裏販揚州。',28,'全唐诗/poet.song.113000.json','["堂前開飯店，屋裏販揚州。", "南泉翻鹽落醤鋼，趙州老鼠入牛角。"]'),
('1db9400c-3221-42b1-860d-d4856b5e6eef','偈頌一百零二首  其四三','釋慧遠','宋','宋诗','song-poetry','','[]','久雨不晴，務在丙丁。',54,'全唐诗/poet.song.113000.json','["久雨不晴，務在丙丁。", "修羅合掌，菩薩生瞋。", "佛也不會，波斯轉經。", "拗直作曲，弄假像真。", "好是明明說與，從教鴨聽雷聲。"]'),
('21d54d6c-84e8-4783-a022-4b1c4f948720','偈頌一百零二首  其四四','釋慧遠','宋','宋诗','song-poetry','','[]','陝府鐵牛口門窄，嘉州石佛耳輪長。',32,'全唐诗/poet.song.113000.json','["陝府鐵牛口門窄，嘉州石佛耳輪長。", "驚起暮天沙上雁，海門斜去兩三行。"]'),
('665470ea-c4bb-410a-aca3-62a3c965cb80','偈頌一百零二首  其四五','釋慧遠','宋','宋诗','song-poetry','','[]','初二十六，虀羹豆粥。',20,'全唐诗/poet.song.113000.json','["初二十六，虀羹豆粥。", "日午夜行，投明暗宿。"]'),
('419f5534-d0e6-4964-8635-2a5f91cacf49','偈頌一百零二首  其四六','釋慧遠','宋','宋诗','song-poetry','','[]','我聞禪師，榮領天竺。',163,'全唐诗/poet.song.113000.json','["我聞禪師，榮領天竺。", "山色湖光，爭輝奪日。", "佛法禪道，日月燈燭。", "眼放電光，機逾臂竹。", "說雲門禪，如珠走盤。", "唱無生曲，鏗金戛玉。", "千眼洞明，萬機攢簇。", "佛祖竝驅，水雲疊足。", "掣顛掣狂，可記可錄。", "誑嚇閭閻，鼓蕩流俗。", "眉毛廝結，形影相逐。", "把手共行，孤峰獨宿。", "彼上人者，難繼高躅。", "因甚如此，爲佗牽犁入市，騎牛上屋。", "七九從來八十三，六六何曾三十六。"]'),
('b78c04b7-a34a-40e8-a649-b4a8c464bd25','偈頌一百零二首  其四七','釋慧遠','宋','宋诗','song-poetry','','[]','阿呵呵，也大奇，折臂脩羅舞柘枝。',43,'全唐诗/poet.song.113000.json','["阿呵呵，也大奇，折臂脩羅舞柘枝。", "急如閃電，疾如飛毛，{眘皮}翣眼迷癡，得便宜是落便宜。"]'),
('fc502815-6b89-46a2-9d58-95a4b33b0e4a','偈頌一百零二首  其四八','釋慧遠','宋','宋诗','song-poetry','','[]','腐韝架壁本無情，致雨興雷自有因。',64,'全唐诗/poet.song.113000.json','["腐韝架壁本無情，致雨興雷自有因。", "傾倒十年放火口，高譚一夜動公卿。", "林長老，久相親，楚語吳歌曲調新。", "羚羊已挂懸崖角，猛虎難藏露地身。"]'),
('52e0dc6c-d443-4336-95ea-32f6ca4ec585','偈頌一百零二首  其四九','釋慧遠','宋','宋诗','song-poetry','','[]','萬機徹處若爲酬，千聖頭邊合自由。',32,'全唐诗/poet.song.113000.json','["萬機徹處若爲酬，千聖頭邊合自由。", "佛國乍歸金作界，仙宮回首玉爲樓。"]'),
('24cc5054-2e51-42b8-b985-a6c42c2f2d81','偈頌一百零二首  其五○','釋慧遠','宋','宋诗','song-poetry','','[]','大哉釋迦文，生下便作怪。',140,'全唐诗/poet.song.113000.json','["大哉釋迦文，生下便作怪。", "南北東西行，點胸也忒殺。", "棄捨輪王位，反受父母拜。", "六載向雪山，精進修浄戒。", "明星纔出現，證道果能快。", "分別說三乘，惹得一身債。", "最後向靈山，拈花索買賣。", "十萬衆人前，就中無一介。", "獨有迦葉波，和贓與捉敗。", "二千年前且放過，直至而今被佗壞。", "壞不壞，主元在。", "主既在，休廝頼。"]'),
('d5a27fa2-d726-48d0-9299-b3db69662cdf','偈頌一百零二首  其五一','釋慧遠','宋','宋诗','song-poetry','','[]','平生學弄蛇，是蛇皆可弄。',64,'全唐诗/poet.song.113000.json','["平生學弄蛇，是蛇皆可弄。", "唯有遮一條，咬人不可動。", "輕輕動便覺，和身入草蓬。", "草蓬深，無處尋，不用尋。", "好水好山留不住，千巖萬壑聽龍吟。"]'),
('9acacd43-19c0-4a6a-8836-c1a6ec03c909','偈頌一百零二首  其五二','釋慧遠','宋','宋诗','song-poetry','','[]','寒山掃松徑，拾得拂蒼苔。',28,'全唐诗/poet.song.113000.json','["寒山掃松徑，拾得拂蒼苔。", "憑仗東君些子力，一時吹入我門來。"]'),
('12a9fe47-6097-47db-ad42-c1127d3b4183','偈頌一百零二首  其五三','釋慧遠','宋','宋诗','song-poetry','','[]','古聖伽藍，一切成見。',20,'全唐诗/poet.song.113000.json','["古聖伽藍，一切成見。", "未跨三門，先見佛殿。"]'),
('24df977a-b5d9-4f04-aadb-ba9fdd531ba4','偈頌一百零二首  其五四','釋慧遠','宋','宋诗','song-poetry','','[]','毗耶離瞎人撞彩，摩竭陀啞子喫瓜。',35,'全唐诗/poet.song.113000.json','["毗耶離瞎人撞彩，摩竭陀啞子喫瓜。", "新長老到遮裏，棒頭開正眼，拳下作生涯。"]'),
('f3ea7f43-c3ea-443c-84ce-5e2ff9ff3442','偈頌一百零二首  其五五','釋慧遠','宋','宋诗','song-poetry','','[]','良宵三月十五，依舊神歌鬼舞。',84,'全唐诗/poet.song.113000.json','["良宵三月十五，依舊神歌鬼舞。", "未須三四吐吞，且看七八吞吐。", "臨濟瞎馿倒跨，雲門正法眼普。", "三人證鼈成龜，一任衲僧氣鼓。", "休氣鼓，甜者甜兮苦者苦。", "偃月長蛇不用呈，發機自有千鈞弩。"]'),
('1c6134dc-a832-4144-b209-963e36ed0249','偈頌一百零二首  其五六','釋慧遠','宋','宋诗','song-poetry','','[]','山僧有箇不是，喪盡衲僧巴鼻。',28,'全唐诗/poet.song.113000.json','["山僧有箇不是，喪盡衲僧巴鼻。", "驚回陝府鐵牛，吞却山河大地。"]'),
('bb044141-f443-45b3-9f9d-ee1f87bc0914','偈頌一百零二首  其五七','釋慧遠','宋','宋诗','song-poetry','','[]','四月上夏漸熱，善療也須調攝。',58,'全唐诗/poet.song.113000.json','["四月上夏漸熱，善療也須調攝。", "文殊眼裏抽筋，金剛腦後拔楔。", "須彌㪍跳上天，海底崑崙吐舌。", "幾度長歌幾度愁，一回飲水一回噎。"]'),
('c5575ed7-d9a4-4a63-8e83-938cf0191136','偈頌一百零二首  其五八','釋慧遠','宋','宋诗','song-poetry','','[]','徐六擔板，我則不然。',40,'全唐诗/poet.song.113000.json','["徐六擔板，我則不然。", "初三十一，不用擇日。", "鼻孔剔穿，眼睛突出。", "撞著露柱，參學事畢。"]'),
('fced70dc-ab1a-4fd5-909d-b1abebe3eaf3','偈頌一百零二首  其五九','釋慧遠','宋','宋诗','song-poetry','','[]','金地嶺胸中丘壑，赤城山皮裏陽秋。',32,'全唐诗/poet.song.113000.json','["金地嶺胸中丘壑，赤城山皮裏陽秋。", "華頂峰腦門著地，桐柏觀稽首叩頭。"]'),
('83c37a2b-5063-463e-af7b-f5baccbca622','偈頌一百零二首  其六○','釋慧遠','宋','宋诗','song-poetry','','[]','雲外千峰秀，目前雙澗清。',24,'全唐诗/poet.song.113000.json','["雲外千峰秀，目前雙澗清。", "若作如是會，永劫受沉淪。"]'),
('d15aa08a-223d-4683-89e7-847e1dd1e056','偈頌一百零二首  其六一','釋慧遠','宋','宋诗','song-poetry','','[]','今朝七月初一，叢林法歲將周。',86,'全唐诗/poet.song.113000.json','["今朝七月初一，叢林法歲將周。", "便請解開布袋，相從觸處□遊。", "解與不解總得，而今要休便休。", "凡聖本無忌諱，佛魔總是寃讎。", "靜悄悄沒干涉，閙浩浩莫能收。", "東行不見西行利，一葉落知天下秋。"]'),
('ea21a211-7dbe-43fb-ab50-70ed52b1ce37','偈頌一百零二首  其六二','釋慧遠','宋','宋诗','song-poetry','','[]','錦江巨浪連三峽，九隴峰高接五天。',94,'全唐诗/poet.song.113000.json','["錦江巨浪連三峽，九隴峰高接五天。", "中有導師口生角，眉毛落盡脚跟穿。", "擊得嘉州石佛眼中火出，驚回陝府鐵牛鼻孔生煙。", "阿呵呵，莫怨天。", "有利無利，不離行市。", "伸手縮手，無黨無偏。", "釅茶三五碗，意在钁頭邊。"]'),
('7dc9d88f-9db4-40da-929f-a14b43b8738d','偈頌一百零二首  其六三','釋慧遠','宋','宋诗','song-poetry','','[]','容路如天遠，情忘道義深。',24,'全唐诗/poet.song.113000.json','["容路如天遠，情忘道義深。", "虛空無向背，何處覓家音。"]'),
('c31cd3f9-54e6-46f6-957b-11a3b7c35d49','偈頌一百零二首  其六四','釋慧遠','宋','宋诗','song-poetry','','[]','道大兮功不立，隅無兮方莫存。',30,'全唐诗/poet.song.113000.json','["道大兮功不立，隅無兮方莫存。", "跨鼇頭兮歸巨海，挾月角兮出天門。"]'),
('3bb33f81-4930-4279-aa36-b0f1d317cf81','偈頌一百零二首  其六五','釋慧遠','宋','宋诗','song-poetry','','[]','大地毗嵐起，人天覺樹摧。',36,'全唐诗/poet.song.113000.json','["大地毗嵐起，人天覺樹摧。", "白雲歸大壑，慘霧結成堆。", "淼淼江天門，聲聲喚不回。"]'),
('8da89166-b8f3-4d53-8347-09257ac41135','偈頌一百零二首  其六六','釋慧遠','宋','宋诗','song-poetry','','[]','長連床上，北俱盧洲。',20,'全唐诗/poet.song.113000.json','["長連床上，北俱盧洲。", "喫粥喫飯，遍界冤讎。"]'),
('a7324fe3-a911-4471-8200-0adf63b5bc6c','偈頌一百零二首  其六七','釋慧遠','宋','宋诗','song-poetry','','[]','一是二，二是三，咬定牙關徹底參。',64,'全唐诗/poet.song.113000.json','["一是二，二是三，咬定牙關徹底參。", "閙浩浩時雙手擲，赤條條處兩肩擔。", "文殊老，强指南，□門三頓實難甘。", "五峰山下翻筋斗，八達衢頭轉放憨。"]'),
('0eadef93-564f-4d5a-9d03-cf170307153d','偈頌一百零二首  其六八','釋慧遠','宋','宋诗','song-poetry','','[]','大地山河不現，虛空冷汗通身。',28,'全唐诗/poet.song.113000.json','["大地山河不現，虛空冷汗通身。", "拄杖頭邊路絕，髑髏眼裏抽筋。"]'),
('d80e6163-eca0-4fa5-806c-b8793e0f5f01','偈頌一百零二首  其六九','釋慧遠','宋','宋诗','song-poetry','','[]','虎穴魔宮闊步挨，犁耕拔舌待君來。',80,'全唐诗/poet.song.113000.json','["虎穴魔宮闊步挨，犁耕拔舌待君來。", "摩雲鼻孔鬚胡口，閙裏相逢鬼擘開。", "不離刀山居馬腹，便從爐炭入馿胎。", "一句子，不須猜，延賓豈在預安排。", "換手搥胸何處去，蝦蟇頭上戴青苔。"]'),
('32cad4b0-7d6b-4cc3-bd8b-431a179d9f93','偈頌一百零二首  其七○','釋慧遠','宋','宋诗','song-poetry','','[]','今朝六月初五，明眼衲僧難覩。',60,'全唐诗/poet.song.113000.json','["今朝六月初五，明眼衲僧難覩。", "驚回座□□龜，咬殺街頭石虎。", "磨鎮旗，撾鐵鼓，破口半治閑佛祖。", "起坐相隨獨自行，夜漏聲沈日卓午。"]'),
('d1000554-54ec-49c6-ac89-2690d3d2b9b9','偈頌一百零二首  其七一','釋慧遠','宋','宋诗','song-poetry','','[]','今朝臘月二十，依舊眼橫鼻直。',98,'全唐诗/poet.song.113000.json','["今朝臘月二十，依舊眼橫鼻直。", "從頭收拾將來，恰似一棚雜劇。", "便是抹土塗灰，我也阿誰相識。", "九百木大小進，處分全由節級。", "忽然出至棚前，也解打躬相揖。", "駝起要打便打，放下要泣便泣。", "驀然冷笑一聲，笑倒判官五十。"]'),
('8c9297b5-2203-4654-b49c-b44b5db6204b','偈頌一百零二首  其七二','釋慧遠','宋','宋诗','song-poetry','','[]','夢魂飛錫下天台，疑是佗方應供來。',32,'全唐诗/poet.song.113000.json','["夢魂飛錫下天台，疑是佗方應供來。", "石室乍歸於霧冷，海山風月滿樓臺。"]'),
('391dbbbd-654c-483e-a2bd-69ec2feb359b','偈頌一百零二首  其七三','釋慧遠','宋','宋诗','song-poetry','','[]','曾到未到俱喫茶，不在沾唇眼便花。',32,'全唐诗/poet.song.113000.json','["曾到未到俱喫茶，不在沾唇眼便花。", "若是謝家船上客，肯來平地摝魚鰕。"]'),
('9b6ec766-ff6d-4b06-bf17-aa58000f51e4','偈頌一百零二首  其七四','釋慧遠','宋','宋诗','song-poetry','','[]','一雨洗郊原，千山鎖寒色。',24,'全唐诗/poet.song.113000.json','["一雨洗郊原，千山鎖寒色。", "底事不須論，元胡口門窄。"]'),
('f743f246-00d5-4174-8206-0ea263b85ae7','偈頌一百零二首  其七五','釋慧遠','宋','宋诗','song-poetry','','[]','仲冬十一月半，冷地急著眼看。',72,'全唐诗/poet.song.113000.json','["仲冬十一月半，冷地急著眼看。", "春來草木還青，冬去冰霜自泮。", "誰知兩箇五百，元來合成一貫。", "縱饒百煉真金，也入紅爐再煅。", "衡門突出古菱花，由勝秦時𨍏轢鑽。"]'),
('7b11960d-4e5e-4d1c-a265-7abdfb6a0e7a','偈頌一百零二首  其七六','釋慧遠','宋','宋诗','song-poetry','','[]','神仙秘訣妙難傳，禿頭修羅打左拳。',32,'全唐诗/poet.song.113000.json','["神仙秘訣妙難傳，禿頭修羅打左拳。", "夜半歸來無覓處，忍饑高卧飯籮邊。"]'),
('62d9e8f6-616e-4b9d-8deb-f951980ce2ca','偈頌一百零二首  其七七','釋慧遠','宋','宋诗','song-poetry','','[]','鉢盂盛世界，拄杖攪滄溟。',48,'全唐诗/poet.song.113000.json','["鉢盂盛世界，拄杖攪滄溟。", "魚龍俱削迹，佛祖也逃形。", "日午全機現，烏沉未出輪。", "秋高山月白，春至燒痕青。"]'),
('444b3a01-a72c-48ac-a4c2-ea78383c8304','偈頌一百零二首  其七八','釋慧遠','宋','宋诗','song-poetry','','[]','春日遲遲，春風浩浩。',40,'全唐诗/poet.song.113000.json','["春日遲遲，春風浩浩。", "綠水繞腰，青山戴帽。", "柳綠花紅，鴉鳴鵲噪。", "大施門開，何處著到。"]'),
('d43244a3-3a98-4226-adf4-6c657ea8c394','偈頌一百零二首  其七九','釋慧遠','宋','宋诗','song-poetry','','[]','兩陣交鋒笑似嗔，雙眉倒卓眼生筋。',32,'全唐诗/poet.song.113000.json','["兩陣交鋒笑似嗔，雙眉倒卓眼生筋。", "谿山雲月誰爲侶，南北東西絕近鄰。"]'),
('d7d7331f-e81c-4f8e-b650-8a736deb203c','偈頌一百零二首  其八○','釋慧遠','宋','宋诗','song-poetry','','[]','建山徐廷幹，三請譚般若。',104,'全唐诗/poet.song.113000.json','["建山徐廷幹，三請譚般若。", "未跨浮山門，一時說了也。", "更開破天口，塞破太虛空。", "潭南湘之北，趙州西院東。", "擲下金剛圈，更饒栗棘蓬。", "百千萬億箇，吞跳無有窮。", "幸有當陽險崖句，山僧不敢重下注。", "月裏麒麟笑揭天，泥牛拔斷珊瑚樹。"]'),
('d9e8c02f-6e0c-4f5e-833a-0fe0417292a2','偈頌一百零二首  其八一','釋慧遠','宋','宋诗','song-poetry','','[]','而來與一杓鹹鹽酸醋，北來與一杓苦菜淡虀。',35,'全唐诗/poet.song.113000.json','["而來與一杓鹹鹽酸醋，北來與一杓苦菜淡虀。", "喫則因邪打正，不喫則自東自西。"]'),
('3256a321-a8aa-4900-8414-94e792fb8168','偈頌一百零二首  其八二','釋慧遠','宋','宋诗','song-poetry','','[]','紅霞穿碧落，白鷺點蒼苔。',64,'全唐诗/poet.song.113000.json','["紅霞穿碧落，白鷺點蒼苔。", "不得顔良首，誰能歎善哉。", "根向梢頭出，子從花裏開。", "只遮是，不須猜，青山綠水鬢邊腮。", "有時尋不見，依舊却還來。"]'),
('34dd1320-1578-43f8-8312-b8e9cbb58164','偈頌一百零二首  其八三','釋慧遠','宋','宋诗','song-poetry','','[]','當年四月初八，老胡舊病再發。',60,'全唐诗/poet.song.113000.json','["當年四月初八，老胡舊病再發。", "雲門遇水脫鞵，且莫隨佗孟八。", "九龍吐水沐金軀，七步周行總不如。", "稽首歸依乾屎橛，胡鬚更撞赤鬚鬍。"]'),
('787bd478-ec13-41cc-944d-5a08d45ed76e','偈頌一百零二首  其八四','釋慧遠','宋','宋诗','song-poetry','','[]','水滿花肥春正長，東君作意腦愁腸。',32,'全唐诗/poet.song.113000.json','["水滿花肥春正長，東君作意腦愁腸。", "同風未必如吾蜀，鼻觀先聞荔子香。"]'),
('8bd2b263-3c95-45e3-b2fd-9f63173d9b38','偈頌一百零二首  其八五','釋慧遠','宋','宋诗','song-poetry','','[]','文殊盡力一問，維摩結舌無言。',70,'全唐诗/poet.song.113000.json','["文殊盡力一問，維摩結舌無言。", "布袋長時落魄，飲光論劫坐禪。", "鼻孔只在面上，口皮不離唇邊。", "四箇合成兩箇，三錢置得一錢。", "而今除本算利，且喜本利俱全。"]'),
('f804d948-6314-4103-8a31-b33df53a6229','偈頌一百零二首  其八六','釋慧遠','宋','宋诗','song-poetry','','[]','會得浮山兩錯，佛祖從頭架閣。',28,'全唐诗/poet.song.113000.json','["會得浮山兩錯，佛祖從頭架閣。", "若還依舊寧馨，若極黄病白鶴。"]'),
('c43b5cba-7be7-4ae1-ac67-d2aba41d77a6','偈頌一百零二首  其八七','釋慧遠','宋','宋诗','song-poetry','','[]','若能離諸相，即入法王家。',36,'全唐诗/poet.song.113000.json','["若能離諸相，即入法王家。", "法王無二法，無法即是家。", "是故法王法，當甚苦瓠瓜。"]'),
('ba86cc75-917a-4ea9-87a7-58923538ba12','偈頌一百零二首  其八八','釋慧遠','宋','宋诗','song-poetry','','[]','雲籠嶽頂，月印波心。',58,'全唐诗/poet.song.113000.json','["雲籠嶽頂，月印波心。", "私道車馬，官不容針。", "著底一任著，不著底一任不著。", "虎□龍駒，兔頭生角。", "春光夜雨晝晴，不怕和根爛却。"]'),
('c141d53e-8cff-43da-8ee4-b0b1597847ab','偈頌一百零二首  其八九','釋慧遠','宋','宋诗','song-poetry','','[]','門外春將半，巖花带雨開。',48,'全唐诗/poet.song.113000.json','["門外春將半，巖花带雨開。", "信從天外至，人自日邊來。", "虎嘯風生谷，龍吟霧滿腮。", "相逢眉蓋眼，平地舞三臺。"]'),
('3463582c-031c-4700-b2f2-6d70309f57fa','偈頌一百零二首  其九○','釋慧遠','宋','宋诗','song-poetry','','[]','菴內不知菴外事，鐵額銅頭不相似。',32,'全唐诗/poet.song.113000.json','["菴內不知菴外事，鐵額銅頭不相似。", "定花板上打鞦韆，猛虎舌頭書卍字。"]'),
('ffe8fcdd-7b62-47ad-8b5d-54f8b01fc551','偈頌一百零二首  其九一','釋慧遠','宋','宋诗','song-poetry','','[]','天書下十詔，雲恩飛九重。',24,'全唐诗/poet.song.113000.json','["天書下十詔，雲恩飛九重。", "萬邦歸正化，千載一遭逢。"]'),
('d3ea252b-91e9-406f-b41a-daf38fe9f63a','偈頌一百零二首  其九二','釋慧遠','宋','宋诗','song-poetry','','[]','電卷星馳作者知，倒施逆用猛提撕。',32,'全唐诗/poet.song.113000.json','["電卷星馳作者知，倒施逆用猛提撕。", "霜華寶劍當風按，忿怒那吒斫額窺。"]'),
('a95a9395-c528-427b-b2ba-8a47346ffd8f','偈頌一百零二首  其九三','釋慧遠','宋','宋诗','song-poetry','','[]','圓機互唱脫名模，妙應還同轉轆轤。',72,'全唐诗/poet.song.113000.json','["圓機互唱脫名模，妙應還同轉轆轤。", "北濟淵源連海嶠，西岐枝葉茂江湖。", "一句子，徹天衢。", "草木蟲魚隨物化，山川海嶽亦歡呼。", "大千世界歸明主，萬國梯航貢帝都。"]'),
('e8d900c4-d2e1-4cc2-8d5f-d395d5d15969','偈頌一百零二首  其九四','釋慧遠','宋','宋诗','song-poetry','','[]','風捲雲天小艇斜，煙波深處作生涯。',32,'全唐诗/poet.song.113000.json','["風捲雲天小艇斜，煙波深處作生涯。", "絲綸掣斷雙關手，抉出驪龍眼裏沙。"]'),
('765408cf-167a-4f10-9a2e-82085148e5e7','偈頌一百零二首  其九五','釋慧遠','宋','宋诗','song-poetry','','[]','託跡但知忘世故，棲蘆何事不容閑。',32,'全唐诗/poet.song.113000.json','["託跡但知忘世故，棲蘆何事不容閑。", "已能躡足龍門過，試把輪鉤颺碧灣。"]'),
('1b36fd9a-9992-477c-b9c2-4fe3ad98a47a','偈頌一百零二首  其九六','釋慧遠','宋','宋诗','song-poetry','','[]','青蒼山色挼藍翠，瀲灩湖光照眼新。',32,'全唐诗/poet.song.113000.json','["青蒼山色挼藍翠，瀲灩湖光照眼新。", "珍重導師居此地，頹綱振舉是其人。"]'),
('334c2903-7c83-4b2e-9168-bed355529828','偈頌一百零二首  其九七','釋慧遠','宋','宋诗','song-poetry','','[]','言無展事，語不投機。',84,'全唐诗/poet.song.113000.json','["言無展事，語不投機。", "頂門著眼，頷下安眉。", "聖凡路絕，事理俱非。", "刀截春風，鋸解稱鎚。", "刀鋸俱妙，明暗可追。", "刀鋸不爾，二破一虧。", "阿呵呵，也大奇。", "風卷怒濤天際闊，莫教斷送老頭皮。"]'),
('96ed7bd6-6fdc-48ad-a67f-2691b5adc200','偈頌一百零二首  其九八','釋慧遠','宋','宋诗','song-poetry','','[]','年年臘月三十日，家家門首釘桃符。',112,'全唐诗/poet.song.113000.json','["年年臘月三十日，家家門首釘桃符。", "苦菜澹虀隨分有，殘杯冷炙阿誰無。", "大丈夫，德不孤，醋酸不用挂葫蘆。", "收白牯，放狸奴。", "地碓舂粳光似玉，沙缾煮豆軟如酥。", "窮鬼子嘴，盧都一飽，但知忘百念，更有何人得似渠。", "從此華山圖籍上，更添潘閬倒騎馿。"]'),
('89ad1f1d-f7a3-4e0b-a18a-79e9ed896bc1','偈頌一百零二首  其九九','釋慧遠','宋','宋诗','song-poetry','','[]','濃雲潑墨無回互，疾燄過風不可窺。',32,'全唐诗/poet.song.113000.json','["濃雲潑墨無回互，疾燄過風不可窺。", "頼有金華慈愍力，火坑化作白蓮池。"]'),
('508a9f24-c757-4cdf-b838-04de341cf5e3','偈頌一百零二首  其一○○','釋慧遠','宋','宋诗','song-poetry','','[]','三世諸佛轉法輪，一大藏教說不盡。',64,'全唐诗/poet.song.113000.json','["三世諸佛轉法輪，一大藏教說不盡。", "象骨當機正令行，玄沙見機行正令。", "或說或聽聞不聞，電卷星飛誰與論。", "撥轉那邊關捩子，眉毛留得數莖有。"]'),
('124a7390-cada-41a5-aea2-b9c88c19e31f','偈頌一百零二首  其一○一','釋慧遠','宋','宋诗','song-poetry','','[]','來日書雲節，新陽歲月更。',48,'全唐诗/poet.song.113000.json','["來日書雲節，新陽歲月更。", "泥牛光影亂，石女肚膨脝。", "迤邐蛇吞甕，相將虎眼橫。", "春風一陣至，敢與百花爭。"]'),
('26d8bfbe-a4d2-4fd8-b17c-e76787ebce89','偈頌一百零二首  其一○二','釋慧遠','宋','宋诗','song-poetry','','[]','兩陣交鋒出戰時，旗鎗倒卓鼓無槌。',32,'全唐诗/poet.song.113000.json','["兩陣交鋒出戰時，旗鎗倒卓鼓無槌。", "絲毫不犯將軍令，獨脚機關各自提。"]'),
('888f5de8-0048-4bbb-9978-f1b853b74245','偈頌一百零二首  其一○三','釋慧遠','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','正如窮漢破衫袖，也不與萬法爲侶。',99,'全唐诗/poet.song.113000.json','["正如窮漢破衫袖，也不與萬法爲侶。", "捺著頭，掀尾舉，西江吸盡鐵船浮，活捉泥牛和角煮。", "潑天大，些子許，君不見二月三月寒食天，桃花杏花落如雨。", "一口吸盡西江水，栗棘金圈饒得底。", "解道心空及第歸，此去西天十萬里。"]'),
('f172d3c9-15f3-492d-928b-9384dcff7162','偈頌一百零二首  其一○四','釋慧遠','宋','宋诗','song-poetry','','[]','學道如學射，久久自中的。',24,'全唐诗/poet.song.113000.json','["學道如學射，久久自中的。", "一句透天關，萬機俱喪跡。"]'),
('06151bcc-f071-4b2c-863c-ca5c343638b7','偈頌一百零二首  其一○五','釋慧遠','宋','宋诗','song-poetry','','[]','參透西來鼻祖禪，乘時東去廣流傳。',64,'全唐诗/poet.song.113000.json','["參透西來鼻祖禪，乘時東去廣流傳。", "鑊湯爐炭隨緣入，劍樹刀山自在攀。", "教海義天休更問，龍宮寶藏豈能詮。", "翻身師子通塗妙，活捉魔王鼻孔穿。"]'),
('70e6339c-1f5d-44d2-84aa-47d77af124f1','頌古四十五首  其一','釋慧遠','宋','宋诗','song-poetry','','[]','未離兜率降王宮，便就刀山入鑊湯。',32,'全唐诗/poet.song.113000.json','["未離兜率降王宮，便就刀山入鑊湯。", "等閑擒下白拈賊，滿眼俱爲敗露贓。"]'),
('d4d38a1d-ff00-4eda-8001-e93f86bd72c9','頌古四十五首  其二','釋慧遠','宋','宋诗','song-poetry','','[]','毗藍園裏喪佳聲，分手徒勞布惡名。',32,'全唐诗/poet.song.113000.json','["毗藍園裏喪佳聲，分手徒勞布惡名。", "果是一文偷不得，至今虛作不良人。"]'),
('0f09e4c6-3310-403e-8ef6-92dfd494391c','頌古四十五首  其三','釋慧遠','宋','宋诗','song-poetry','','[]','十萬衆前無出路，冬瓜印子印何人。',32,'全唐诗/poet.song.113000.json','["十萬衆前無出路，冬瓜印子印何人。", "迦葉只因曾冷笑，至今陷在涅槃城。"]'),
('6f9e10b0-43e1-4a02-9ea3-d2b60b3c1eb1','頌古四十五首  其四','釋慧遠','宋','宋诗','song-poetry','','[]','家常待客勸三杯，鴆酒不消喫一盞。',32,'全唐诗/poet.song.113000.json','["家常待客勸三杯，鴆酒不消喫一盞。", "當時裂破夜叉頭，頂門突出醯羅眼。"]'),
('d550b9bd-a718-40a6-8bd6-d530a5ba1f84','頌古四十五首  其五','釋慧遠','宋','宋诗','song-poetry','','[]','纔拈折箭斷弦弓，隨手雙鵰落碧空。',32,'全唐诗/poet.song.113000.json','["纔拈折箭斷弦弓，隨手雙鵰落碧空。", "打鼓看來君不見，萬年松在祝融峰。"]'),
('ab0ddaa4-030b-4fbf-bd3d-acb9dba92ad9','頌古四十五首  其六','釋慧遠','宋','宋诗','song-poetry','','[]','馬面馿腮無處雪，海竭山摧天地裂。',40,'全唐诗/poet.song.113000.json','["馬面馿腮無處雪，海竭山摧天地裂。", "老古錐，太孤絕。", "龜毛拂去眼中塵，兔角杖敲空裏月。"]'),
('ca1a1adb-906d-4df1-89fc-0509a947613b','頌古四十五首  其七','釋慧遠','宋','宋诗','song-poetry','','[]','時臨孤島畔，拭目望蓬萊。',24,'全唐诗/poet.song.113000.json','["時臨孤島畔，拭目望蓬萊。", "空山無人處，水流花自開。"]'),
('05344189-c93f-4b8b-b86b-81487cbaeec4','頌古四十五首  其八','釋慧遠','宋','宋诗','song-poetry','','[]','咄咄瞎馿趁大隊，眨上眉毛佛不會。',32,'全唐诗/poet.song.113000.json','["咄咄瞎馿趁大隊，眨上眉毛佛不會。", "白雲斷處是青山，行人更在青山外。"]'),
('2a452987-b821-44c3-aaa7-7b7666842690','頌古四十五首  其九','釋慧遠','宋','宋诗','song-poetry','','[]','濃雲潑墨半遮山，碎雨跳珠亂入船。',32,'全唐诗/poet.song.113000.json','["濃雲潑墨半遮山，碎雨跳珠亂入船。", "卷地風來忽吹散，望湖樓下水如天。"]'),
('b0e17579-110b-4143-b196-906abd6b467e','頌古四十五首  其一○','釋慧遠','宋','宋诗','song-poetry','','[]','參天白刃赤身挨，李順王均破草鞵。',32,'全唐诗/poet.song.113000.json','["參天白刃赤身挨，李順王均破草鞵。", "德山智量過君子，活捉生擒立地埋。"]'),
('49091a5b-5e00-4c22-9c2e-c9d82bbf01f6','頌古四十五首  其一一','釋慧遠','宋','宋诗','song-poetry','','[]','梵志有錢時，能肥又能白。',36,'全唐诗/poet.song.113000.json','["梵志有錢時，能肥又能白。", "梵志無錢時，能瘦又能黑。", "十字街頭立，被人喚作賊。"]'),
('ccaf732e-ff85-4383-a41c-080c5b3fbf9f','頌古四十五首  其一二','釋慧遠','宋','宋诗','song-poetry','','[]','尊位如何，澄潭影裏探秋波。',65,'全唐诗/poet.song.113000.json','["尊位如何，澄潭影裏探秋波。", "日面月面，鐵眼銅睛安可辨。", "君不見一聲霹靂兮霧罩長空，千眼頓開兮雲收嶽面。", "還見馬師麽？病在膏肓，切須忌口。"]'),
('947c0e11-eca6-4b16-80d7-8f5c15ac729b','頌古四十五首  其一三','釋慧遠','宋','宋诗','song-poetry','','[]','摶風展翅拏滄海，直取龍吞也大奇。',65,'全唐诗/poet.song.113000.json','["摶風展翅拏滄海，直取龍吞也大奇。", "八臂那吒攔得住，和聲撲碎五須彌。", "風前截斷，句後全提。", "高出祖師三要印，不落雲門第一機。", "噫！盧陂盧陂。"]'),
('bce5e3ce-d64f-42b8-b55e-a148118b731c','頌古四十五首  其一四','釋慧遠','宋','宋诗','song-poetry','','[]','短帽輕衫宮樣窄，舞遍胡笳十八拍。',32,'全唐诗/poet.song.113000.json','["短帽輕衫宮樣窄，舞遍胡笳十八拍。", "曲罷酒闌猶未歸，歸來月色和雲白。"]'),
('af974b22-4f79-4677-ab40-8d91f4d680f7','頌古四十五首  其一五','釋慧遠','宋','宋诗','song-poetry','','[]','去若丘山重，來如一羽輕。',24,'全唐诗/poet.song.113000.json','["去若丘山重，來如一羽輕。", "去來無別路，傾蓋白頭新。"]'),
('c9258c03-41a1-4a0b-a8a0-83bd3af19a06','頌古四十五首  其一六','釋慧遠','宋','宋诗','song-poetry','','[]','唱拍相隨特地新，舞衣歌版不須呈。',32,'全唐诗/poet.song.113000.json','["唱拍相隨特地新，舞衣歌版不須呈。", "雲間獨有簫韶曲，未肯流傳取次人。"]'),
('b535d06c-79e6-4eed-9232-2c9d5649bdd8','頌古四十五首  其一七','釋慧遠','宋','宋诗','song-poetry','','[]','案頭獲敕令行時，閫外全提殺活機。',32,'全唐诗/poet.song.113000.json','["案頭獲敕令行時，閫外全提殺活機。", "回首華山孤頂望，巨靈神亦豎降旗。"]'),
('c5a2be6e-e91c-46e9-b605-d5fed389f54b','頌古四十五首  其一八','釋慧遠','宋','宋诗','song-poetry','','[]','率陀天上翻筋斗，酆畢羅都汩碖眠。',32,'全唐诗/poet.song.113000.json','["率陀天上翻筋斗，酆畢羅都汩碖眠。", "醉後歸來明月夜，笙歌引入畫堂前。"]'),
('588e6fd6-c476-4c64-a364-7b8f471bea64','頌古四十五首  其一九','釋慧遠','宋','宋诗','song-poetry','','[]','不是風幡動，亦非仁者心。',24,'全唐诗/poet.song.113000.json','["不是風幡動，亦非仁者心。", "自從胡亂後，淈𣸩到而今。"]'),
('1303526f-1e43-4239-8687-5953e70bb148','頌古四十五首  其二○','釋慧遠','宋','宋诗','song-poetry','','[]','楚王城畔水東流，獨脚山魈趯氣毬。',32,'全唐诗/poet.song.113000.json','["楚王城畔水東流，獨脚山魈趯氣毬。", "貪看六么花十八，不知船子下揚州。"]'),
('cc53eb5f-0386-486b-aa05-9d7f60a0436a','頌古四十五首  其二一','釋慧遠','宋','宋诗','song-poetry','','[]','神仙秘訣妙難傳，禿頂脩羅打左拳。',32,'全唐诗/poet.song.113000.json','["神仙秘訣妙難傳，禿頂脩羅打左拳。", "半夜歸來無覓處，忍饑高卧飯籮邊。"]'),
('083db837-f86d-4da2-b1a9-27a4ca5647bf','頌古四十五首  其二二','釋慧遠','宋','宋诗','song-poetry','','[]','登壇道士羽衣輕，呪力雖窮法轉新。',32,'全唐诗/poet.song.113000.json','["登壇道士羽衣輕，呪力雖窮法轉新。", "拇指破開天地暗，蛇頭攧落鬼神驚。"]'),
('8b62897b-f29d-438c-859b-a83f9baf97d7','頌古四十五首  其二三','釋慧遠','宋','宋诗','song-poetry','','[]','門裏有，門外有，不作嚴平犯牛斗。',64,'全唐诗/poet.song.113000.json','["門裏有，門外有，不作嚴平犯牛斗。", "師子嚬呻野犴鳴，抉出離婁眼裏筋。", "伸一手，縮一手，重陽决定九月九。", "相喚相呼獨自歸，赤骨貧窮露雙肘。"]'),
('0ef1a659-3829-43e0-9766-d73354b5c6ba','頌古四十五首  其二四','釋慧遠','宋','宋诗','song-poetry','','[]','膏肓未必兩邊尋，好是良醫雙下鍼。',32,'全唐诗/poet.song.113000.json','["膏肓未必兩邊尋，好是良醫雙下鍼。", "死活不能全忌口，喪車背後念觀音。"]'),
('136e7ee8-fab6-4e8b-9558-37720fe53459','頌古四十五首  其二五','釋慧遠','宋','宋诗','song-poetry','','[]','父嚴子逆事猶乖，宣德樓前問李差。',32,'全唐诗/poet.song.113000.json','["父嚴子逆事猶乖，宣德樓前問李差。", "斷頭剖腹從輕斷，直待還魂合處埋。"]'),
('402000a4-518f-467e-a302-138b9265a701','頌古四十五首  其二六','釋慧遠','宋','宋诗','song-poetry','','[]','汲水佳人立曉風，青絲放盡轆轤空。',32,'全唐诗/poet.song.113000.json','["汲水佳人立曉風，青絲放盡轆轤空。", "銀瓶觸破紅粧面，零落桃花滿井紅。"]'),
('9362d80b-2275-4152-b6e5-af06bd7fafb4','頌古四十五首  其二七','釋慧遠','宋','宋诗','song-poetry','','[]','兩陣交鋒笑似瞋，雙眉倒卓眼生筋。',32,'全唐诗/poet.song.113000.json','["兩陣交鋒笑似瞋，雙眉倒卓眼生筋。", "谿山雲月誰爲侶，南北東西絕近隣。"]'),
('298b9049-16de-428d-ba89-d3ca38651c97','頌古四十五首  其二八','釋慧遠','宋','宋诗','song-poetry','','[]','不問有言無言，說甚見影見鞭。',28,'全唐诗/poet.song.113000.json','["不問有言無言，說甚見影見鞭。", "露柱口挂壁上，燈籠倒退三千。"]'),
('d6f6ca7b-5781-4a21-8369-3247ef6c148a','頌古四十五首  其二九','釋慧遠','宋','宋诗','song-poetry','','[]','塞破太虛空，關津更不通。',40,'全唐诗/poet.song.113000.json','["塞破太虛空，關津更不通。", "文殊與網明，自西還自東。", "眉間拔劍頻相顧，女子瞿曇立下風。"]'),
('7dac97ab-9514-48fc-8d2e-be8876bfe86c','頌古四十五首  其三○','釋慧遠','宋','宋诗','song-poetry','','[]','等閑饒舌話金襴，便與當頭倒剎竿。',32,'全唐诗/poet.song.113000.json','["等閑饒舌話金襴，便與當頭倒剎竿。", "從此天倫轉無義，冷光猶自逼人寒。"]'),
('e203aaec-53df-488f-a0fe-f02bfda2ab05','頌古四十五首  其三一','釋慧遠','宋','宋诗','song-poetry','','[]','韶陽一擊最新奇，閙市門頭直面提。',32,'全唐诗/poet.song.113000.json','["韶陽一擊最新奇，閙市門頭直面提。", "倒嶽傾湫全正令，電光石火去難追。"]'),
('5792ef69-871f-4e09-b073-659b786e3b11','頌古四十五首  其三二','釋慧遠','宋','宋诗','song-poetry','','[]','眼目高低鼻孔橫，淺深輕重不多爭。',64,'全唐诗/poet.song.113000.json','["眼目高低鼻孔橫，淺深輕重不多爭。", "蠓蝱蠆上挨肩入，鸑鷟牙根借路行。", "便把長河攪酥酪，敢將粟柄作禾莖。", "後山未是潛身處，出沒任佗烏兔更。"]'),
('6b6c0e7b-fa50-4346-8fcd-f0c05e99ca40','頌古四十五首  其三三','釋慧遠','宋','宋诗','song-poetry','','[]','霧卷雲收，雷奔電爍。',44,'全唐诗/poet.song.113000.json','["霧卷雲收，雷奔電爍。", "眼暗耳聾，此錯彼錯。", "錯不錯，何處著。", "去兮住兮大匆匆，寂兮寥兮活鱍鱍。"]'),
('1de6a5f3-b189-4b65-bffa-c395d71e25e3','頌古四十五首  其三四','釋慧遠','宋','宋诗','song-poetry','','[]','饒君舌拄梵天，我也令行一半。',28,'全唐诗/poet.song.113000.json','["饒君舌拄梵天，我也令行一半。", "趙州頭戴草鞵，也是新繁轢鑽。"]'),
('be975cd1-3aaf-4403-82e8-d8fbc5620526','頌古四十五首  其三五','釋慧遠','宋','宋诗','song-poetry','','[]','趙州狗子無佛性，石牛不怕師子吼。',64,'全唐诗/poet.song.113000.json','["趙州狗子無佛性，石牛不怕師子吼。", "午夜雲騰浪接天，海門一陣狂風掃。", "茫茫大地參玄人，眼裏無筋一世貧。", "掣電機關何處討，頭角崢嶸出荒草。"]'),
('3941103f-3854-4720-9327-cb83b9291f59','頌古四十五首  其三六','釋慧遠','宋','宋诗','song-poetry','','[]','更深夜靜好商量，携手相將入醉鄉。',32,'全唐诗/poet.song.113000.json','["更深夜靜好商量，携手相將入醉鄉。", "姹女已歸霄漢去，獃郎何事守空房。"]'),
('a442f5a2-5f6e-416e-a72a-a8933d0f6f9b','頌古四十五首  其三七','釋慧遠','宋','宋诗','song-poetry','','[]','無位真人赤肉團，電機旋掣走珠盤。',32,'全唐诗/poet.song.113000.json','["無位真人赤肉團，電機旋掣走珠盤。", "金剛正眼泥彈子，烈燄光中側足看。"]'),
('e4a721e6-a9e2-451a-b198-9c1a9cafc714','頌古四十五首  其三八','釋慧遠','宋','宋诗','song-poetry','','[]','門外雨滴聲，家和萬事成。',24,'全唐诗/poet.song.113000.json','["門外雨滴聲，家和萬事成。", "歸來無一物，令人憶鏡清。"]'),
('b0a3e98d-5c5b-4021-8e7d-585548cc5569','頌古四十五首  其三九','釋慧遠','宋','宋诗','song-poetry','','[]','因我得禮汝，乾坤粟粒許。',24,'全唐诗/poet.song.113000.json','["因我得禮汝，乾坤粟粒許。", "若要除三害，無過問周處。"]'),
('3031a7e0-4ef1-431c-a3f7-02568614d75c','頌古四十五首  其四○','釋慧遠','宋','宋诗','song-poetry','','[]','神前撥帳問西來，直截當機指酒臺。',32,'全唐诗/poet.song.113000.json','["神前撥帳問西來，直截當機指酒臺。", "赤體袒肩頭面禮，禍從天降不生災。"]'),
('076382fe-1b10-4730-9ce5-9048658dfa61','頌古四十五首  其四一','釋慧遠','宋','宋诗','song-poetry','','[]','暑往寒來春復秋，夕陽西去水東流。',32,'全唐诗/poet.song.113000.json','["暑往寒來春復秋，夕陽西去水東流。", "將軍戰馬今何在，野草閑花滿地愁。"]'),
('656c202c-a936-4679-a0dc-e54a2cab4f01','頌古四十五首  其四二','釋慧遠','宋','宋诗','song-poetry','','[]','飄飄一雁落寒空，步步追空覓雁蹤。',32,'全唐诗/poet.song.113000.json','["飄飄一雁落寒空，步步追空覓雁蹤。", "蹋破草鞵跟已斷，巍然獨坐大雄峯。"]'),
('465a7568-bde6-48f2-998b-966d7547eaa5','釋迦出山相贊','釋慧遠','宋','宋诗','song-poetry','','[]','大哉釋迦文，福聚海無量。',40,'全唐诗/poet.song.113000.json','["大哉釋迦文，福聚海無量。", "此地少朱砂，赤土以爲上。", "我今稽首禮讚揚，留與人天作牓樣。"]'),
('9f23c7c4-4712-417b-9798-046b11d41e62','觀音大士贊','釋慧遠','宋','宋诗','song-poetry','','[]','大哉觀世音，功德不思議。',24,'全唐诗/poet.song.113000.json','["大哉觀世音，功德不思議。", "來說是非人，是非人便是。"]'),
('8a5c0b6b-7162-4587-9ce1-ce0a39f7d72e','布袋和尚贊恭依聖上韵','釋慧遠','宋','宋诗','song-poetry','','[]','布袋挨開，猿啼曉月。',59,'全唐诗/poet.song.113000.json','["布袋挨開，猿啼曉月。", "海嶽逃形，佛魔路絕。", "列列挈挈，翹翹傑傑。", "大機兮棒打不回頭，大用兮利劍流鮮血。", "別別，出海崑崙頭戴雪。"]'),
('9f3a7c7b-0c0a-46c3-a418-3150fba31525','誌公和尚贊','釋慧遠','宋','宋诗','song-poetry','','[]','一據獨龍岡，三朝揚聖化。',72,'全唐诗/poet.song.113000.json','["一據獨龍岡，三朝揚聖化。", "擘破老面皮，索盡遼天價。", "當時誤殺張僧繇，誰料而今轉更遥。", "描不成，畫不就，三箇骰兒拋十九。", "一段風光何處有，曲尺翦刀并掃箒。"]'),
('82f507e8-272c-4921-8ecf-68700f1b4aa3','維摩居士贊','釋慧遠','宋','宋诗','song-poetry','','[]','到處毀僧駡佛，知佗有官無官。',56,'全唐诗/poet.song.113000.json','["到處毀僧駡佛，知佗有官無官。", "善現屢遭呵責，瞿曇也被熱謾。", "只有文殊不肯，喫氣出來理問。", "遮漢自知無理，當時口似磉盤。"]'),
('d5eab81d-b663-42cf-b09e-8195f0af2080','金華聖者贊','釋慧遠','宋','宋诗','song-poetry','','[]','禦兵戈刀，斧不能斫。',52,'全唐诗/poet.song.113000.json','["禦兵戈刀，斧不能斫。", "經大劫水，火不能著。", "姊夫小舅有來由，佛面豬頭何處求。", "二百年來龜嶺下，三山依舊水東流。"]'),
('34c85d78-1972-4a8d-a70b-8e54850fc61b','達磨祖師贊','釋慧遠','宋','宋诗','song-poetry','','[]','不是梁皇勘過，肯來少室冷坐。',28,'全唐诗/poet.song.113000.json','["不是梁皇勘過，肯來少室冷坐。", "累佗二祖失心，被人喚作達磨。"]'),
('a886f97d-2c48-4829-b0ae-43ae07cf2fac','鹽官和尚贊','釋慧遠','宋','宋诗','song-poetry','','[]','老倒放，不會事。',30,'全唐诗/poet.song.113000.json','["老倒放，不會事。", "扇破覓，犀牛兒。", "尚有遺風餘烈，㗶吒噠哩嚤呢。"]'),
('95a425e0-9a0f-4eb2-a5b8-8a769aa6c8b6','雪峰和尚贊','釋慧遠','宋','宋诗','song-poetry','','[]','三回訪道投子，九度親到洞山。',44,'全唐诗/poet.song.113000.json','["三回訪道投子，九度親到洞山。", "末後最初非句，從教蓋地蓋天。", "三箇木毬開鬼眼，無端羈鎖落人間。"]'),
('75fc45cf-033d-4a27-a224-0163c4eedd58','長髭和尚贊','釋慧遠','宋','宋诗','song-poetry','','[]','突兀神光萬尋，𣭝𣬬髭鬚百結。',44,'全唐诗/poet.song.113000.json','["突兀神光萬尋，𣭝𣬬髭鬚百結。", "聲冤瑞應峯前，解道紅爐片雪。", "我今稽音問行蹤，敢向虛空釘鐵橛。"]'),
('eb0093cd-054b-4407-b9cf-b02206611112','臨濟和尚贊','釋慧遠','宋','宋诗','song-poetry','','["\u897f\u6e56"]','吹毛未舉，鮮血淋漓。',82,'全唐诗/poet.song.113000.json','["吹毛未舉，鮮血淋漓。", "塗毒纔撾，遍界橫屍。", "機如劈竹，口似鼓槌。", "二百年前江西湖南殺人放火，三千里外山東河北奪鼓攙旗。", "掀翻大海，倒坐須彌。", "青草步頭行正令，白拈手裏覓便宜。"]'),
('5d3fc1e2-bf37-4f4d-a92b-42ccd126290b','雲門大師贊','釋慧遠','宋','宋诗','song-poetry','','[]','倒著睦州破蒲鞵，橫輥雪峯爛毬子。',64,'全唐诗/poet.song.113000.json','["倒著睦州破蒲鞵，橫輥雪峯爛毬子。", "鴆鳥飛空草不生，毒龍入水魚皆死。", "單提獨掇驗人關，逆順雙行絕往還。", "遺烈尚餘風凜凜，至今猶有一斑斑。"]'),
('5a2b0ead-e84b-45cf-8fb3-e798a5f9fd8d','普化和尚贊','釋慧遠','宋','宋诗','song-poetry','','[]','熱發風狂，趯倒飯床。',76,'全唐诗/poet.song.113000.json','["熱發風狂，趯倒飯床。", "挨脚脫漏，倒翻筋斗。", "壞佗臨濟一生禪，啞却盤山三昧口。", "有時好，未必好。", "有時惡，未必惡。", "有時把箇破木鐸。", "大悲院裏趕村齋，直至而今無摸索。"]'),
('e4cf8655-f9bc-445b-a90b-baeac8af04a6','木平和尚贊','釋慧遠','宋','宋诗','song-poetry','','[]','嶽聳淵深，貌古神清。',74,'全唐诗/poet.song.113000.json','["嶽聳淵深，貌古神清。", "渴有米汁，饌無佳珍。", "龍床頭賣弄草鞵兩脚，御舟前突出雲衲半身。", "舉棹迷源兮檈索已露，移舟別水兮眼倒生筋。", "敢道不勞斤斧，夫是之謂木平。"]'),
('9b2de79d-d253-46ea-8297-af5729599d89','船子和尚贊  其一','釋慧遠','宋','宋诗','song-poetry','','[]','老手當年靠夾山，全機喪盡結深冤。',32,'全唐诗/poet.song.113000.json','["老手當年靠夾山，全機喪盡結深冤。", "父南子北家何在，撥轉天關地軸翻。"]'),
('b2b36371-8f12-4f66-8c46-178c2d7524c9','船子和尚贊  其二','釋慧遠','宋','宋诗','song-poetry','','[]','風卷雲天小艇斜，煙波深處作生涯。',32,'全唐诗/poet.song.113000.json','["風卷雲天小艇斜，煙波深處作生涯。", "絲綸掣斷雙關手，抉出驪龍眼裏沙。"]'),
('9c1cc5db-d705-49f8-a5ca-dda692ab77b6','香林遠和尚贊','釋慧遠','宋','宋诗','song-poetry','','[]','十八年參甚麽禪，雲門奧旨要人傳。',32,'全唐诗/poet.song.113000.json','["十八年參甚麽禪，雲門奧旨要人傳。", "驀然合著大石調，斬新臘月火燒山。"]'),
('3974cb3a-6fae-4fa6-a2da-3e39def5d7cf','楊岐和尚贊','釋慧遠','宋','宋诗','song-poetry','','[]','劄楊岐，獨脚寨。',84,'全唐诗/poet.song.113000.json','["劄楊岐，獨脚寨。", "嚇臨濟，小廝兒。", "栗棘金圈輸貨價，土曠人稀賣與誰。", "只將破草鞵泥彈子，向十字街頭換得眼睛三百擔。", "人亦不覺，鬼也不知，噫嘻嚱，半夜歸來日卓午，虛空依舊畫娥眉。"]'),
('3e7bda42-4c66-480f-aa32-26eda311813a','玉泉皓和尚贊','釋慧遠','宋','宋诗','song-poetry','','[]','倒施逆用，獨掇單提。',72,'全唐诗/poet.song.113000.json','["倒施逆用，獨掇單提。", "烏飛兔走，虎驟龍馳。", "晷運推移兮日南長至，布裩不洗兮無來換替。", "從教撒土拋沙，自在碗鳴𡱰沸。", "我今稽首樓至如來，揭諦揭諦波羅揭諦。"]'),
('d2b33e98-ab83-4e80-848e-f43be4ea6637','典午和尚贊','釋慧遠','宋','宋诗','song-poetry','','[]','濯錦之源，怒濤洶湧吞三峽。',134,'全唐诗/poet.song.113000.json','["濯錦之源，怒濤洶湧吞三峽。", "合浦之淵，巨浪騰空接五湖。", "奪雙標隨手便擲，考丹霞復得賢無。", "顱頂方衣，踞死心席面而飽飲鴆毒。", "鵰眉象準，造湛堂虎穴而斷命喪軀。", "徹黄龍三關巴鼻，脫臨濟十世規模。", "牛頭馬頭出沒，佛病祖病痛除。", "稽首瞎馿，非橫滅族。", "水無鱗介，巖有塗毒。", "義斷情忘，親承付囑。"]'),
('91213d98-ddff-43db-93ca-ae19dc7276f9','大慧禪師贊','釋慧遠','宋','宋诗','song-poetry','','[]','參禪闕典，學佛無功。',91,'全唐诗/poet.song.113000.json','["參禪闕典，學佛無功。", "破楊岐道，滅臨濟宗。", "直下單提，佛祖不犯令。", "掣顛掣狂，住雙徑峯。", "等閑拈却衲僧定命索，將錯就錯，名聞九重。", "阿呵呵，見也麽？竹篦觸背，失錢遭罪。", "天道不放還，驪珠絕瑕纇。"]'),
('21fa931e-0be6-4825-8c52-0cf1185f9960','楞嚴六根 非眼能見','釋慧遠','宋','宋诗','song-poetry','','[]','阿那律陀天眼觀，大千攝入一毫端。',32,'全唐诗/poet.song.113000.json','["阿那律陀天眼觀，大千攝入一毫端。", "掌中謾說菴摩勒，無限蒼生被熱謾。"]'),
('0c635fe0-0ec5-4770-8d47-ab783f2dfff3','楞嚴六根 無耳能聞','釋慧遠','宋','宋诗','song-poetry','','[]','跋難陀龍能聽聞，浄名結舌若爲論。',32,'全唐诗/poet.song.113000.json','["跋難陀龍能聽聞，浄名結舌若爲論。", "行到水窮山盡處，虛空依舊塞乾坤。"]'),
('46db36a9-b47b-4d32-98eb-b58364d495bc','楞嚴六根 無鼻嗅香','釋慧遠','宋','宋诗','song-poetry','','[]','殑伽河神非鼻香，貧兒乍富也尋常。',32,'全唐诗/poet.song.113000.json','["殑伽河神非鼻香，貧兒乍富也尋常。", "蓮河岸上曾遭叱，禍出私門變吉祥。"]'),
('686b3e46-4a73-4874-aaa0-a4eb7f27a753','楞嚴六根 異舌知味','釋慧遠','宋','宋诗','song-poetry','','[]','憍梵鉢提知此味，苦澀鹹酸那裏是。',32,'全唐诗/poet.song.113000.json','["憍梵鉢提知此味，苦澀鹹酸那裏是。", "一舉如能至梵天，超證如來真實義。"]'),
