('af7e7500-cd46-4241-b838-01933d26b2db','鏡菴','釋慧遠','宋','宋诗','song-poetry','','[]','古鏡破來菴許大，秋毫未盡眼能寬。',32,'全唐诗/poet.song.113000.json','["古鏡破來菴許大，秋毫未盡眼能寬。", "江湖不記三生夢，風月惟餘一釣竿。"]'),
('5d3509d3-d3d5-4e27-9346-8d970fb317ae','鴻福普同塔','釋慧遠','宋','宋诗','song-poetry','','[]','海底紅塵起，山頭白浪飛。',24,'全唐诗/poet.song.113000.json','["海底紅塵起，山頭白浪飛。", "若能如是會，永劫墮泥犁。"]'),
('3fc45e8c-30a4-4595-91fe-af0621803c32','題墨竹','釋慧遠','宋','宋诗','song-poetry','','[]','通乎筆端之有神，妙乎造化之有功。',46,'全唐诗/poet.song.113000.json','["通乎筆端之有神，妙乎造化之有功。", "戲蒼龍之引尾，背皓月而摇風。", "疏影無聲亂寒墨，瘦枝有葉翻秋空。"]'),
('c5c57454-120a-41e9-bb7f-6d46df07e3bb','福勝寺香風堂','釋慧遠','宋','宋诗','song-poetry','','[]','襲襲聞天都，飄飄滿衣𧞨。',60,'全唐诗/poet.song.113000.json','["襲襲聞天都，飄飄滿衣𧞨。", "高出威音前，平超樓至後。", "不墮四時春，肯與百花鬭。", "鼻觀豈能收，河神安可詬。", "陶然水鏡空，雲冷香風透。"]'),
('91fdd2da-1b7c-4287-bf32-d0075a730e33','妙喜南還以偈迓之','釋慧遠','宋','宋诗','song-poetry','','[]','聞道天書下禁闈，定知雲跡會樞機。',32,'全唐诗/poet.song.113000.json','["聞道天書下禁闈，定知雲跡會樞機。", "銅駝千載今休問，一段風光本彩歸。"]'),
('686e01a4-2bfc-42b8-a624-367561a23b7d','次萬年賁和尚韵  其一','釋慧遠','宋','宋诗','song-poetry','','[]','就得頭來正好參，倚佗門戶不相諳。',32,'全唐诗/poet.song.113000.json','["就得頭來正好參，倚佗門戶不相諳。", "導師故有眠雲句，應笑空生夢裏談。"]'),
('9fda2a18-d285-454e-988f-27d7fd02e59c','次萬年賁和尚韵  其二','釋慧遠','宋','宋诗','song-poetry','','[]','一丘一壑笑談開，安用相逢把酒杯。',32,'全唐诗/poet.song.113000.json','["一丘一壑笑談開，安用相逢把酒杯。", "雨後雨前牙爪在，細磨春色待君來。"]'),
('62feb6bb-f3b8-4569-a14b-84a5bab0adfb','寄中竺妙禪師','釋慧遠','宋','宋诗','song-poetry','','[]','湖山添得老魔王，舌卷風雷眼放光。',32,'全唐诗/poet.song.113000.json','["湖山添得老魔王，舌卷風雷眼放光。", "背却法堂重勘破，不知誰與我分贓。"]'),
('43159bdc-16ef-45b6-b017-4ae6ed025b0b','寄道場全和尚','釋慧遠','宋','宋诗','song-poetry','','[]','雪頂崑崙著意猜，十頭羅剎笑顔開。',32,'全唐诗/poet.song.113000.json','["雪頂崑崙著意猜，十頭羅剎笑顔開。", "鑊湯冷處君先入，滸眼橫時待我來。"]'),
('a137e86d-71c1-4440-bdc5-0dc3084ff3b4','寄㑃堂仁和尚','釋慧遠','宋','宋诗','song-poetry','','[]','一擊當機，千聖莫窺。',96,'全唐诗/poet.song.113000.json','["一擊當機，千聖莫窺。", "佩無文印，著糞掃衣。", "踞魔王殿，開邪見扉。", "說禪說道，惡口臊齒。", "論心論性，撒屎撒尿。", "牽犁上樹，拗折稱鎚。", "抗戾佛祖，倒行逆施。", "不是㑃堂，更是阿誰。", "曲罷酒闌人不會，斷腸依舊畫娥眉。"]'),
('6981ebad-542e-4250-80c3-17d8729874ff','寄體首座','釋慧遠','宋','宋诗','song-poetry','','[]','白石山頭衲子多，泥牛吸盡井中波。',32,'全唐诗/poet.song.113000.json','["白石山頭衲子多，泥牛吸盡井中波。", "佗年布袋重開口，佛祖依前不奈何。"]'),
('9428d9f9-0c3b-4d32-9c46-a5c73444afa3','送能首座住紫籜','釋慧遠','宋','宋诗','song-poetry','','[]','驅耕奪食繼心燈，互換交馳貨物增。',32,'全唐诗/poet.song.113000.json','["驅耕奪食繼心燈，互換交馳貨物增。", "道大莫知空冀北，功恢高揖嶺南能。"]'),
('ce590791-f65f-44fa-93b9-faecdc4e95e3','送宣長老住林泉','釋慧遠','宋','宋诗','song-poetry','','[]','脫籠掣轡換皮毛，水遠山長道自高。',32,'全唐诗/poet.song.113000.json','["脫籠掣轡換皮毛，水遠山長道自高。", "平澹家風隨分展，割雞時暫屈牛刀。"]'),
('5cea0ad0-b3b4-468a-9dc0-938081414a97','送九峰長老歸舊隠','釋慧遠','宋','宋诗','song-poetry','','[]','鐵面波斯駕怒濤，黑風纔起浪頭高。',32,'全唐诗/poet.song.113000.json','["鐵面波斯駕怒濤，黑風纔起浪頭高。", "倒撐小艇抽金鏃，恰似將軍入不毛。"]'),
('4561fb37-b1fa-471b-aa1b-e32aa02bf328','送之書記','釋慧遠','宋','宋诗','song-poetry','','[]','大用現前全體是，聖凡情盡影難留。',56,'全唐诗/poet.song.113000.json','["大用現前全體是，聖凡情盡影難留。", "鉢盂根底三千界，拄杖頭邊四百州。", "雲作伴，月爲儔。", "到家別有通天路，把定牢關輥繡毬。"]'),
('9805bb0d-3a16-4618-85f2-ab7f9aa091db','寄楊高士','釋慧遠','宋','宋诗','song-poetry','','[]','富有十年別，貧無一覺眠。',24,'全唐诗/poet.song.113000.json','["富有十年別，貧無一覺眠。", "好來同夜話，相共酌清泉。"]'),
('e98f0cca-1198-45ae-8a91-b8ab6f7adee9','寄源大師','釋慧遠','宋','宋诗','song-poetry','','[]','學佛以悟爲則，虛詞不入公門。',28,'全唐诗/poet.song.113000.json','["學佛以悟爲則，虛詞不入公門。", "君看羲之草聖，一點入石三分。"]'),
('76490b58-321f-431a-a6b4-896f1f914d7c','送萬年化主兼簡妙浄居士','釋慧遠','宋','宋诗','song-poetry','','[]','石橋路嶮橫身入，牛宿峰高䫌面看。',32,'全唐诗/poet.song.113000.json','["石橋路嶮橫身入，牛宿峰高䫌面看。", "不是閭丘賢太守，誰能閑識老豐干。"]'),
('7db9d04e-6186-4301-ba64-b9fa331e31df','送日本國覺阿金慶二禪人遊天台  其一','釋慧遠','宋','宋诗','song-poetry','','[]','佛子親從日本來，人天隨步歎奇哉。',32,'全唐诗/poet.song.113000.json','["佛子親從日本來，人天隨步歎奇哉。", "一機拶出金牛舞，千聖當頭正眼開。"]'),
('201ef7fb-b0fc-4df3-968a-964af8de0c1a','送日本國覺阿金慶二禪人遊天台  其二','釋慧遠','宋','宋诗','song-poetry','','[]','殺人放火大慈悲，禪教俱非道莫齊。',32,'全唐诗/poet.song.113000.json','["殺人放火大慈悲，禪教俱非道莫齊。", "平地一聲師子吼，釋迦彌勒豎降旗。"]'),
('04f2a8cc-4477-445e-9a0d-8bf35eec4a91','送日本國覺阿金慶二禪人遊天台  其三','釋慧遠','宋','宋诗','song-poetry','','[]','佛子飛帆過海來，好携瓶錫上天台。',32,'全唐诗/poet.song.113000.json','["佛子飛帆過海來，好携瓶錫上天台。", "國師尚有靈蹤在，寶塔巍然正面開。"]'),
('2042d9f6-d95a-4f58-9686-264232d75414','送日本國覺阿金慶二禪人遊天台  其四','釋慧遠','宋','宋诗','song-poetry','','[]','達磨西來教外宗，了無言說立全功。',32,'全唐诗/poet.song.113000.json','["達磨西來教外宗，了無言說立全功。", "單傳直指通身眼，誰信從前徹骨窮。"]'),
('a8efc2eb-0d49-4f2e-8c6a-fcfa8e705514','次陳秘書韵  其一','釋慧遠','宋','宋诗','song-poetry','','[]','保福當年閑借問，鵝湖驟步入僧堂。',32,'全唐诗/poet.song.113000.json','["保福當年閑借問，鵝湖驟步入僧堂。", "定盤星上無深意，莫認鉤頭些子香。"]'),
('df7edcf8-ca53-4cba-a4fb-0994060f247e','次陳秘書韵  其二','釋慧遠','宋','宋诗','song-poetry','','[]','一句單提脫正偏，百川風月自陶然。',32,'全唐诗/poet.song.113000.json','["一句單提脫正偏，百川風月自陶然。", "優樓不敢輕開口，合掌擎拳在佛前。"]'),
('fe558b65-574d-4fce-ac1d-518314793037','次陳秘書韵  其三','釋慧遠','宋','宋诗','song-poetry','','[]','旋機倒用從前事，奪食驅耕驗作家。',32,'全唐诗/poet.song.113000.json','["旋機倒用從前事，奪食驅耕驗作家。", "星電交馳玄路絕，從教努目視深沙。"]'),
('bd985dcf-ecf7-4271-90ff-03b85434e153','次陳判院韵','釋慧遠','宋','宋诗','song-poetry','','[]','謗佗佛法壞佗禪，劍樹刀山在目前。',32,'全唐诗/poet.song.113000.json','["謗佗佛法壞佗禪，劍樹刀山在目前。", "井底烏龜吞夜月，木人回首哭蒼天。"]'),
('08b5eef7-9236-4f79-8ba8-64b75798b03a','示無住道人','釋慧遠','宋','宋诗','song-poetry','','[]','打破從來浄潔禪，萬機攢簇髑髏前。',32,'全唐诗/poet.song.113000.json','["打破從來浄潔禪，萬機攢簇髑髏前。", "橫身塞斷來時路，一句當機日麗天。"]'),
('31c3b2ee-c589-43c7-bcfa-2cd8d4faf566','示幹水碓化士','釋慧遠','宋','宋诗','song-poetry','','[]','轉轆轆時難近傍，立停停處絕承當。',32,'全唐诗/poet.song.113000.json','["轉轆轆時難近傍，立停停處絕承當。", "磑磨碓擣從來事，磕破渾侖總不妨。"]'),
('b5beb413-e9ca-47f4-b307-dfd6f1629631','赴鴻福示衆','釋慧遠','宋','宋诗','song-poetry','','[]','十處住山今已老，半生雲水未忘機。',32,'全唐诗/poet.song.113000.json','["十處住山今已老，半生雲水未忘機。", "今朝又作浮山夢，暗寫愁腸寄與誰。"]'),
('d7debcef-a3aa-45f2-844d-1c425f43ea1c','送楊高士歸蜀','釋慧遠','宋','宋诗','song-poetry','','[]','龍馳虎驟道何存，肯轉靈丹奉至尊。',64,'全唐诗/poet.song.113000.json','["龍馳虎驟道何存，肯轉靈丹奉至尊。", "令下家山言下準，瓢中日月掌中分。", "昔年握手登金殿，今日擎拳出禁門。", "我欲送君迷舊隠，桃源流水杏花村。"]'),
('239f2981-6ff2-4a9c-8e81-295c02773ba4','寄驥禪人','釋慧遠','宋','宋诗','song-poetry','','[]','姑蘇臺畔惡相從，海湧峯前事亦同。',32,'全唐诗/poet.song.113000.json','["姑蘇臺畔惡相從，海湧峯前事亦同。", "故國夢回春已走，水雲相望一帆風。"]'),
('f3a1643c-ef31-4939-9710-eab88d210be4','送惠沖禪客','釋慧遠','宋','宋诗','song-poetry','','[]','老沖問法如春雷，忿怒那吒挽不回。',94,'全唐诗/poet.song.113000.json','["老沖問法如春雷，忿怒那吒挽不回。", "龍馳虎驟劈箭催，暴風狂雨山嶽摧。", "我亦隨分圓機應，出必取也戰必勝。", "如珠走盤盤走珠，星飛電轉了無餘。", "佗年呵風駡雨，巍巍獨坐妙峯頂。", "佇看殺人放火，烱烱雙眸爍太虛。"]'),
('ccaabfa5-1a6e-44fa-841a-aefa30bdf0c2','送了禪人','釋慧遠','宋','宋诗','song-poetry','','[]','未明定觀三千界，且看江西十八灘。',32,'全唐诗/poet.song.113000.json','["未明定觀三千界，且看江西十八灘。", "照出芙蓉城下月，金波影裏麥秋寒。"]'),
('05db9ce7-d0e9-4890-856d-4074d62ee33a','示禪人  其一','釋慧遠','宋','宋诗','song-poetry','','[]','鐵石身心來問道，慣調金鏃若爲酬。',32,'全唐诗/poet.song.113000.json','["鐵石身心來問道，慣調金鏃若爲酬。", "棒頭喝下隨流入，靠倒溈山水牯牛。"]'),
('8b85fb91-fd00-40bf-86a2-0f8bcadb3a83','示禪人  其二','釋慧遠','宋','宋诗','song-poetry','','[]','一句全提絕類倫，萬機不到始通津。',32,'全唐诗/poet.song.113000.json','["一句全提絕類倫，萬機不到始通津。", "道人別有遮天眼，四海無家總是親。"]'),
('66e982b1-dac8-4b17-b9b5-f2a38b70481f','示禪人  其三','釋慧遠','宋','宋诗','song-poetry','','[]','顧鑑全抽徹底參，新豐三頓實難甘。',32,'全唐诗/poet.song.113000.json','["顧鑑全抽徹底參，新豐三頓實難甘。", "到頭恩怨無餘地，贏得兒孫轉放憨。"]'),
('934e5903-11fe-49a1-99cb-7d5d8ea66366','示禪人  其四','釋慧遠','宋','宋诗','song-poetry','','[]','六塵不惡機難測，三昧無聲妙莫窮。',32,'全唐诗/poet.song.113000.json','["六塵不惡機難測，三昧無聲妙莫窮。", "脫體頓拋忘朕跡，瞎馿何處覓行蹤。"]'),
('01756c44-cad6-4b57-9ace-1f04a30af6b3','示禪人  其五','釋慧遠','宋','宋诗','song-poetry','','[]','懸崖捉拍舞三臺，死虎驚忙眼豁開。',32,'全唐诗/poet.song.113000.json','["懸崖捉拍舞三臺，死虎驚忙眼豁開。", "聖地不生凡草木，果然親見瞎堂來。"]'),
('84bcc4c2-3c67-4cea-b83c-04a0e50e90dd','示禪人  其六','釋慧遠','宋','宋诗','song-poetry','','[]','風前突出醯羅眼，格外單提栗棘禪。',32,'全唐诗/poet.song.113000.json','["風前突出醯羅眼，格外單提栗棘禪。", "百草頭邊玄路絕，到家不直半分錢。"]'),
('582e6cdb-3d3d-4b48-8f5a-b792f6abd216','示化士  其一','釋慧遠','宋','宋诗','song-poetry','','[]','披毛戴角學無生，劍樹刀山取次行。',32,'全唐诗/poet.song.113000.json','["披毛戴角學無生，劍樹刀山取次行。", "不向五峯吞栗棘，爭知日午打三更。"]'),
('deff17e3-c9e4-4c64-bb25-d34d59a23a5c','示化士  其二','釋慧遠','宋','宋诗','song-poetry','','[]','身如椰子膽如天，喝道來參栗棘禪。',32,'全唐诗/poet.song.113000.json','["身如椰子膽如天，喝道來參栗棘禪。", "按下雲頭輕領過，口皮元只在唇邊。"]'),
('eccd3516-5d4a-4b6e-89fd-dfe05665a7fe','示化士  其三','釋慧遠','宋','宋诗','song-poetry','','[]','臨濟家常添鉢遊，知音纔見不輕酬。',32,'全唐诗/poet.song.113000.json','["臨濟家常添鉢遊，知音纔見不輕酬。", "掩門歸去陳嘉饌，直至而今飽未休。"]'),
('67344803-55ba-42a8-b286-f32fc9314905','示化士  其四','釋慧遠','宋','宋诗','song-poetry','','[]','拄杖生根挑不上，鉢盂無底滿盛歸。',62,'全唐诗/poet.song.113000.json','["拄杖生根挑不上，鉢盂無底滿盛歸。", "浄名何用空惆悵，哭罷香嚴也不知。", "頭蓬鬆兮郡辨，耳卓朔兮莫窺。", "渡口船回人借問，寒山南畔石橋西。"]'),
('08e091d0-5060-4087-9c7c-bb5e839f0dbb','示化士  其五','釋慧遠','宋','宋诗','song-poetry','','[]','顧在機前發，鑑從顧後抽。',48,'全唐诗/poet.song.113000.json','["顧在機前發，鑑從顧後抽。", "法身藏北斗，船子下揚州。", "四海風爲線，三山月作鉤。", "回戈撥龍尾，佇看釣鼇頭。"]'),
('c0125b48-f98d-472d-b4e8-54190bb1419e','洪秀才乞頌','釋慧遠','宋','宋诗','song-poetry','','[]','列聖叢中獨許君，空王令下急翻身。',32,'全唐诗/poet.song.113000.json','["列聖叢中獨許君，空王令下急翻身。", "會須別有拏雲手，指出威音那畔人。"]'),
('e3df892a-6be0-4e0e-ac4e-89330b3e9ddc','陳道士乞頌','釋慧遠','宋','宋诗','song-poetry','','[]','先生道妙一時傳，我亦隨機叩兩端。',32,'全唐诗/poet.song.113000.json','["先生道妙一時傳，我亦隨機叩兩端。", "拈却司農無字印，百川從此絕波瀾。"]'),
('ed7b8545-da20-4d9a-b361-b44c3e044a7b','東陽光化士乞頌','釋慧遠','宋','宋诗','song-poetry','','[]','古殿燒殘不記年，冷光相射斗牛寒。',32,'全唐诗/poet.song.113000.json','["古殿燒殘不記年，冷光相射斗牛寒。", "投機會有揮斤手，碧瓦朱甍翠插天。"]'),
('b28c6feb-8e32-4615-ad0e-e2eb44966204','贈演說人','釋慧遠','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖演士妙天機，舌轉風雷口角飛。',64,'全唐诗/poet.song.113000.json','["西湖演士妙天機，舌轉風雷口角飛。", "奪騎未聞沙塞冷，斬關先覺陣雲低。", "前賢後聖從君數，水遠山長我自知。", "皓首不須尋舊隠，到頭誰是復誰非。"]'),
('d93119f3-107d-4a00-a312-f93a6027ff74','禪人寫師真請讚  其一','釋慧遠','宋','宋诗','song-poetry','','[]','早依圜悟，晚住林泉。',66,'全唐诗/poet.song.113000.json','["早依圜悟，晚住林泉。", "無門雪屈，遍界聲冤。", "對天子廓摩醯首羅眼，提楊岐金圈栗棘蓬禪。", "神仙秘訣，父子不傳。", "平地放開縛虎手，等閑迸出攔胸拳。"]'),
('95e61d1f-135c-4635-bf8b-304854922326','禪人寫師真請讚  其二','釋慧遠','宋','宋诗','song-poetry','','[]','獨步邪見林，高據魔王殿。',66,'全唐诗/poet.song.113000.json','["獨步邪見林，高據魔王殿。", "說欺凡罔聖禪，現夜叉羅剎面。", "掀翻巨嶽，徹底放憨。", "打破牢關，突出難辨。", "阿呵呵，見也麽。", "到江吳地盡，隔岸越山多。"]'),
('5ce5f9ba-716b-4200-aae1-0166b680a06c','禪人寫師真請讚  其三','釋慧遠','宋','宋诗','song-poetry','','[]','畫也錯，讚也錯。',46,'全唐诗/poet.song.113000.json','["畫也錯，讚也錯。", "不識蜆子笊籬，喚作普化木鐸。", "而今要且頭不是頭，脚不是脚。", "恐人無信，立此爲約。"]'),
('19ce0094-fc11-4c5f-b99b-cef9f1b7eca8','禪人寫師真請讚  其四','釋慧遠','宋','宋诗','song-poetry','','[]','開荆棘林，塞人天路。',48,'全唐诗/poet.song.113000.json','["開荆棘林，塞人天路。", "把斷綱宗，闊行大步。", "風高雲靜月眉橫，直向金輪水際行。", "到家無剩地，日出事還生。"]'),
('703cdaae-b722-4f5e-aa16-67090f2e4aa1','禪人寫師真請讚  其五','釋慧遠','宋','宋诗','song-poetry','','[]','斷滅佛種，破除家計。',46,'全唐诗/poet.song.113000.json','["斷滅佛種，破除家計。", "不是別人，楊岐五世。", "禪道耳邊風，佛法眼中翳。", "問渠將底爲人，尚有隨身赤契。"]'),
('0912ec89-b5ab-48d2-8c12-6a789ff10a7d','禪人寫師真請讚  其六','釋慧遠','宋','宋诗','song-poetry','','[]','大地一渾身，虛空絕四隣。',82,'全唐诗/poet.song.113000.json','["大地一渾身，虛空絕四隣。", "不識柏樹子，喚作麻三斤。", "好時十分瀟灑，惡時一味藞苴。", "等閑牽犁上佛殿，乘興鉢盂裏走馬。", "平地撒屎撒尿，知佗是真是假。", "禪人描邈將來，大蟲頭上火把。"]'),
('2049e3fb-da46-4d9b-bdcf-3385f0bf86ba','禪人寫師真請讚  其七','釋慧遠','宋','宋诗','song-poetry','','[]','祝髮何早，聞道何晚。',50,'全唐诗/poet.song.113000.json','["祝髮何早，聞道何晚。", "出林猛虎靠山，當路毒蛇開眼。", "重不重漏洩，擬不擬便著。", "借問呂望六韜，何似黄公三略。"]'),
('1b114c41-117f-4cb3-b976-63ffa1a4cedd','禪人寫師真請讚  其八','釋慧遠','宋','宋诗','song-poetry','','[]','把定放開全在你，和泥合水更由誰。',52,'全唐诗/poet.song.113000.json','["把定放開全在你，和泥合水更由誰。", "大地簇成三事衲，虛空迸出兩條眉。", "絕忌諱，猛提撕。", "驚回春夢破，倒跨鐵牛歸。"]'),
('914b268c-8039-409f-933a-50d2aa09f42e','禪人寫師真請讚  其九','釋慧遠','宋','宋诗','song-poetry','','[]','按輪王劍，全生殺機。',48,'全唐诗/poet.song.113000.json','["按輪王劍，全生殺機。", "豁開正眼，當頭者誰。", "從來無忌諱，底事沒商量。", "趙州密意憑誰訴，鐵作心肝也斷腸。"]'),
('2d698e78-e5f6-4d8b-ae12-1eb1212a0ddc','禪人寫師真請讚  其一○','釋慧遠','宋','宋诗','song-poetry','','[]','冷笑德山，熱謾臨濟。',48,'全唐诗/poet.song.113000.json','["冷笑德山，熱謾臨濟。", "頭重尾輕，碗鳴𡱰沸。", "明侍者，透天機，八十翁翁巧畫眉。", "掀翻師子窟，倒跨瞎馿兒。"]'),
('4cfdc679-c3a3-4212-8aca-f2f9c733a482','禪人寫師真請讚  其一一','釋慧遠','宋','宋诗','song-poetry','','[]','風高雲澹，露冷煙清。',52,'全唐诗/poet.song.113000.json','["風高雲澹，露冷煙清。", "坐松下石，聽松上聲。", "聞知見覺沒干涉，暑往寒來無處雪。", "八臂那吒䫌面看，七星利劍和聲截。"]'),
('15e562a7-6782-478b-b843-3c3fee021f04','禪人寫師真請讚  其一二','釋慧遠','宋','宋诗','song-poetry','','[]','畫出不堪，棄智雜毒。',46,'全唐诗/poet.song.113000.json','["畫出不堪，棄智雜毒。", "讚之不是，厭身桎梏。", "一十三處坐道場，二時粥飯何曾足。", "日裏夜行，投明暗宿。"]'),
('fa08dff9-af48-419f-9720-c296a7a7720b','禪人寫師真請讚  其一三','釋慧遠','宋','宋诗','song-poetry','','[]','透過荆棘林，瞎却醯羅眼。',52,'全唐诗/poet.song.113000.json','["透過荆棘林，瞎却醯羅眼。", "拈起破砂盆，放下漏燈盞。", "獨有周書記，全機識得渠。", "好笑雲黄傅大士，也曾赤脚禮文殊。"]'),
('90b2a502-e111-44ed-b354-a5c01b15fcba','禪人寫師真請讚  其一四','釋慧遠','宋','宋诗','song-poetry','','[]','靠倒雲門抽顧鑒，挨開臨濟主賓禪。',56,'全唐诗/poet.song.113000.json','["靠倒雲門抽顧鑒，挨開臨濟主賓禪。", "一星猊血化馿乳，半點鸞膠續斷弦。", "淳侍者，脫機緣。", "波斯拾得招文袋，月裏麒麟笑揭天。"]'),
('9a3d9a58-d142-4d56-bf4e-75b26b1f1b83','禪人寫師真請讚  其一五','釋慧遠','宋','宋诗','song-poetry','','[]','帀地普天，銀山鐵壁。',52,'全唐诗/poet.song.113000.json','["帀地普天，銀山鐵壁。", "正令全提，虛空削跡。", "月眉橫，照用分，星流電掣透龍門。", "向道瞎馿無忌諱，脚尖趯出舊乾坤。"]'),
('968d384f-42a2-4258-9431-432597434f70','禪人寫師真請讚  其一六','釋慧遠','宋','宋诗','song-poetry','','[]','不參鼻祖禪，不使冬瓜印。',52,'全唐诗/poet.song.113000.json','["不參鼻祖禪，不使冬瓜印。", "倒拈定命索，單提不犯令。", "天堂地獄莫能收，佛界魔宮任意遊。", "因尋清水閘，誤入赤城州。"]'),
('ffc5333d-8f7e-4525-8482-0ade3422bbb7','禪人寫師真請讚  其一七','釋慧遠','宋','宋诗','song-poetry','','[]','雖有兩條眉，不識一箇字。',66,'全唐诗/poet.song.113000.json','["雖有兩條眉，不識一箇字。", "露柱未懷胎，面目却相似。", "說心說性，來與三斤麻。", "撒屎撒尿，演出一大事。", "阿呵呵，見也麽？江南生皂樹，江北出天蘿。"]'),
('277d05c3-5e3c-4015-ad08-ea7aa176bb08','禪人寫師真請讚  其一八','釋慧遠','宋','宋诗','song-poetry','','[]','橫按拄杖，坐盤陀石。',44,'全唐诗/poet.song.113000.json','["橫按拄杖，坐盤陀石。", "鼻孔遼天，眼睛突出。", "澹煙籠古樹，缺月挂藤蘿。", "分付俊禪者，勘破老頭陀。"]'),
('62fd5dab-c307-4f5a-8718-a30d9a6d7cca','禪人寫師真請讚  其一九','釋慧遠','宋','宋诗','song-poetry','','[]','列列挈挈，磽磽聱聱。',44,'全唐诗/poet.song.113000.json','["列列挈挈，磽磽聱聱。", "廓然無聖，平地喫交。", "鼻孔生三竅，眉毛只一般。", "奇哉王道士，頭戴樺皮冠。"]'),
('1b12c341-d73a-427a-a026-e5e6a9499f48','禪人寫師真請讚  其二○','釋慧遠','宋','宋诗','song-poetry','','[]','面目可憎，語言無味。',52,'全唐诗/poet.song.113000.json','["面目可憎，語言無味。", "放箸忘恩，停杯斷義。", "參得些兒小玉禪，幾回賣弄帝王前。", "圓悟室中遭毒手，爲人揮起迸心拳。"]'),
('123a9aba-70a8-4fde-9926-871ef815e691','禪人寫師真請讚  其二一','釋慧遠','宋','宋诗','song-poetry','','[]','飄飄蕭蕭松百赤，突突兀兀雲半肩。',32,'全唐诗/poet.song.113000.json','["飄飄蕭蕭松百赤，突突兀兀雲半肩。", "放□□□□□調，剛被時人喚作禪。"]'),
('f77bc6e7-a825-4109-988c-ae2e12524a9c','禪人寫師真請讚  其二二','釋慧遠','宋','宋诗','song-poetry','','[]','松形鶴骨底村僧，鬼妬人嫌我亦憎。',84,'全唐诗/poet.song.113000.json','["松形鶴骨底村僧，鬼妬人嫌我亦憎。", "懸羊賣狗隨時遣，栗棘金圈任跳吞。", "忽然拶著東弗于逮，騎馿喫撲。", "驀地拓開北鬰單越，海湧波騰。", "淮山兩踞，撥火求冰。", "問渠西祖之道，何曾□□□□。"]'),
('62d9ec96-2943-4100-9250-ef628f7acb90','禪人寫師真請讚  其二三','釋慧遠','宋','宋诗','song-poetry','','[]','幸自十分，畫出一半。',98,'全唐诗/poet.song.113000.json','["幸自十分，畫出一半。", "我便是渠，略無思算。", "無思算處妙難傳，忿怒那吒喫痛拳。", "道不是道，禪不是禪。", "星馳電掣，漢語胡言。", "驀地揭起腦蓋，依前舌拄梵天。", "咄，是甚麽面目。", "可憐只有些兒栗棘金圈，盡底分付常山林泉。"]'),
('f76c10d2-0e4a-4c07-ba09-1ef135a35971','禪人寫師真請讚  其二四','釋慧遠','宋','宋诗','song-poetry','','[]','倒數一二三，翻成四五六。',48,'全唐诗/poet.song.113000.json','["倒數一二三，翻成四五六。", "蹋斷獨木橋，唱起雲門曲。", "急似箭，直如弦。", "列祖不知何處去，瞎馿依舊痛加鞭。"]'),
('737684d0-e8dd-44d3-9558-22326bcfe476','禪人寫師真請讚  其二五','釋慧遠','宋','宋诗','song-poetry','','[]','住飛來峯，飲冷泉水。',54,'全唐诗/poet.song.113000.json','["住飛來峯，飲冷泉水。", "倒用逆施，拈頭作尾。", "十字街頭擊鼓，五天印土喫茶。", "南北東西若稻麻。", "钁頭些子意，驗盡當行家。"]'),
('381e8a3b-1a40-4942-8ff2-92e80ba55b18','禪人寫師真請讚  其二六','釋慧遠','宋','宋诗','song-poetry','','[]','普證作此像，是相故非真。',66,'全唐诗/poet.song.113000.json','["普證作此像，是相故非真。", "虛空無背面，露柱倒生根。", "傍提正按低叉手，獨掇單提高打躬。", "佛魔削跡，凡聖泯蹤。", "雨過雲山空漠漠，日高花影亂重重。"]'),
('de50da16-0cf7-40bd-8a09-a1cf4d85c1b2','禪人寫師真請讚  其二七','釋慧遠','宋','宋诗','song-poetry','','[]','道出古今，法超聞見。',52,'全唐诗/poet.song.113000.json','["道出古今，法超聞見。", "雨驟雲馳，星移斗轉。", "夢魂歷盡百城餘，覺後端知一物無。", "打鼓看來君不見，拈花笑殺老臊胡。"]'),
('0d8f8bb0-3e21-493b-8f25-0037b9b3ba75','禪人寫師真請讚  其二八','釋慧遠','宋','宋诗','song-poetry','','[]','師子哮吼，象王回旋。',68,'全唐诗/poet.song.113000.json','["師子哮吼，象王回旋。", "左顧右盻，七穴八穿。", "平地和聲便拶，等閑㪍跳上天。", "築著梵王香案，然後退身歸本位，叉手而立。", "自云法徽伏候台旨，未敢自專。"]'),
('cb395038-d72e-4e76-8943-964c3c55c572','禪人寫師真請讚  其二九','釋慧遠','宋','宋诗','song-poetry','','[]','入魔王隊，住邪見林。',36,'全唐诗/poet.song.113000.json','["入魔王隊，住邪見林。", "修菩薩行，現夜叉心。", "舌頭拖地有誰識，鼻孔遼天無處尋。"]'),
('c1d1d9e1-25f3-4bfb-bf02-6f0ec75808fe','禪人寫師真請讚  其三○','釋慧遠','宋','宋诗','song-poetry','','[]','大道廓然，真空泯跡。',48,'全唐诗/poet.song.113000.json','["大道廓然，真空泯跡。", "金裏淘砂，玉中辨石。", "衲僧用處脫羅籠，熨斗煎茶銚不同。", "一聲師子吼，遍界絕狐蹤。"]'),
('11ada573-4e8f-4444-87f8-aba06e78db9c','禪人寫師真請讚  其三一','釋慧遠','宋','宋诗','song-poetry','','[]','到處說禪說道，爲人入水入泥。',55,'全唐诗/poet.song.113000.json','["到處說禪說道，爲人入水入泥。", "半生出來住院，一□斷送頭皮。", "讚也得，毀也得，臨濟便是白拈賊。", "賊賊，也只當甚乾羅蔔。"]'),
('81fb1410-773e-4d03-8a3c-2432c9422151','偈','釋慧遠','宋','宋诗','song-poetry','','[]','至道無難，唯嫌揀擇。',30,'全唐诗/poet.song.113000.json','["至道無難，唯嫌揀擇。", "但莫憎愛，洞然明白。", "毫釐有差，天地懸隔。"]'),
('03d9da40-a448-4640-89fb-9e3771605039','偈八首  其一','釋慧遠','宋','宋诗','song-poetry','','[]','道絕名言，法離聞見。',34,'全唐诗/poet.song.113000.json','["道絕名言，法離聞見。", "打破虛空，成七八片。", "直饒錮鏴完全，也是由基副箭。"]'),
('ccc605ef-41cd-4468-a400-af9475141aa6','偈八首  其二','釋慧遠','宋','宋诗','song-poetry','','[]','昨夜來報五參，正值老僧洗脚。',28,'全唐诗/poet.song.113000.json','["昨夜來報五參，正值老僧洗脚。", "起來抖擻精神，末上輸他一著。"]'),
('94055747-7ff3-49bc-a177-3c39b6b4c7c5','偈八首  其三','釋慧遠','宋','宋诗','song-poetry','','[]','天道虧盈，地道變盈。',20,'全唐诗/poet.song.113000.json','["天道虧盈，地道變盈。", "鬼神害盈，人道惡盈。"]'),
('d3229624-11d8-4a5f-94be-ca739c94f460','偈八首  其四','釋慧遠','宋','宋诗','song-poetry','','[]','自小出家，橫草不拈，豎草不把。',31,'全唐诗/poet.song.113000.json','["自小出家，橫草不拈，豎草不把。", "路轉山回君自看，南不龜頭北不厦。"]'),
('a5ea797b-e5fd-4bb7-b7e7-20f04f9c8122','偈八首  其五','釋慧遠','宋','宋诗','song-poetry','','[]','滴水冰生分外寒，凍雲環合鎖峰巒。',32,'全唐诗/poet.song.113000.json','["滴水冰生分外寒，凍雲環合鎖峰巒。", "根塵不昧心珠露，眨上眉毛子細看。"]'),
('8923b637-9502-4733-ad51-317380334678','偈八首  其六','釋慧遠','宋','宋诗','song-poetry','','[]','好是仲春漸暖，那堪寒食清明。',64,'全唐诗/poet.song.113000.json','["好是仲春漸暖，那堪寒食清明。", "萬疊雲山聳翠，一天風月爲鄰。", "在處華紅柳綠，湖天浪穩風平。", "山禽枝上語諄諄，再三瑣瑣碎碎，囑付叮叮嚀嚀。"]'),
('df67ff17-5186-4ad2-98bb-d252634a151a','偈八首  其七','釋慧遠','宋','宋诗','song-poetry','','[]','閙處莫出頭，冷地著眼看。',72,'全唐诗/poet.song.113000.json','["閙處莫出頭，冷地著眼看。", "明暗不相干，彼此分一半。", "一種作貴人，教誰賣柴炭。", "向你道，不可毀，不可讚，體若虛空沒涯岸。", "相喚相呼歸去來，記取明年正月半。"]'),
('7c3d23f9-df9c-43fb-b46c-af4cd61788c7','偈八首  其八','釋慧遠','宋','宋诗','song-poetry','','[]','拗折秤鎚，掀翻露布。',20,'全唐诗/poet.song.113000.json','["拗折秤鎚，掀翻露布。", "突出機先，鴉飛不度。"]'),
('0b2bbbeb-a768-4b87-9e26-69767109437c','頌古','釋慧遠','宋','宋诗','song-poetry','','[]','靜鞭聲裏駕頭來，緊握雙拳打不開。',36,'全唐诗/poet.song.113000.json','["靜鞭聲裏駕頭來，緊握雙拳打不開。", "打得開，雲壓香塵何處是，靜鞭聲裏駕頭來。"]'),
('72baa846-cdb8-4440-858d-bd927b62fc2b','頌古十五首  其一','釋慧遠','宋','宋诗','song-poetry','','[]','老胡一擊許誰知，大冶紅爐片雪飛。',32,'全唐诗/poet.song.113000.json','["老胡一擊許誰知，大冶紅爐片雪飛。", "青草塚間留不住，白雲還望故山歸。"]'),
('8328d10e-b5d1-4f62-a905-37256efca0e4','頌古十五首  其二','釋慧遠','宋','宋诗','song-poetry','','[]','接著一箇半箇，覓得三文兩文。',28,'全唐诗/poet.song.113000.json','["接著一箇半箇，覓得三文兩文。", "誰知破布袋裏，許多彌勒世尊。"]'),
('d4643a6b-4807-409a-b092-df6934a4105c','頌古十五首  其三','釋慧遠','宋','宋诗','song-poetry','','[]','良哉觀世音，旋聞與聲脫。',28,'全唐诗/poet.song.113000.json','["良哉觀世音，旋聞與聲脫。", "犬吠馿鳴休未休，世出世間活鱍鱍。"]'),
('fbcc5f65-4c74-40a0-a3c4-5fe854412d58','頌古十五首  其四','釋慧遠','宋','宋诗','song-poetry','','[]','見處孤危立處高，急如石火利如刀。',32,'全唐诗/poet.song.113000.json','["見處孤危立處高，急如石火利如刀。", "到家問路家何在，掀倒棋盤脫布袍。"]'),
('5cb2031d-bd6d-4e15-a50e-1abc401a252d','頌古十五首  其五','釋慧遠','宋','宋诗','song-poetry','','[]','電捲星飛，珠回玉轉。',20,'全唐诗/poet.song.113000.json','["電捲星飛，珠回玉轉。", "打破面皮，赤心片片。"]'),
('8f986878-c821-4102-a56e-3ad35343f40b','頌古十五首  其六','釋慧遠','宋','宋诗','song-poetry','','[]','三喚三應，更饒貼稱。',30,'全唐诗/poet.song.113000.json','["三喚三應，更饒貼稱。", "月逗寒窗，水歸巨浸。", "負汝負吾，全鋒敵勝。"]'),
('8bc301c0-8880-4416-a623-74257e1bd4a9','頌古十五首  其七','釋慧遠','宋','宋诗','song-poetry','','[]','起模畫樣弄精魂，拂跡除蹤更見人。',32,'全唐诗/poet.song.113000.json','["起模畫樣弄精魂，拂跡除蹤更見人。", "行到水窮山盡處，滿天雲散月華明。"]'),
('8d4e9675-e554-464d-b7fe-b1def7afedbc','頌古十五首  其八','釋慧遠','宋','宋诗','song-poetry','','[]','行行月冷風高，步步山寒水深。',28,'全唐诗/poet.song.113000.json','["行行月冷風高，步步山寒水深。", "逢人披肝露膽，見義劈腹剜心。"]'),
('80e781fe-19cf-425a-8baf-5b5cddccfc04','頌古十五首  其九','釋慧遠','宋','宋诗','song-poetry','','[]','你愛我笊籬，我愛你木杓。',52,'全唐诗/poet.song.113000.json','["你愛我笊籬，我愛你木杓。", "主山纔放高，案山又岌嶪。", "居士大同師，將錯便就錯。", "歸去來兮天地寬，一對鐵槌何處著。"]'),
('7a670ad5-8871-49a9-b3a3-fa4e12cd17f4','頌古十五首  其一○','釋慧遠','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','佛性分明脫有無，醋酸何用挂葫蘆。',32,'全唐诗/poet.song.113000.json','["佛性分明脫有無，醋酸何用挂葫蘆。", "薄霧輕烟留不住，扁舟已過洞庭湖。"]'),
('6f8f37a1-934e-45d8-b017-989f837004ef','頌古十五首  其一一','釋慧遠','宋','宋诗','song-poetry','','[]','換手搥胸哭老爺，棺材未出死屍斜。',32,'全唐诗/poet.song.113000.json','["換手搥胸哭老爺，棺材未出死屍斜。", "不如掘地深埋却，管取來年喫嫩茄。"]'),
('7a561279-87fb-44d2-890f-6c4214086c61','頌古十五首  其一二','釋慧遠','宋','宋诗','song-poetry','','[]','南北東西老趙州，見人騎馬也騎牛。',32,'全唐诗/poet.song.113000.json','["南北東西老趙州，見人騎馬也騎牛。", "清風月下尋歸路，夫子門前問孔丘。"]'),
('3cd5076f-e7ad-4442-a3a5-3fed471c54bd','頌古十五首  其一三','釋慧遠','宋','宋诗','song-poetry','','[]','明暗雙雙照用分，幾人親到孟嘗門。',32,'全唐诗/poet.song.113000.json','["明暗雙雙照用分，幾人親到孟嘗門。", "街頭不識真彌勒，却向靈山問世尊。"]'),
('cb4538c0-6ffc-47ba-9ac8-3c8e6a1d1f46','頌古十五首  其一四','釋慧遠','宋','宋诗','song-poetry','','[]','山花如錦水如藍，親見文殊接話談。',32,'全唐诗/poet.song.113000.json','["山花如錦水如藍，親見文殊接話談。", "十字街頭輕一拶，前三三對後三三。"]'),
('31ca3196-c782-432e-ace0-2430688fc1c5','頌古十五首  其一五','釋慧遠','宋','宋诗','song-poetry','','[]','盡力當胸一拳，幾箇眉鬚墮落。',28,'全唐诗/poet.song.113000.json','["盡力當胸一拳，幾箇眉鬚墮落。", "更欲如何若何，普化空中木鐸。"]'),
('f6ba666d-120a-4687-a3bd-c34ecbd3f418','贈栖禪上人','釋與咸','宋','宋诗','song-poetry','','[]','巖房高且靜，住此幾寒暄。',48,'全唐诗/poet.song.113000.json','["巖房高且靜，住此幾寒暄。", "鹿嗅安禪石，猿啼乞食村。", "朝陽生樹罅，古路透雲根。", "獨步閒相覓，淒涼碧洞門。"]'),
('c1794d40-64a7-47b6-9471-1ba952099edc','句','釋與咸','宋','宋诗','song-poetry','','[]','金谷人亡後，沙場日暖時。',12,'全唐诗/poet.song.113000.json','["金谷人亡後，沙場日暖時。"]'),
('10a48ff2-1ec1-45c5-8437-3556d33a7ad1','灘石八陣圖行','王剛中','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','我生孔明後，相望九百載。',384,'全唐诗/poet.song.113000.json','["我生孔明後，相望九百載。", "我想孔明賢，巍然伊呂配。", "奇謀勇略誇雄師，大節英風蓋當代。", "木牛流馬何足言，八陣遺蹤千古在。", "我行已度瞿唐門，長灘石壘差參分。", "洪纖高下尺寸等，猶有當年節制存。", "四頭八尾觸處首，敵衝中央兩皆救。", "握奇如樞運無窮，七縱七擒仍敢攻。", "規模黄帝已垂文，後來得者惟將軍。", "唐宗李靖拾遺意，樂舞旛表徒繽紛。", "長江之上石蟠結，江波洶湧石不滅。", "使君何事遽剗除，一夜風雷吼天闕。", "明朝仍舊石縱橫，神物護持人已驚。", "向來守蜀用此法，誰知石壘真金城。", "嗟乎孔明遇不遇，遇則劉公恢大度。", "國險地狹民力微，法出萬全勢未具。", "嗟乎孔明以此用於吳，長江內固魏可圖。", "嗟乎孔明以此用於魏，掃平三分歸一篲。", "祇應所遇勢不同，勢既不同功亦異。", "嗟乎孔明之心如石堅，欲扶漢室還中原。", "事之不就則天耳，安肯俯首從曹袁。", "嗟乎孔明如生石不老，後世用兵無草草。", "忽然變作六花看，便失本真難按考。", "請觀疊石韜機籌，江流東去自悠悠。"]'),
('9bb0e239-80c4-465d-b6aa-e8606f970fe0','彌牟鎮孔明八陣圖','王剛中','宋','宋诗','song-poetry','','[]','我稽八陣圖，規模載方冊。',120,'全唐诗/poet.song.113000.json','["我稽八陣圖，規模載方冊。", "朅來鎮西蜀，夔門觀疊石。", "賦詩有數字，字字究來歷。", "進涉漢州西，彌牟鎮之北。", "平原列堆阜，灘石同一式。", "細思作者意，孔明有深策。", "高岸或爲谷，灘石存遺跡。", "江海變桑田，平原猶可覓。", "故今兩處存，千載必一得。", "再歌遂成篇，當有智者識。"]'),
('0661efb3-f4f5-43fb-8744-48ac4a4d4e05','應雪木','王之淵','宋','宋诗','song-poetry','','[]','木名應雪匪辭誇，比似靈蓍總不差。',32,'全唐诗/poet.song.113000.json','["木名應雪匪辭誇，比似靈蓍總不差。", "從昔到今凡幾驗，一番飛雪一番花。"]'),
('07420bc1-2f1e-4148-a514-77606f9fd6ad','經湘東','侍其備','宋','宋诗','song-poetry','','[]','迢迢萍水向西流，地接長沙一片秋。',32,'全唐诗/poet.song.113000.json','["迢迢萍水向西流，地接長沙一片秋。", "不逐征鴻過湘浦，行程應記到南州。"]'),
('1635cd9d-6619-4baa-808d-47ba646fb5ae','自贊','李迎','宋','宋诗','song-poetry','','[]','三仕三已，應緣而進。',20,'全唐诗/poet.song.113000.json','["三仕三已，應緣而進。", "一丘一壑，倦遊而歸。"]'),
('87542eb9-75b0-4a80-87f2-17b066d61a69','句','李迎','宋','宋诗','song-poetry','','[]','籍甚人言易已東。',8,'全唐诗/poet.song.113000.json','["籍甚人言易已東。"]'),
('b8ad47f2-71dc-4b3d-bc3f-b7b0d1f417b2','丁角暮春','聞人武子','宋','宋诗','song-poetry','','[]','綠葉成陰春已歸，茅檐相對兩斜暉。',64,'全唐诗/poet.song.113000.json','["綠葉成陰春已歸，茅檐相對兩斜暉。", "殘花且插春事急，別酒欲酌歌聲微。", "黄鳥匆匆隔林語，楊花款款沾人衣。", "人間一別春常好，過我漁舟果是非。"]'),
('878ec0b1-590c-4443-ac20-84e15a8a83fc','墨梅','聞人武子','宋','宋诗','song-poetry','','[]','隴首人歸信息稀，愁看冰楮破寒枝。',32,'全唐诗/poet.song.113000.json','["隴首人歸信息稀，愁看冰楮破寒枝。", "瑶姬駐立緣何事，直到霜飛月墮時。"]'),
('665b67e5-73b7-4cde-84e3-4822fc743a01','句','聞人武子','宋','宋诗','song-poetry','','[]','蹤跡共徘徊。',6,'全唐诗/poet.song.113000.json','["蹤跡共徘徊。"]'),
('b6c77a1d-09c8-42c0-bdb1-4a35172bac07','呈德厚宮主先生','王伯淮','宋','宋诗','song-poetry','','[]','九鎖松門夜不關，蓬萊分境到塵寰。',64,'全唐诗/poet.song.113000.json','["九鎖松門夜不關，蓬萊分境到塵寰。", "仙風鶴駕來天表，白晝雲旗下世間。", "古洞得泉消俗病，名山有藥駐童顔。", "何當常對先生面，願借飛鳬日往還。"]'),
('932d0056-ca8d-4ded-92b2-e3a5df268bc1','題十詠堂','趙善宣','宋','宋诗','song-poetry','','[]','十詠名堂歲月深，我來訪古闢荆榛。',64,'全唐诗/poet.song.113000.json','["十詠名堂歲月深，我來訪古闢荆榛。", "依村結屋臨山址，種柳尋花傍水濱。", "珠玉舊傳清唱在，滄浪初棹綠波新。", "此心樂與邦人共，要使渾如郡北春。"]'),
('7311a3f6-b3b2-4ed8-9eb2-20c291e9eab9','東林院','何麟','宋','宋诗','song-poetry','','[]','此地非廬岳，東林邂逅過。',24,'全唐诗/poet.song.113000.json','["此地非廬岳，東林邂逅過。", "我羞陶靖節，僧異遠頭陀。"]'),
('e7b60752-935c-4e58-8492-391d469db698','外大父丞相初登科爲雒縣主簿經攝𡊚窯鎮稅官留詩護國寺中令狐監征錄以見寄謹再拜追和而記其後','何麟','宋','宋诗','song-poetry','','[]','傳翁遺墨剩咨嗟，四海當年尚一家。',64,'全唐诗/poet.song.113000.json','["傳翁遺墨剩咨嗟，四海當年尚一家。", "大老不爲今日用，小詩徒遣後人誇。", "興來思跨巴滇馬，歸去方乘下澤車。", "燕麥兔葵僧舍裏，何如夢得訪桃花。"]'),
('6f2f9347-b90f-4b4e-9744-e63c91ba3539','生公講堂','何麟','宋','宋诗','song-poetry','','[]','平地湧巖壑，稜層驚大雄。',48,'全唐诗/poet.song.113000.json','["平地湧巖壑，稜層驚大雄。", "何曾遠人世，直欲傍天宮。", "白虎威靈在，赤烏緣影空。", "生公能說法，音與塔鈴同。"]'),
('78b60812-fef2-4f85-a9ed-07b9bf957653','句  其一','何麟','宋','宋诗','song-poetry','','[]','明朝一棹夷陵過，始覺吳天楚地寬。',16,'全唐诗/poet.song.113000.json','["明朝一棹夷陵過，始覺吳天楚地寬。"]'),
('358eb1a6-008c-452b-b93a-da23a117a199','句  其二','何麟','宋','宋诗','song-poetry','','[]','但見岑樓名楚塞，不知元是國西門。',16,'全唐诗/poet.song.113000.json','["但見岑樓名楚塞，不知元是國西門。"]'),
('27c05b6e-9a1f-45c3-8c2f-c544fba956da','句  其三','何麟','宋','宋诗','song-poetry','','[]','一楠枯再生，兩石合無罅。',12,'全唐诗/poet.song.113000.json','["一楠枯再生，兩石合無罅。"]'),
('2fc65fa2-d237-49c3-883d-02a5cafa051a','句  其四','何麟','宋','宋诗','song-poetry','','[]','梁山韮黄妙天下，玉筯金釵盈大把。',16,'全唐诗/poet.song.113000.json','["梁山韮黄妙天下，玉筯金釵盈大把。"]'),
('98aa8e2f-17f1-4432-8d86-ed75fb4f4321','朱槿花','張登','宋','宋诗','song-poetry','','[]','甲子雖推小雪天，刺桐猶綠槿花然。',32,'全唐诗/poet.song.113000.json','["甲子雖推小雪天，刺桐猶綠槿花然。", "陽和長養無時歇，却是炎州雨露偏。"]'),
('a13cd56c-139a-4587-b9d8-76de8e8b7044','洞石巖','張登','宋','宋诗','song-poetry','','[]','山斷開元蝎，龕留大業僧。',24,'全唐诗/poet.song.113000.json','["山斷開元蝎，龕留大業僧。", "七年馳便路，三躡石梯層。"]'),
('f1f22514-2c82-46f8-b1ed-ac4ccd5aa031','留題熙春亭','張登','宋','宋诗','song-poetry','','[]','熙春亭建爲民安，要識熙熙本不難。',64,'全唐诗/poet.song.113000.json','["熙春亭建爲民安，要識熙熙本不難。", "一日但能先克復，百年雖久亦勝殘。", "滿城和氣薰天地，終歲長春忘暑寒。", "斯道古今無異路，獨題待與後賢看。"]'),
('4940427d-06f8-48ed-bcb4-df24f116daba','句','張登','宋','宋诗','song-poetry','','[]','孤高齊帝右，瀟灑晉亭峯。',12,'全唐诗/poet.song.113000.json','["孤高齊帝右，瀟灑晉亭峯。"]'),
('c9f8af60-b242-40d2-9525-85bb666d6b3f','泊吳江寄僧','孫大雅','宋','宋诗','song-poetry','','["\u592a\u6e56"]','松陵橋畔太湖前，斜日青楓繫客船。',64,'全唐诗/poet.song.113000.json','["松陵橋畔太湖前，斜日青楓繫客船。", "引頸數看花鴨亂，含情深愧白鷗賢。", "千鐙庾嶺傳無盡，一宿曹溪覺有緣。", "稍待月明風細細，卧吹簫管學坡仙。"]'),
('b6253d1d-d0af-4a13-869f-cdf86fd8e281','侍家君詣洞霄宮道出天竺山紀興','李茂之','宋','宋诗','song-poetry','','[]','九里松陰路，三天竺國山。',48,'全唐诗/poet.song.113000.json','["九里松陰路，三天竺國山。", "日蒸巖霧紫，花點石苔斑。", "谿盡寺方到，雲深僧獨還。", "吟行隨杖履，蹤迹出人間。"]'),
('8c425173-9164-4b1e-8d34-85ee00319259','詠石僧','湯思退','宋','宋诗','song-poetry','','[]','雲作袈裟石作僧，巖前獨立幾經春。',32,'全唐诗/poet.song.113000.json','["雲作袈裟石作僧，巖前獨立幾經春。", "有人若問西來意，默默無言總是真。"]'),
('6bdd6121-7e88-4d15-9828-f1ab4a7ae61f','句','湯思退','宋','宋诗','song-poetry','','[]','虞妃從梧野，啟母祔稽山。',12,'全唐诗/poet.song.113000.json','["虞妃從梧野，啟母祔稽山。"]'),
('2299f2b1-8ccd-4edc-9d2f-292368bbbfdc','殊聖寺和孟我幕韵','吳詠','宋','宋诗','song-poetry','','[]','院靜僧疑少，門幽客自稀。',48,'全唐诗/poet.song.113000.json','["院靜僧疑少，門幽客自稀。", "山寒雲近屋，徑狹石侵衣。", "松鬣蒼髯古，薑芽紫笋肥。", "騷人詩戰罷，踏月夜深歸。"]'),
('7c01c99f-9088-432c-895f-e26690c2d1ea','題大興院','孟大武','宋','宋诗','song-poetry','','[]','松柏回環路屈盤，像堂僧室枕層巒。',64,'全唐诗/poet.song.113000.json','["松柏回環路屈盤，像堂僧室枕層巒。", "泉多翠茗臨烹便，寺僻紅塵欲到難。", "樵斧斫雲春谷暗，漁榔敲月夜溪寒。", "我來未足登高興，欲去裴回更倚闌。"]'),
('15ab7979-63a8-4158-b6fa-8eb047e0247e','題萬安院','孟大武','宋','宋诗','song-poetry','','[]','十年不作此山來，依舊青山好在哉。',64,'全唐诗/poet.song.113000.json','["十年不作此山來，依舊青山好在哉。", "聊逐春風驅酒病，却驚身世得愁媒。", "禪床寄枕眠初熟，山鬼嫌人夢却回。", "明日拂衣還出去，桃花地上欲成堆。"]'),
('9b00bf1f-6bab-4775-926f-56a33c440191','題紫巖寺','孟大武','宋','宋诗','song-poetry','','[]','路入溪聲遠，秋深樹影稀。',48,'全唐诗/poet.song.113000.json','["路入溪聲遠，秋深樹影稀。", "澗雲藏鳥語，松露滴人衣。", "詩戰蜂腰怯，茶分粥面肥。", "勝遊殊未厭，肯爲夜寒歸。"]'),
('08be2a05-e37d-4b2f-b087-650443e0a5e5','春日晚望','孟大武','宋','宋诗','song-poetry','','[]','屋角風微烟霧霏，柳絲無力杏花肥。',32,'全唐诗/poet.song.113000.json','["屋角風微烟霧霏，柳絲無力杏花肥。", "朦朧數點斜陽裏，應是呢喃燕子歸。"]'),
('af12f9c1-4a78-4b80-857f-101b9c489d90','句  其一','孟大武','宋','宋诗','song-poetry','','[]','綵仞氣浮三塔聳，浮牌聲振兩溪寒。',16,'全唐诗/poet.song.113000.json','["綵仞氣浮三塔聳，浮牌聲振兩溪寒。"]'),
('df690363-beb4-4037-b02e-23c581c0f0aa','句  其二','孟大武','宋','宋诗','song-poetry','','[]','掃地石盆冷，閉門春晝長。',12,'全唐诗/poet.song.113000.json','["掃地石盆冷，閉門春晝長。"]'),
('0ac87e53-9b37-4d63-937e-6ab0c3cd4a8b','書事十絕  其一','曾惇','宋','宋诗','song-poetry','','[]','黄泥坂下雪猶深，赤壁磯頭江欲平。',32,'全唐诗/poet.song.113000.json','["黄泥坂下雪猶深，赤壁磯頭江欲平。", "驛吏西來聞好語，蕃人已出蔡州城。"]'),
('7b9348b2-f72b-4c2e-b462-3cbb26529270','書事十絕  其二','曾惇','宋','宋诗','song-poetry','','[]','和戎詔下破羣疑，無復旄頭彗紫微。',32,'全唐诗/poet.song.113000.json','["和戎詔下破羣疑，無復旄頭彗紫微。", "屈己銷兵宜有報，先看長樂版輿歸。"]'),
('d120fd02-988b-4fdc-bb24-edd88c844d16','書事十絕  其三','曾惇','宋','宋诗','song-poetry','','[]','吾君見事若通神，兵柄收還號令新。',32,'全唐诗/poet.song.113000.json','["吾君見事若通神，兵柄收還號令新。", "裴度只今真聖相，勒碑十丈可無人。"]'),
('770903eb-3bb5-425b-b8b5-cea6b696c347','書事十絕  其四','曾惇','宋','宋诗','song-poetry','','[]','淮上州州盡滅烽，今年方喜得和戎。',32,'全唐诗/poet.song.113000.json','["淮上州州盡滅烽，今年方喜得和戎。", "問誰整頓乾坤了，學語兒童道相公。"]'),
('01ee8449-4ee4-4f7a-902a-ae348fc81d6a','書事十絕  其五','曾惇','宋','宋诗','song-poetry','','[]','連營貔虎氣如雲，聽詔人人願立勳。',32,'全唐诗/poet.song.113000.json','["連營貔虎氣如雲，聽詔人人願立勳。", "沔鄂蘄黄一千里，更無人說岳家軍。"]'),
('3aae94cf-b90b-4efc-846c-823230954322','書事十絕  其六','曾惇','宋','宋诗','song-poetry','','[]','田父今年作社頻，邊頭聞見一番新。',32,'全唐诗/poet.song.113000.json','["田父今年作社頻，邊頭聞見一番新。", "官軍不斫人家樹，各自持錢去買薪。"]'),
('32c8f978-7201-4b6b-b68b-858cb69cae14','書事十絕  其七','曾惇','宋','宋诗','song-poetry','','[]','江頭柳木已參天，柳色花光日日妍。',32,'全唐诗/poet.song.113000.json','["江頭柳木已參天，柳色花光日日妍。", "驚怪田家頻得醉，今年斗米不論錢。"]'),
('0fecba02-7bb6-425f-a7f5-def2e7467ef6','書事十絕  其八','曾惇','宋','宋诗','song-poetry','','[]','村村準擬十分禾，老稚扶携笑且歌。',32,'全唐诗/poet.song.113000.json','["村村準擬十分禾，老稚扶携笑且歌。", "租稅况今黄紙放，陽城元自拙催科。"]'),
('a5bd1094-d4ff-49fe-8419-887bef8542e4','書事十絕  其九','曾惇','宋','宋诗','song-poetry','','[]','淮畔風塵自此清，斯人還喜見昇平。',32,'全唐诗/poet.song.113000.json','["淮畔風塵自此清，斯人還喜見昇平。", "田家盡說今年好，要雨雨來晴便晴。"]'),
('cbbd7047-975d-4f57-9bc0-5bc61e377a39','書事十絕  其一○','曾惇','宋','宋诗','song-poetry','','[]','百丈岢峨賈客船，張帆打鼓下長川。',32,'全唐诗/poet.song.113000.json','["百丈岢峨賈客船，張帆打鼓下長川。", "路人指點幾垂淚，江道無來十六年。"]'),
('efad3cbb-e7a9-4cb0-b583-3272c6343670','棲霞會飲諸僚','曾惇','宋','宋诗','song-poetry','','[]','月近中秋好，風因小雨清。',48,'全唐诗/poet.song.113000.json','["月近中秋好，風因小雨清。", "山眉煙外遠，江練夜深橫。", "我病自不飲，君詩俱有聲。", "放歌能取醉，不必喚嘉榮。"]'),
('d7d6e5a6-2dab-48db-8db3-c14bbf525b12','棲霞偶作','曾惇','宋','宋诗','song-poetry','','[]','蔬飯已忘肉，清心已是僧。',48,'全唐诗/poet.song.113000.json','["蔬飯已忘肉，清心已是僧。", "春華空婉娩，衰病苦侵凌。", "風颺孤舟急，江明遠浦澄。", "邵樓來遠念，實怯醉時登。"]'),
('c59f94ca-da0d-49fe-90ec-dd17ec5f35c7','和何麒子應雪堂','曾惇','宋','宋诗','song-poetry','','[]','坐想誅茅日，山川走百靈。',48,'全唐诗/poet.song.113000.json','["坐想誅茅日，山川走百靈。", "重來尋舊宅，幾至泣新亭。", "何意投天祿，猶傳是歲星。", "花磚知底物，只老合沉溟。"]'),
('8d92684f-39a3-467e-9a70-25f8960ec664','次謝景思韵','曾惇','宋','宋诗','song-poetry','','[]','埋沒雙巖已百年，班班勝事漫流傳。',64,'全唐诗/poet.song.113000.json','["埋沒雙巖已百年，班班勝事漫流傳。", "幸陪佳客揮犀麈，實欠傾城舞繡筵。", "故老風流寒似鐵，月卿英妙筆如椽。", "拂衣便欲故山去，復恐眼中無此賢。"]'),
('7dcd828b-c8a3-44f6-a2db-4457a7891e70','東湖懷洪景伯','曾惇','宋','宋诗','song-poetry','','[]','東湖徑昃半蒼苔，問訊紅蕖幾許開。',64,'全唐诗/poet.song.113000.json','["東湖徑昃半蒼苔，問訊紅蕖幾許開。", "渺渺波光侵坐席，霏霏荷氣著尊罍。", "片雲正爲詩情起，好雨更將凉意來。", "別乘朝來知健否，頗思劇飲拗蓮臺。"]'),
('244a65c5-0c09-42ef-ae52-7e8118ab74ac','和謝景思','曾惇','宋','宋诗','song-poetry','','[]','康樂東山迹已陳，續衣傳鉢不無人。',64,'全唐诗/poet.song.113000.json','["康樂東山迹已陳，續衣傳鉢不無人。", "往時絳闕清都上，幾歲荒山野水濱。", "紅藥高吟須小謝，白蓮勝社得遺民。", "不嫌小邑來車轍，同試龍園第一春。"]'),
('4c6ffe96-edd7-4e26-a1b8-7817f5ebbe0f','次洪景伯韵  其一','曾惇','宋','宋诗','song-poetry','','[]','午夜崩騰玉馬飛，春前臘後未爲遲。',64,'全唐诗/poet.song.113000.json','["午夜崩騰玉馬飛，春前臘後未爲遲。", "正憐灞上詩無繼，似與山陰客有期。", "摇蕩江花迷遠渚，埋藏海嶠失多歧。", "誰能作句催端水，清絕台州別駕詩。"]'),
('985cd878-4f6a-4a8b-85db-c20e20e076c4','次洪景伯韵  其二','曾惇','宋','宋诗','song-poetry','','[]','半刺風流雅好賢，幽尋同舉蔡經鞭。',64,'全唐诗/poet.song.113000.json','["半刺風流雅好賢，幽尋同舉蔡經鞭。", "江梅滿樹爲誰好，官柳著行還自妍。", "筆陣如君難索敵，詩鋒顧我敢爭先。", "一春剩喚忘憂子，要看長鯨吸百川。"]'),
('97d13692-fa1a-4036-b1c2-f100ef1058ac','次洪景伯韵  其三','曾惇','宋','宋诗','song-poetry','','[]','新詩清如玉壺冰，一讀爲破旅愁凝。',64,'全唐诗/poet.song.113000.json','["新詩清如玉壺冰，一讀爲破旅愁凝。", "正懷狂客賀祕監，忽見高人王右丞。", "坐忘仙去境尚在，廣文骨冷呼不應。", "其誰洗滌懷古恨，別乘博物如何曾。"]'),
('f6a65f48-76ba-4a44-aa4a-0a149b16e596','題一相菴','曾惇','宋','宋诗','song-poetry','','[]','滿山松竹翠成林，彷彿前身舊所臨。',32,'全唐诗/poet.song.113000.json','["滿山松竹翠成林，彷彿前身舊所臨。", "不分雙旌殺風景，他年蠟屐再幽尋。"]'),
('b8e67092-055f-44a6-85c3-0e1aefe5a40f','後園觀梅簡洪景伯','曾惇','宋','宋诗','song-poetry','','[]','扶藜點檢後園梅，小雨霑滋第一回。',64,'全唐诗/poet.song.113000.json','["扶藜點檢後園梅，小雨霑滋第一回。", "賓客正愁花有語，拾遺只恐老相催。", "關心故國賞心處，愛酒暮年疏酒杯。", "待得山宮千樹白，與君騎馬入青苔。"]'),
('4da77243-0501-4e44-8fef-62efc6b2ec1b','分繡閣','曾惇','宋','宋诗','song-poetry','','[]','治中妙言語，洪濤瀉詞源。',96,'全唐诗/poet.song.113000.json','["治中妙言語，洪濤瀉詞源。", "向來羣玉府，垂上紫微垣。", "佐郡滄海傍，憑軒望朝暾。", "便欲乘輕車，長嘯登崑崙。", "茲樓何縹緲，千巖靄雲屯。", "空庭百吏散，博山炷微薰。", "重尋羨門輩，仙事渺無垠。", "何知對妙高，舉手招德雲。"]'),
('a7cbb8b8-7f11-4c9e-bb5a-0744f89f05fb','清閟堂','曾惇','宋','宋诗','song-poetry','','[]','洪郎雅吳語，不減賀季真。',96,'全唐诗/poet.song.113000.json','["洪郎雅吳語，不減賀季真。", "開軒風煙上，爽氣朝朝新。", "手栽渭川竹，坐對北海尊。", "平生耐久朋，歲晚獨此君。", "此君不可疏，亦復未易親。", "紛紛桃李行，豈容託清塵。", "退食靜隠几，微風冷衣巾。", "乃知王子猷，真是我輩人。"]'),
('57999de5-f2bc-46c4-8d96-eb72580c7944','題東湖','曾惇','宋','宋诗','song-poetry','','[]','三年領客醉東湖，欲去猶携竹裏厨。',32,'全唐诗/poet.song.113000.json','["三年領客醉東湖，欲去猶携竹裏厨。", "誰解挽留狂太守，風荷十頃翠相扶。"]'),
('5ac591c0-7315-4cfe-addb-58aeddfeac03','次韵朱知裁少卿見貽二首  其一','曾惇','宋','宋诗','song-poetry','','[]','丹丘山水窟，中有如斗城。',108,'全唐诗/poet.song.113000.json','["丹丘山水窟，中有如斗城。", "地迥鳥不喧，一葉動亦驚。", "閒門有勝士，學道師廣成。", "翛然卧環堵，六印一縷輕。", "脫非玄真子，疑即坐忘生。", "姓名存丹臺，寧問月旦評。", "小試未軒翥，襆被辭漢廷。", "肯令蓮社流，坐歎草堂靈。", "要當酌家釀，酒色粲碧瑛。"]'),
('ade82f8f-02b6-4d92-958f-0d745c83883c','次韵朱知裁少卿見貽二首  其二','曾惇','宋','宋诗','song-poetry','','[]','少陵卧窮巷，作詩歎秋雨。',168,'全唐诗/poet.song.113000.json','["少陵卧窮巷，作詩歎秋雨。", "坐令馬羣空，真欲洗萬古。", "乃知筆有神，寧復慚思阻。", "此翁已仙去，上界足官府。", "下視五濁世，正自一塵聚。", "後學如秋蟬，聒耳了無取。", "月卿折檻後，傳家有儀矩。", "織成錦繡段，宮商寄鳴杼。", "追還正始音，雅頌繼皇武。", "即今風騷將，僅可一二數。", "豈伊塵滓人，得此百世士。", "心源忽湛然，對面識諸祖。", "何待登妙高，歷險歎踽踽。", "便可咤善才，室中聞密語。"]'),
('f30fe308-c341-42ab-a14f-32ac54543ec9','題謝景思少卿藥寮二首  其一','曾惇','宋','宋诗','song-poetry','','[]','先生數畝園，種藥一何盛。',96,'全唐诗/poet.song.113000.json','["先生數畝園，種藥一何盛。", "子知醫國手，元自諳藥性。", "愚溪植仙毗，服食每自信。", "伏波收薏苡，初不避讒柄。", "牛溲馬渤輩，並蓄用必慎。", "我知若人心，欲了世閒病。", "君非山中相，疑即句漏令。", "問訊紫金丹，刀圭宜有贈。"]'),
('7c3b2e57-a958-4793-ac38-ba59b29eb022','題謝景思少卿藥寮二首  其二','曾惇','宋','宋诗','song-poetry','','[]','維摩示清羸，宴坐丈室中。',96,'全唐诗/poet.song.113000.json','["維摩示清羸，宴坐丈室中。", "靜觀世上人，百邪所交攻。", "我有一丸藥，得之無是公。", "人人各安樂，淡然心地空。", "脫復未辦此，濟物存陰功。", "南山千歲苓，託根萬丈松。", "下有青青草，其名爲救窮。", "願君時舉手，採取置藥籠。"]'),
('87efe2d9-a46f-4cb7-a3fb-593038b9e2a6','次韵李舉之玉霄亭  其一','曾惇','宋','宋诗','song-poetry','','[]','新亭崛起最高峰，無數遥岑翠埽空。',64,'全唐诗/poet.song.113000.json','["新亭崛起最高峰，無數遥岑翠埽空。", "恐有謝公留屐齒，爲開摩詰畫屏風。", "倚江楊柳自高下，照水杏花能白紅。", "正欠渭川千畝竹，清陰分借頼鄰翁。"]'),
('b87d409e-621c-4605-a52b-035b16439606','次韵李舉之玉霄亭  其二','曾惇','宋','宋诗','song-poetry','','[]','亭據城央一徑開，仍標蘭芷出蒿萊。',64,'全唐诗/poet.song.113000.json','["亭據城央一徑開，仍標蘭芷出蒿萊。", "諸峰合沓雲邊出，大舶岢峩海上來。", "已辦酒池供倒載，可無舞袖看低回。", "風煙正頼君彈壓，時遣詩鋒爲剸裁。"]'),
('ff900327-5a38-4a8a-bc53-12560be0f407','再用前韵  其一','曾惇','宋','宋诗','song-poetry','','[]','舉觴東望玉霄峰，萬頃雲濤雪塞空。',64,'全唐诗/poet.song.113000.json','["舉觴東望玉霄峰，萬頃雲濤雪塞空。", "擁鼻自應多好句，褰裳便欲御長風。", "際天江草如許碧，隔水山桃無限紅。", "李侯長句有家法，驚倒江樓一禿翁。"]'),
('724ff6c9-753e-4270-b5b7-b3a063706240','再用前韵  其二','曾惇','宋','宋诗','song-poetry','','[]','危觀干霄百尺開，海山羅列似東萊。',64,'全唐诗/poet.song.113000.json','["危觀干霄百尺開，海山羅列似東萊。", "鳥飛千里暮天碧，雲斷半弦新月來。", "報答風光傷晼晚，扶持歡事小徘徊。", "一春準擬留君醉，翡翠羅衫窄窄裁。"]'),
('880742a5-5043-4127-82bc-e07448af0e42','東湖懷賀子忱','曾惇','宋','宋诗','song-poetry','','[]','不負春風爛漫晴，聊驅小隊出郊坰。',64,'全唐诗/poet.song.113000.json','["不負春風爛漫晴，聊驅小隊出郊坰。", "一百五日可無酒，二十四弦須細聽。", "溶溶漾漾沙鳥白，短短長長溪柳青。", "賀監扁舟在何許，惜無妙墨記蘭亭。"]'),
('22aff49e-a828-413d-8d50-5987008b2bcf','丹丘諸先輩被薦書赴試南宮郡守曾惇既大合樂祖其行復成小詩歌以送之','曾惇','宋','宋诗','song-poetry','','[]','夜窗幾歲聚寒螢，一日秋闈較藝精。',64,'全唐诗/poet.song.113000.json','["夜窗幾歲聚寒螢，一日秋闈較藝精。", "不但春秋明古義，雅知月旦著鄉評。", "毫端剩埽三千牘，雲路方期九萬程。", "三郡看魁天下士，丹丘應未墜家聲。"]'),
('953dd4cd-ab94-49b5-8430-3f3d51a5f2fc','江南野步簡賀子忱蔡瞻明','曾惇','宋','宋诗','song-poetry','','[]','步屧溪南探野梅，衝寒仍與故人來。',64,'全唐诗/poet.song.113000.json','["步屧溪南探野梅，衝寒仍與故人來。", "竹邊嫩蕊爲誰好，雪後惡雲今日開。", "照夜剩呼修月戶，惜花須築避風臺。", "中郎華髮殊堪酒，更挽稽山賀監回。"]'),
('e71b68a1-6f98-406d-949c-0ec35a226a41','次韵景伯寵示勸農新什','曾惇','宋','宋诗','song-poetry','','[]','奉詔東郊宣主恩，如雲和氣藹生春。',64,'全唐诗/poet.song.113000.json','["奉詔東郊宣主恩，如雲和氣藹生春。", "仙舟偶共元禮載，宮舍仍依王翰鄰。", "忽有清詩驚老眼，慚無惠化及斯人。", "半生不分微官縛，早晚故溪歸釣綸。"]'),
('a335c6d8-3b5f-40a2-b376-0dc637cf375f','題桐柏石道士院妙聲堂','曾惇','宋','宋诗','song-poetry','','[]','門外千峰翠作堆，道人名籍在丹臺。',32,'全唐诗/poet.song.113000.json','["門外千峰翠作堆，道人名籍在丹臺。", "是非榮辱俱休問，只放泉聲入耳來。"]'),
('3e644887-7695-4b22-82f9-18c6f21019e2','洪景伯飲諸丈分繡閣以詩戲之','曾惇','宋','宋诗','song-poetry','','[]','新營小閣面孱顔，領客開樽紫翠閒。',64,'全唐诗/poet.song.113000.json','["新營小閣面孱顔，領客開樽紫翠閒。", "千里畫圖供徙倚，一時名勝喜躋攀。", "好風已破晚來暑，小雨不遮湖上山。", "老子箇中殊不淺，尚堪同醉看弓彎。"]'),
('950e5131-9797-4100-9881-d9662000a379','龍溪新亭','曾惇','宋','宋诗','song-poetry','','[]','懷玉知名寺，諸峯翠插天。',48,'全唐诗/poet.song.113000.json','["懷玉知名寺，諸峯翠插天。", "凌雲飛略彴，照水舞蜿蜒。", "午日孤穿履，新凉定著鞭。", "更須煩惠遠，小立虎溪邊。"]'),
('a264446a-0f20-4fc1-8616-d9650ddbaa7d','句  其一','曾惇','宋','宋诗','song-poetry','','[]','家貧只舊醅，不辦樽中醁。',24,'全唐诗/poet.song.113000.json','["家貧只舊醅，不辦樽中醁。", "但煮官焙香，炊飯鱠魚腹。"]'),
('99996ed4-5d7e-49c1-ac92-1f68224e137f','句  其二','曾惇','宋','宋诗','song-poetry','','[]','淺沙細與鷗盟。',7,'全唐诗/poet.song.113000.json','["淺沙細與鷗盟。"]'),
('f2f7dfaa-74e9-4cf6-83a7-1fd55d3eff72','句  其三','曾惇','宋','宋诗','song-poetry','','[]','南城南豐萬家邑，異人間出俱屹立。',16,'全唐诗/poet.song.113000.json','["南城南豐萬家邑，異人間出俱屹立。"]'),
('6eaea7e9-5847-4310-97e6-d5e4bfd15bae','句  其四','曾惇','宋','宋诗','song-poetry','','[]','坐對潛山萬髻鬟，一峰孤秀獨攙天。',16,'全唐诗/poet.song.113000.json','["坐對潛山萬髻鬟，一峰孤秀獨攙天。"]'),
('f4e5c00b-7196-42a9-995e-182ce347aff5','句  其五','曾惇','宋','宋诗','song-poetry','','[]','近城殊未發，君與探山宮。',12,'全唐诗/poet.song.113000.json','["近城殊未發，君與探山宮。"]'),
('b6ae4243-0154-491b-bd8e-ea26d672b814','懷天台','謝伋','宋','宋诗','song-poetry','','[]','有妹有弟奉親慈，我因官事獨此縻。',64,'全唐诗/poet.song.113000.json','["有妹有弟奉親慈，我因官事獨此縻。", "濤江身隔一萬里，永日心思十二時。", "戀豆豈能勞遠駕，臨流端欲賦清詩。", "故山尚有茅茨舊，端策何須更拂龜。"]'),
('c789c1ec-a51f-4365-ae04-4b4a6da440c6','紹興甲寅正月至吳文叟山莊','謝伋','宋','宋诗','song-poetry','','[]','學士奔波方繞枝，隠者盤旋能避時。',128,'全唐诗/poet.song.113000.json','["學士奔波方繞枝，隠者盤旋能避時。", "縈紆三徑襄枳棘，庇蔭萬木藏茅茨。", "常時理棹去城遠，先世卜築無人知。", "高山爲屏開錦繡，清泉可鑑堆琉璃。", "主人好德鄉黨敬，賓客來游鄰里窺。", "有田千畝何所羨，遺子一經常自期。", "莫向清流歌考槃，須知好爵徒爾縻。", "驅羊拾芥不難取，濯纓洗耳應復思。"]'),
('42569b00-2f54-4f3c-b244-e44fe652a904','曾谹父使君招客雙巖堂','謝伋','宋','宋诗','song-poetry','','[]','雲篆長懸紀歲年，鳳池人去政聲傳。',64,'全唐诗/poet.song.113000.json','["雲篆長懸紀歲年，鳳池人去政聲傳。", "風流繼踵今詩伯，物色分留到綺筵。", "南國甘棠有琪樹，平居大屋尚修椽。", "使君小試扶顛手，高義仍聞過昔賢。"]'),
('f7d01b19-7772-42c1-955b-78aac8d37e87','寄曾使君','謝伋','宋','宋诗','song-poetry','','[]','江色城霞氣象新，中興岳牧用詩人。',64,'全唐诗/poet.song.113000.json','["江色城霞氣象新，中興岳牧用詩人。", "爭趨畫戟高門地，竊伏荒山漲海瀕。", "敢望車魚延傳舍，先持箋簡具州民。", "猿驚鶴訝知吾意，欲醉雙巖堂上春。"]'),
('3e75c842-4d38-4cd2-ae06-756731f2d315','國清愚谷禪師索更好堂詩','謝伋','宋','宋诗','song-poetry','','[]','丹梯寧復倦扶筇，聞說青山又改容。',64,'全唐诗/poet.song.113000.json','["丹梯寧復倦扶筇，聞說青山又改容。", "下界已同三絕寺，上方仍對妙高峰。", "聊須小憩窗前榻，莫慮遥聞齋後鐘。", "脚力已窮猶應接，茲時目力更難供。"]'),
('2ed549b5-13bd-494c-99cf-c10d11740bcf','恭謁台嶽桐柏觀紀事','謝伋','宋','宋诗','song-poetry','','[]','拜恩散號在茲地，乘興真游駕小車。',272,'全唐诗/poet.song.113000.json','["拜恩散號在茲地，乘興真游駕小車。", "擁笏朝真香火罷，虛明庭院靜無譁。", "按圖默記金聲賦，意氣直欲登仙槎。", "龍淵三井液膏乳，瓊臺雙闕飛雲霞。", "玉堂珠閣不可到，山靈勒回因念差。", "金壺龍檢世已遠，五千漆字猶堪誇。", "如今丹筆已漫漶，風日暴炙元無遮。", "元公豐碑壓千柱，擇木小隸湮塵沙。", "丈人巾屨青松下，道士甌蟻隨傾茶。", "謂予讀敕見陳請，州帖次第來幽遐。", "了知君心棄符竹，不敢復獻旌節花。", "我今便欲老巖谷，亦不求棗大如瓜。", "洗心脫然去塵累，不慕盛麗並紛華。", "黄衣青藜或可遇，願授竹簡觀聱牙。", "人生信是行樂耳，豈復自慁同池蛙。", "茲行已占平生勝，後來游觀寧復加。", "清興不極尚忘返，長天日暮空咨嗟。"]'),
('eedac126-e7ae-4dfb-b0b3-11a5dae91756','靈巖寂菴辯才師有羅漢樹一株移自台嶽託根木香架下頗妨成長因寄沈水香往易之','謝伋','宋','宋诗','song-poetry','','[]','台嶽石爲梁，苔滑水湍激。',240,'全唐诗/poet.song.113000.json','["台嶽石爲梁，苔滑水湍激。", "應真所游處，林杪飛杖錫。", "遂令山木閒，變現如所歷。", "扶疏冠琪玉，不受霜雪滴。", "當其含蕊時，知狀曾目擊。", "端如尊者相，相呈咸可覿。", "掌合貌甚恭，頭光不加冪。", "升高真躡虛，集菀聊憩寂。", "枝棲過三宿，神通渺難測。", "不於下成蹊，俗眼何曾識。", "四皓共木奴，大槐蔭土國。", "孰非夢幻閒，昧者徒自惑。", "况此方廣徒，衲身豈人力。", "我有一瓣香，敬爲千百億。", "漂摇風雨中，此地何偪仄。", "向來專一丘，不受山庭勒。", "盤踞來藥寮，使我親封植。", "清泉堪晚漱，甘露充朝食。", "埽除有浮屠，高下宜降陟。", "稽首達聲聞，應供毋難色。"]'),
('a8e08c1c-66d8-4826-87b0-e4d8d5d6fd2b','買舟過雙塔夜阻風舟中有作','謝伋','宋','宋诗','song-poetry','','[]','高閣臨流雙塔寺，扁舟艤岸一帆風。',64,'全唐诗/poet.song.113000.json','["高閣臨流雙塔寺，扁舟艤岸一帆風。", "夜潮迷浦難安枕，晝雨翻江只閉篷。", "人境行時雖甚逆，我身著處本來空。", "明朝乍喜團欒話，應忘波濤洶湧中。"]'),
('bc27f8dc-a397-449c-9608-d7eb6cf9a5c1','恭謁靈康祠下二首  其一','謝伋','宋','宋诗','song-poetry','','[]','婺女光分鄰土壤，赤城標建絕紛埃。',64,'全唐诗/poet.song.113000.json','["婺女光分鄰土壤，赤城標建絕紛埃。", "叢祠祗事無終古，靈迹相傳有自來。", "屋上飛煙梧鼎熟，水邊迎棹度船回。", "大神如在匪徼福，但欲乞靈消禍災。"]'),
('073101df-f7d0-4ee0-911e-dca1329eac49','恭謁靈康祠下二首  其二','謝伋','宋','宋诗','song-poetry','','[]','生求同志論心事，沒聳邦人福禍間。',64,'全唐诗/poet.song.113000.json','["生求同志論心事，沒聳邦人福禍間。", "吏奉敕書躋舊典，廟長血食配崇山。", "刲羊刺豕來村社，鼓瑟吹笙出市闤。", "報祭豐年更晴日，稻秔充羨老農閒。"]'),
('23b14a1a-b90f-469a-8663-f57963e9e9c3','某昨日赴景伯通判正字宴集坐間使君郎中有詩問訊末章仍及今日湖上之約輒次嚴韵','謝伋','宋','宋诗','song-poetry','','[]','巾車入郭解愁顔，著我群賢俎豆間。',64,'全唐诗/poet.song.113000.json','["巾車入郭解愁顔，著我群賢俎豆間。", "小隊出郊還許從，清詩首唱詎容攀。", "溪風杜守吟秋浦，雲月韋侯誇盛山。", "何似赤城遺暑溼，東湖盡醉碧筒彎。"]'),
('50fb3aff-1dcf-4afb-8963-a2733a98c774','洪景伯正字分繡閣','謝伋','宋','宋诗','song-poetry','','[]','層屋周遭列岫圍，碧滋紅彩眩晴暉。',64,'全唐诗/poet.song.113000.json','["層屋周遭列岫圍，碧滋紅彩眩晴暉。", "境中一段明綾出，望外千春碎縷歸。", "疊嶂分留女媧練，飛流不雜衛文衣。", "主人亦是登臨客，鳳閣明年詠紫薇。"]'),
('c534d897-b428-4eac-b35c-f46aaea1ff07','子忱崇道吏部寄書問訊并寄藥物適當風雨夕長句代謝','謝伋','宋','宋诗','song-poetry','','[]','數閒破屋壓崔嵬，經月何人共酒杯。',64,'全唐诗/poet.song.113000.json','["數閒破屋壓崔嵬，經月何人共酒杯。", "入耳了無門外事，關心惟訪藥中材。", "一山秋色連雲暗，半夜風聲夾雨來。", "欲向天台招賀監，未應容易拔船開。"]'),
('9bce784f-716c-4902-9f93-f09964b54e5b','題瑞巖惺惺石','謝伋','宋','宋诗','song-poetry','','[]','寧復露稜角，明心不受欺。',24,'全唐诗/poet.song.113000.json','["寧復露稜角，明心不受欺。", "千年誰可轉，空照是宗師。"]'),
('7919eb53-67d9-45d4-b287-9ec4ec99610f','滴滴泉','謝伋','宋','宋诗','song-poetry','','[]','滴瀝來無盡，秋聲雜水聲。',24,'全唐诗/poet.song.113000.json','["滴瀝來無盡，秋聲雜水聲。", "縱觀深省後，一酌更心清。"]'),
('6399d500-0623-4bf7-8a71-c4a98b9629b6','奉酬洪景伯','謝伋','宋','宋诗','song-poetry','','[]','屏居常恨造門疏，覿面真如得異書。',64,'全唐诗/poet.song.113000.json','["屏居常恨造門疏，覿面真如得異書。", "昔年丹筆勘閣本，此日海邦題坐輿。", "幸接好音聞正始，豈惟妙句突黄初。", "道山學士來車騎，還使林僧識佩魚。"]'),
('e3759e03-3030-4de8-b126-c4c0185aec2a','藥寮候洪景伯','謝伋','宋','宋诗','song-poetry','','[]','十日元無兩日晴，小園幽事最關情。',64,'全唐诗/poet.song.113000.json','["十日元無兩日晴，小園幽事最關情。", "早披鶴氅看雲出，晚踏漁舟趁月明。", "夜雨洗來修竹浄，曉風吹入瘦松清。", "野亭花徑緣君埽，嫋嫋秋聲動旆旌。"]'),
('d3a53cc4-5914-45e4-9204-e92230520eda','天台李公孟長官出示桐柏觀百丈坑玉蘭且索賦詩繼以一本分惠又復見督勉爲之賦','謝伋','宋','宋诗','song-poetry','','[]','桐柏古福地，瓊臺上侵星。',192,'全唐诗/poet.song.113000.json','["桐柏古福地，瓊臺上侵星。", "仙人種玉處，瑶草猶亭亭。", "羽人紉作佩，瑞露濯芳馨。", "懸崖百丈坑，九疇詩得經。", "真境有誰何，守護煩六丁。", "長官仙李氏，不畏茲山靈。", "河陽無數花，葉蕊衒紫青。", "受此貞潔姿，不露凡卉形。", "命彼輕舉者，竊取巖中扃。", "封植入籠檻，羅列旁軒屏。", "結根失所託，摧殘日飄零。", "揖我求我言，矢詩當見聽。", "草木遂其性，民物自安寧。", "君其毋求奇，采掇庶可停。", "蘭玉近取譬，何用專階庭。", "人觀盡白眼，莫遣下青冥。"]'),
('f8c4887b-b595-4bda-9dac-52835f9e2f74','過護國廣恩寺','謝伋','宋','宋诗','song-poetry','','[]','地隔三江雲水深，那知帝子啟山林。',32,'全唐诗/poet.song.113000.json','["地隔三江雲水深，那知帝子啟山林。", "咸京築館今誰主，白晝松風哀怨音。"]'),
('0a7ab2cd-0943-4ad6-8265-d71534f41987','同季父游東掖能仁寺','謝伋','宋','宋诗','song-poetry','','[]','兩寺從分有白蓮，人瞻東掖舊承天。',64,'全唐诗/poet.song.113000.json','["兩寺從分有白蓮，人瞻東掖舊承天。", "重尋貴主布金地，共飲神僧卓錫泉。", "阮叔林閒携伴侶，支郎社內許留連。", "欲迎瑞相還龕去，香火靈山古佛前。"]'),
('cdf72a3d-c9ee-4553-90ef-91b9d8ca6719','伋再和史君前詩末章聞已再乞宮祠伋居在遠郊不獲同州人致挽留之詞復用前韵','謝伋','宋','宋诗','song-poetry','','[]','追鋒未下璽書催，鼎味調和欠爾梅。',64,'全唐诗/poet.song.113000.json','["追鋒未下璽書催，鼎味調和欠爾梅。", "太守印章常懶佩，神仙官府要同陪。", "赤城霞起樓居見，紫邏雲深吏引來。", "豈羨蓬萊新日月，莫教寓士奉離杯。"]'),
('568d196f-df54-4afa-9f76-8c739a201df4','元夕日承再示梅韵佳作過形褒借輒爾繼和自茲當絕筆矣','謝伋','宋','宋诗','song-poetry','','[]','別來無奈歲時催，渴想聲猷但指梅。',64,'全唐诗/poet.song.113000.json','["別來無奈歲時催，渴想聲猷但指梅。", "六逸溪頭難角逐，七賢林下曷追陪。", "忘懷不覺老將至，揣分爭如歸去來。", "况值元宵增感慨，十年耳冷聽傾杯。"]'),
('b9fcd65a-305a-40c6-b525-86aafb1fa284','陪內翰尚書丈同到官梅亭會有他期先去情見乎辭','謝伋','宋','宋诗','song-poetry','','[]','歲云暮矣物華催，江城風光著野梅。',64,'全唐诗/poet.song.113000.json','["歲云暮矣物華催，江城風光著野梅。", "東閣詩成將付與，南枝花發許追陪。", "混冰落素應難久，姑雪欺春不並來。", "誰爲商量開細細，早教玉樹映金杯。"]'),
('00229030-a36c-4f89-b542-c8a345b7ca38','送司馬季思通守沿檄天台二首  其一','謝伋','宋','宋诗','song-poetry','','[]','靜聽天台事，茲行毋憚勞。',48,'全唐诗/poet.song.113000.json','["靜聽天台事，茲行毋憚勞。", "水和青嶼出，霞起赤城高。", "佛寺炊烏飯，仙宮壓白醪。", "奉符須少緩，處處可遊遨。"]'),
('34b32f01-8d9a-48e2-86d3-42d28f4fb600','送司馬季思通守沿檄天台二首  其二','謝伋','宋','宋诗','song-poetry','','[]','靈石山頭路，君應訪藥寮。',48,'全唐诗/poet.song.113000.json','["靈石山頭路，君應訪藥寮。", "竹陰千箇密，松色數章喬。", "季弟方從政，孤僧伴採樵。", "爲言心已往，不待楚詞招。"]'),
('b3928457-3f6d-4295-ad27-a0af64d8c484','送孫仲舉徽猷罷郡造朝','謝伋','宋','宋诗','song-poetry','','[]','四月維夏天未暑，天台居民逃室處。',352,'全唐诗/poet.song.113000.json','["四月維夏天未暑，天台居民逃室處。", "城中屨貴巷陌喧，城外號奴去村墅。", "老癃扶杖少者趨，夫棄禾麻婦投杼。", "肩隨足躡似同謀，色沮聲低咸偶語。", "使君高車挽不止，誰其嗣之保閭里。", "攀轅卧轍豈留行，遮道填門寧足恃。", "三江阻隔江水深，莫使江頭有船艤。", "我聞此語良足聽，呼使來前陳本始。", "吾州使君能靜治，千里無虞安獄市。", "澄之不清擾不濁，盡道使君心似水。", "昔襦不足今袴餘，良藥千金補瘡痏。", "黄屋近駐錢塘城，願說政平並訟理。", "從今更借二三年，增秩賜金書用璽。", "我言此語爾未思，有大於此爾何知。", "入爲三公自故事，天台美稱公是宜。", "德澤但可施一州，潤及九里寧獨私。", "携持却看祖道盛，送車百兩多旌麾。", "爭先勸飲接殷勤，玉酒湛湛皆盈巵。", "使君千觴亦未醉，更聽小儒前致詞。", "嗟予待次七閩郡，法式規模知吏師。", "忘年屈勢待我厚，歲月易得今再期。", "送公去郡情更惡，人送作郡知何時。"]'),
('4e10b363-4624-4490-bed6-40b448b1da7b','過晁使君子莫園有感','謝伋','宋','宋诗','song-poetry','','[]','一丘膴膴占岡原，夐隔塵寰息世喧。',64,'全唐诗/poet.song.113000.json','["一丘膴膴占岡原，夐隔塵寰息世喧。", "牆屋朅來營勝地，籃輿不復羨高軒。", "當年松菊淵明宅，此日蓬蒿仲蔚園。", "奠冢成泥有遺愛，懷人誰爲雪沈冤。"]'),
('e8700775-6f45-41a6-bfc4-2cff3b6b3aeb','妙庭觀二首  其一','謝伋','宋','宋诗','song-poetry','','[]','蕭蕭六轡天邊路，雲竹風松正歲寒。',32,'全唐诗/poet.song.113000.json','["蕭蕭六轡天邊路，雲竹風松正歲寒。", "欲洗衰顔換凡骨，應須九轉大還丹。"]'),
('b08184e8-29e5-4c22-abd1-d73a85461daf','妙庭觀二首  其二','謝伋','宋','宋诗','song-poetry','','[]','雲軿一去遠難追，丹鼎埋光固不疑。',32,'全唐诗/poet.song.113000.json','["雲軿一去遠難追，丹鼎埋光固不疑。", "承露仙人辭漢後，幾重深杳隔瑶池。"]'),
('c6815b22-5ef4-46cf-8d85-c52bb56be3cf','和李士舉過仙都徐氏山居  其一','謝伋','宋','宋诗','song-poetry','','[]','{𥫗場}節光華遠，軺車那得閑。',51,'全唐诗/poet.song.113000.json','["{𥫗場}節光華遠，軺車那得閑。", "咨詢元自急，省斂亦相關。", "去住存高詠，晴陰對好山。", "深慚縻郡紱，仙境不同攀。"]'),
('285cf933-7c5d-47eb-9720-8c8157b26daf','和李士舉過仙都徐氏山居  其二','謝伋','宋','宋诗','song-poetry','','[]','繞耄倪扶杖小童閑，繞舍清溪碧水環。',33,'全唐诗/poet.song.113000.json','["繞耄倪扶杖小童閑，繞舍清溪碧水環。", "爭看赤帷仍避傳，靜無桴鼓愛青山。"]'),
('c5fc2a05-2cc8-4600-a857-514040efcea9','題夾漈草堂  其一','鄭樵','宋','宋诗','song-poetry','','[]','堂後青松百尺長，堂前流水日湯湯。',64,'全唐诗/poet.song.113000.json','["堂後青松百尺長，堂前流水日湯湯。", "西窗盡是農桑域，北牖無非花葛鄉。", "罷去精神渾冉冉，看來几案尚穰穰。", "不知此物何時了，待看臨流自在狂。"]'),
('9df96f8f-f251-4bab-9207-550a2922f2be','題夾漈草堂  其二','鄭樵','宋','宋诗','song-poetry','','[]','堂後施柴堂上燒，柴門終日似無聊。',64,'全唐诗/poet.song.113000.json','["堂後施柴堂上燒，柴門終日似無聊。", "蓼蟲不解知辛苦，松鶴何能慰寂寥。", "述作還驚心力盡，吟哦早覺鬢毛彫。", "布衣蔬食隨天性，休訝巢由不見堯。"]'),
('b8282642-28b6-4b64-bdcd-5c185f864f40','題南山書堂','鄭樵','宋','宋诗','song-poetry','','[]','一泓澄澈照人間，明月團團落古灣。',64,'全唐诗/poet.song.113000.json','["一泓澄澈照人間，明月團團落古灣。", "不向奔流隨浪擊，獨持高潔伴雲閒。", "禪房夜靜留清鑑，閬苑仙歸墜碧環。", "每到軒前心轉逸，了無纖翳可相關。"]'),
('72769c5b-c4b8-432c-bf0a-06648a7effbc','穀城山松隠巖','鄭樵','宋','宋诗','song-poetry','','[]','青嶂迴環畫屏倚，晴窗倒入春湖水。',64,'全唐诗/poet.song.113000.json','["青嶂迴環畫屏倚，晴窗倒入春湖水。", "村村叢樹綠於藍，列列行人去如蟻。", "新秧未插水田平，高低隴麥相縱橫。", "黄昏倦客忘歸去，孤月亭亭雲外生。"]'),
('f9ffeb40-7451-49e8-86c8-62b72a586856','送芹齋','鄭樵','宋','宋诗','song-poetry','','[]','千載清風去不留，何人能伴赤松遊。',64,'全唐诗/poet.song.113000.json','["千載清風去不留，何人能伴赤松遊。", "乞骸直到骸歸日，告老須臨老盡頭。", "元亮園田何處有，向平昏嫁幾時休。", "湖州別駕發深省，掛却朝冠便自由。"]'),
('bf9c60d3-0e78-4380-ad2d-10ca9de8fb5c','題溪東草堂','鄭樵','宋','宋诗','song-poetry','','[]','春融天氣露微微，藥草葱芽脈脈肥。',64,'全唐诗/poet.song.113000.json','["春融天氣露微微，藥草葱芽脈脈肥。", "植竹舊竿從茂謝，栽桃新樹忽芳菲。", "天寒堂上燃柴火，日暖溪東解蝨衣。", "興動便携樽到嶺，人生真性莫教違。"]'),
('3914802b-cbfe-471b-9a29-77054f7642f3','湘妃怨','鄭樵','宋','宋诗','song-poetry','','[]','黄埃游輦轂，翳日冷旌旗。',72,'全唐诗/poet.song.113000.json','["黄埃游輦轂，翳日冷旌旗。", "龍去攀髯遠，鸞孤對影微。", "魂沉江縹渺，淚染竹依稀。", "枯樹空千載，寒松已十圍。", "蘆花深月色，燐火劇螢飛。", "橫笛瀟湘暮，哀猿何處歸。"]'),
('40177fb3-575b-4597-9290-83617c1c37dd','昭君怨','鄭樵','宋','宋诗','song-poetry','','[]','長謝椒房草，終爲薄命身。',72,'全唐诗/poet.song.113000.json','["長謝椒房草，終爲薄命身。", "那教蘭蕙質，翻與雪霜親。", "臉膩勻脂淺，粧殘促恨顰。", "故知關北夜，無分漢南春。", "紅淚殘胡月，輕衣半洛塵。", "琵琶淒切語，愁殺路傍人。"]'),
('add783ac-c7d9-4146-b9d0-3fab250e8d3a','輓通判黄子方','鄭樵','宋','宋诗','song-poetry','','[]','歌成薤露悲，秋草正離離。',48,'全唐诗/poet.song.113000.json','["歌成薤露悲，秋草正離離。", "昔異修文事，今同鬼伯司。", "盾衰雙日落，夷惠兩風遺。", "衰俗吾無恨，親曾識紫芝。"]'),
('e96349c0-020b-4559-b288-11a239a25629','昭君解','鄭樵','宋','宋诗','song-poetry','','[]','巫山能雨亦能雲，宮麗三千杳不聞。',32,'全唐诗/poet.song.113000.json','["巫山能雨亦能雲，宮麗三千杳不聞。", "延壽若爲公道筆，後人誰識一昭君。"]'),
('b6b422a0-0d11-48e5-b864-01b2f70407aa','靈龜潭','鄭樵','宋','宋诗','song-poetry','','[]','泉心漱玉開心孔，山色挼藍熨眼花。',32,'全唐诗/poet.song.113000.json','["泉心漱玉開心孔，山色挼藍熨眼花。", "著手摩娑溪上石，他年來訪汝爲家。"]'),
('2ab520c2-d6bf-4bc9-a572-e2ee344475a9','北山巖','鄭樵','宋','宋诗','song-poetry','','[]','西風曳曳片雲閒，一夜寒泉卧北山。',32,'全唐诗/poet.song.113000.json','["西風曳曳片雲閒，一夜寒泉卧北山。", "倚杖巖頭秋獨望，稀疏烟壠是人間。"]'),
('9973047e-3176-4da1-8f6e-b4469c3a066f','東山採藥','鄭樵','宋','宋诗','song-poetry','','[]','一掬金丹向晚風，山前草木盡龍宮。',32,'全唐诗/poet.song.113000.json','["一掬金丹向晚風，山前草木盡龍宮。", "詩書便是神仙味，更笑行沖問藥籠。"]'),
('c11c35cd-2bc7-460f-99d1-9d5d9e8e6fe6','過桃花洞田家留飲','鄭樵','宋','宋诗','song-poetry','','[]','偶促沼渚過山家，灼灼桃花噪暮鴉。',64,'全唐诗/poet.song.113000.json','["偶促沼渚過山家，灼灼桃花噪暮鴉。", "是處竹籬環草屋，人間雞黍話桑麻。", "抱琴靜聽濤聲急，對酒閒觀月色奢。", "可笑南陽劉子驥，欲尋風土滯京華。"]'),
('e8f38cf7-9c05-4e58-887e-1ef5d872c73c','薌林閒居  其一','鄭樵','宋','宋诗','song-poetry','','[]','薌林蒼翠甚，極目可□詩。',48,'全唐诗/poet.song.113000.json','["薌林蒼翠甚，極目可□詩。", "梅子風前落，杏花雨後移。", "清溪過半郭，孤月隠疏籬。", "寂寂雲山外，蕭然獨自知。"]'),
('4bd7c7d6-6ad7-48a4-8a1a-8d64ad1f1646','薌林閒居  其二','鄭樵','宋','宋诗','song-poetry','','[]','薌林蒼翠甚，霽色繞吾廬。',48,'全唐诗/poet.song.113000.json','["薌林蒼翠甚，霽色繞吾廬。", "四面鳥聲寂，一庭月影疏。", "有山皆入坐，無日不安居。", "好向牆東卧，看人獻子虛。"]'),
('e6cebaf9-9d0f-4888-8cf3-fe2e988a3ca4','晨雨','鄭樵','宋','宋诗','song-poetry','','[]','東方斜未徹，暝色淡初分。',48,'全唐诗/poet.song.113000.json','["東方斜未徹，暝色淡初分。", "宿鳥林中噪，淒風葉上聞。", "鐘鳴催過雨，星落避行雲。", "獨立草堂內，涓涓羣動紛。"]'),
('39c7288e-0838-4b19-8083-32a0d85a28fa','夜雨','鄭樵','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','夜雨瀟瀟至，天寒擁敝裘。',48,'全唐诗/poet.song.113000.json','["夜雨瀟瀟至，天寒擁敝裘。", "空床聽幻響，獨詠解深憂。", "次第園蔬潤，參差漁火幽。", "長江風浪息，何日放舟遊。"]'),
('8baaefe3-80ed-494b-8d80-1868ae24cc6d','村雨','鄭樵','宋','宋诗','song-poetry','','[]','荒村常寂寂，小雨自涓涓。',48,'全唐诗/poet.song.113000.json','["荒村常寂寂，小雨自涓涓。", "寒氣侵人急，野花入目妍。", "看山頻當戶，聽鳥倍難眠。", "萬事蕭條盡，空餘日暮煙。"]'),
('da2b2f85-50f2-4e1a-8e92-230a84401eb3','澗雨','鄭樵','宋','宋诗','song-poetry','','[]','飄飄雨色亂，終日悞聞聲。',48,'全唐诗/poet.song.113000.json','["飄飄雨色亂，終日悞聞聲。", "釣客呼持笠，牧童喜啜羹。", "輕香樹下滿，餘響谷中清。", "爲謝登臨者，枕流洗耳傾。"]'),
('9c858fc4-e37d-45fe-9f70-27eca88ac263','滌愫  其一','鄭樵','宋','宋诗','song-poetry','','[]','枳棘何榛榛，猿狖不敢下。',48,'全唐诗/poet.song.113000.json','["枳棘何榛榛，猿狖不敢下。", "芳苓何燁燁，雹霜不敢灑。", "驊騮馳曲囏，舉足難寬假。", "所以古之人，犁鋤聊自把。"]'),
('25c36b1f-1144-43dd-bb75-db4469c650c4','滌愫  其二','鄭樵','宋','宋诗','song-poetry','','[]','天命既倒懸，將身費椒糈。',48,'全唐诗/poet.song.113000.json','["天命既倒懸，將身費椒糈。", "朝行畏日薄，暮行畏齟齬。", "娵娃雖見珍，衆嫭心未許。", "展轉溷餔歠，敢俟慶雲舉。"]'),
('d5c28b91-697b-4bae-992e-73237131e065','滌愫  其三','鄭樵','宋','宋诗','song-poetry','','[]','孤鳳落鷹巢，啼麟墜虎穴。',48,'全唐诗/poet.song.113000.json','["孤鳳落鷹巢，啼麟墜虎穴。", "未能脫蒙茸，安得出軒凸。", "迢遞空自倬，耀靈久已滅。", "褆身入三門，黽勉成吾拙。"]'),
('db752334-edae-4a50-8056-60f276fae383','滌愫  其四','鄭樵','宋','宋诗','song-poetry','','[]','修身以爲弓，矯思以爲矢。',48,'全唐诗/poet.song.113000.json','["修身以爲弓，矯思以爲矢。", "立義以爲的，亦云善擬議。", "嗚呼彼鴻漸，進德亦猶水。", "我如駕其說，木舌暢所指。"]'),
('5d7980cb-b436-4091-80fa-4e64a1c76f53','滌愫  其五','鄭樵','宋','宋诗','song-poetry','','[]','八荒有禮樂，塗民以耳目。',48,'全唐诗/poet.song.113000.json','["八荒有禮樂，塗民以耳目。", "五政不得加，七賦不能育。", "古今貴天常，最厭彼嬰犢。", "嗟哉生不辰，霑頂滋觳觫。"]'),
('3c89fc21-17d7-4ce3-a69a-289da30e8ffa','滌愫  其六','鄭樵','宋','宋诗','song-poetry','','[]','潛天以不策，潛心以不手。',60,'全唐诗/poet.song.113000.json','["潛天以不策，潛心以不手。", "天人既和同，飛潛均不朽。", "吾生既病勞，未敢輕俯首。", "久幽不改操，旦夕謀杯酒。", "岷峨自沉冥，丘壑難爲後。"]'),
('9acc29c2-6b8e-4898-8d99-952c507e85c3','滌愫  其七','鄭樵','宋','宋诗','song-poetry','','[]','德行尊顔閔，股肱卑蕭曹。',48,'全唐诗/poet.song.113000.json','["德行尊顔閔，股肱卑蕭曹。", "明哲知寢伏，文章亦弁髦。", "縱彼攀龍鱗，何如棹小舠。", "人生一世間，慎勿輕自豪。"]'),
('de6176b2-6f02-46f2-bd4d-83634f5ef012','滌愫  其八','鄭樵','宋','宋诗','song-poetry','','[]','賢者不飽食，何爲仕與農。',48,'全唐诗/poet.song.113000.json','["賢者不飽食，何爲仕與農。", "聖人不詭時，何爲世所宗。", "顯晦既有因，盛衰亦偶逢。", "先秋而後春，俄頃自雍容。"]'),
('f49140a0-d28b-45d0-8409-6befde01abd7','滌愫  其九','鄭樵','宋','宋诗','song-poetry','','[]','金革久不息，遐方徒憚指。',48,'全唐诗/poet.song.113000.json','["金革久不息，遐方徒憚指。", "誰爲民請命，皇天猶未喜。", "茂德自不綏，眷眷我梓里。", "傷哉古王道，樵夫亦冷齒。"]'),
('bf02872c-619e-4059-894c-a0397377534e','滌愫  其一○','鄭樵','宋','宋诗','song-poetry','','[]','嗟余本固陋，湛身入花渚。',48,'全唐诗/poet.song.113000.json','["嗟余本固陋，湛身入花渚。", "未製芙蓉裳，已習離騷語。", "綽約雖多姿，涕零何如雨。", "季夏遭繁霜，天寒不可禦。"]'),
('d957ce40-8482-4ee0-b025-172297b6de32','家園示弟槱  其一','鄭樵','宋','宋诗','song-poetry','','[]','天下輕黄憲，居鄰孰戴良。',48,'全唐诗/poet.song.113000.json','["天下輕黄憲，居鄰孰戴良。", "暴田安足較，散絹未爲狂。", "失劍羞余里，還牛讓古鄉。", "家風留不墜，少賤自翱翔。"]'),
('066014bd-7bd8-40fd-9a6f-348d1742551d','家園示弟槱  其二','鄭樵','宋','宋诗','song-poetry','','[]','竹床讀史慣，土銼勿粘塵。',48,'全唐诗/poet.song.113000.json','["竹床讀史慣，土銼勿粘塵。", "灑掃王維德，澆鋤郭太仁。", "使才看著屐，有道驗時薪。", "小物汝知謹，同心作古人。"]'),
('0272110c-bf51-4720-b03e-e919da77a00d','家園示弟槱  其三','鄭樵','宋','宋诗','song-poetry','','[]','每恨紈綺子，交遊半博徒。',48,'全唐诗/poet.song.113000.json','["每恨紈綺子，交遊半博徒。", "棄家尋有道，舍命事名儒。", "風雅非難及，今人貴與殊。", "夜深何所囑，囑汝似狂夫。"]'),
('e5e4163b-28b6-4608-b567-cc4367eb7147','家園示弟槱  其四','鄭樵','宋','宋诗','song-poetry','','[]','讀書經百卷，見影豈須驚。',48,'全唐诗/poet.song.113000.json','["讀書經百卷，見影豈須驚。", "中夜山精笑，寒燈草魅爭。", "脫冠神采足，擲樏眼光明。", "面壁吾常事，菴題天耐名。"]'),
('7be2b4b9-3e97-4fab-a9da-900d740a6ff1','家園示弟槱  其五','鄭樵','宋','宋诗','song-poetry','','[]','佻達憑豪族，疏狂自克家。',48,'全唐诗/poet.song.113000.json','["佻達憑豪族，疏狂自克家。", "看人呼狗竇，縱我泛漁槎。", "鑿穴安蜂豕，穿籬避管笳。", "如能癡勝黠，寒食賀騮驊。"]'),
('d387fbae-095c-4113-8098-42d6a90cdc8c','家園示弟槱  其六','鄭樵','宋','宋诗','song-poetry','','[]','誰使余爲墨，朝朝哭染絲。',48,'全唐诗/poet.song.113000.json','["誰使余爲墨，朝朝哭染絲。", "獵鷹才子累，殺虎古人癡。", "早信山宜面，休嫌谷可移。", "日光圖史滿，炳燭却驚遲。"]'),
('f2b22338-ba87-4a87-be4c-384a0bf87a72','家園示弟槱  其七','鄭樵','宋','宋诗','song-poetry','','[]','學儉誠佳事，慳名豈足居。',48,'全唐诗/poet.song.113000.json','["學儉誠佳事，慳名豈足居。", "寫多崇厚論，讀廢絕交書。", "結客饒傾産，破貧累賣車。", "前人家訓在，孫孔未全疏。"]'),
('a7875e54-304f-4cf5-81f4-6e518563c51d','家園示弟槱  其八','鄭樵','宋','宋诗','song-poetry','','[]','隻身空後死，千卷未酬恩。',48,'全唐诗/poet.song.113000.json','["隻身空後死，千卷未酬恩。", "不辱看來世，貪生托立言。", "無家稱馬糞，何史世龍門。", "負石今愁晚，中宵弔屈原。"]'),
('1823381e-e15b-44c5-bdae-5f9b3b803429','夏日題王右丞冬山書屋圖','鄭樵','宋','宋诗','song-poetry','','[]','壁間颯颯松濤起，□□□□□氷冽。',312,'全唐诗/poet.song.113000.json','["壁間颯颯松濤起，□□□□□氷冽。", "呼燈始見王右丞，毫毛矜貴逞奇傑。", "揮灑冬山書屋圖，巖壑幽櫺坐高哲。", "數筆蕭瑟天貌寒，不盡枯枝不盡雪。", "高崕崛曲形淒肅，驅禽逐獸但松竹。", "傍有一水白於峰，千頃奔茫日難昱。", "絹外似覺風慘激，大江盡斷船相逐。", "室中之人淡如菊，長年手携一卷讀。", "窗外蒼虬恣飛瀑，欲奪造化齊冷燠。", "天下無幾焦孝然，當世寧更有梅福。", "苦吟抱膝此何人，乃肯蕭條立煉谷。", "古今書畫技總微，貴有嶔崎生眼目。", "我聞孫登居北山，隆冬披髮以自覆。", "又聞昔賢暑重裘，六月御車鄙王侯。", "二公氣岸皆千里，朗月白霜胸際浮。", "名士逆天天不怒，冬景能暖夏能秋。", "千載斯人不可致，我於畫間得其意。", "揆向高飈遠遠至，筆光墨汁俱吐棄。", "但懸此幅清吾心，千巖炎伏曦景熾，布褐推車我不避。"]'),
('a9383901-3904-48e9-9aca-a69c78d3214d','弔采石渡頭將軍','鄭樵','宋','宋诗','song-poetry','','[]','石頭城下何紛紛，將軍疋馬氣如雲。',64,'全唐诗/poet.song.113000.json','["石頭城下何紛紛，將軍疋馬氣如雲。", "金鼓死兮弓矢休，勢失英雄不自由。", "風淅淅兮月沉沉，荻花滿岸江水深。", "千年江水留明月，一片將軍報國心。"]'),
('6bc62eea-bfa7-46cd-998a-33b792cb9472','採茶行','鄭樵','宋','宋诗','song-poetry','','[]','春山曉露洗新碧，宿鳥倦飛啼石壁。',128,'全唐诗/poet.song.113000.json','["春山曉露洗新碧，宿鳥倦飛啼石壁。", "手携桃杖歌行役，鳥道紆迴愜所適。", "千樹朦朧半含白，峰巒高低如几席。", "我生偃蹇耽幽僻，撥草驅煙頻躡屐。", "采采前山慎所擇，紫芽嫩綠敢輕擲。", "龍團佳製自往昔，我今未酌神先懌。", "安得龜蒙地百尺，前種武夷後鄭宅。", "逢春吸露枝潤澤，大招二陸棲魂魄。"]'),
('bee518fd-bb3b-4ac7-8c29-a1321475dd4e','秋水歌','鄭樵','宋','宋诗','song-poetry','','[]','年年秋水崩江石，秋水年年連天碧。',64,'全唐诗/poet.song.113000.json','["年年秋水崩江石，秋水年年連天碧。", "山中草木盡號呼，江外魚龍輕虛擲。", "既憐茅屋化飛蓬，又嘆蝦蟆共枕席。", "人生變化不可知，且聽秋風吹蘿薜。"]'),
('4cae8e9f-2eab-47e8-86ad-531e4bd6a794','負耒歌','鄭樵','宋','宋诗','song-poetry','','[]','煙冉冉兮雨紛紛，負耒耜兮出柴門。',41,'全唐诗/poet.song.113000.json','["煙冉冉兮雨紛紛，負耒耜兮出柴門。", "出柴門兮踏行雲。", "茫茫山色天未分，相率歌吟兮樂耕耘。"]'),
('a32d70d1-d3b4-4eef-b51f-f7184034c9a0','插秧歌','鄭樵','宋','宋诗','song-poetry','','[]','漠漠兮水田，裊裊兮輕煙。',26,'全唐诗/poet.song.113000.json','["漠漠兮水田，裊裊兮輕煙。", "布穀啼兮人比肩，縱橫兮陌阡。"]'),
('fd9cdec2-b656-4056-b50c-6594d1428a71','餉饁歌','鄭樵','宋','宋诗','song-poetry','','[]','提筐兮阡陌，花紅兮衣白，步遲遲兮心迫迫。',37,'全唐诗/poet.song.113000.json','["提筐兮阡陌，花紅兮衣白，步遲遲兮心迫迫。", "行至止兮嗟于役，低聲相勞兮日其夕。"]'),
('1a18be45-c04f-42c2-9400-ec0969872d0c','漫興  其一','鄭樵','宋','宋诗','song-poetry','','[]','野鳥日啼戶外，凉風時入簾間。',28,'全唐诗/poet.song.113000.json','["野鳥日啼戶外，凉風時入簾間。", "老夫夢後欹枕，稚子病中解顔。"]'),
('e14d8feb-11ef-4110-9486-b25265da84b1','漫興  其二','鄭樵','宋','宋诗','song-poetry','','[]','陋巷顔回早死，柴桑陶令長生。',28,'全唐诗/poet.song.113000.json','["陋巷顔回早死，柴桑陶令長生。", "達觀千載兒戲，厭見一時利名。"]'),
('548defb1-d6ee-4d15-80ad-39a73e0a0a64','漫興  其三','鄭樵','宋','宋诗','song-poetry','','[]','門前半畝禾苗，日午翠色可描。',28,'全唐诗/poet.song.113000.json','["門前半畝禾苗，日午翠色可描。", "笑問耦耕沮溺，何勞蓑笠終朝。"]'),
('f826cd46-1224-4a2e-86ab-557edf2bd7b1','漫興  其四','鄭樵','宋','宋诗','song-poetry','','[]','今古去來有數，乾坤闔闢無涯。',28,'全唐诗/poet.song.113000.json','["今古去來有數，乾坤闔闢無涯。", "人生行雲流水，處世運甕搬柴。"]'),
('23178a9b-7485-459b-b884-f0fd8c1e916a','漫興  其五','鄭樵','宋','宋诗','song-poetry','','[]','初秋一雨新凉，子夜長吟未央。',28,'全唐诗/poet.song.113000.json','["初秋一雨新凉，子夜長吟未央。", "階下花枝冷艷，堂前佛火微茫。"]'),
('444377b2-4032-4d9d-bf55-a0fbb3687758','漫興  其六','鄭樵','宋','宋诗','song-poetry','','[]','壺山八面蒼翠，蘭水一泓漣漪。',28,'全唐诗/poet.song.113000.json','["壺山八面蒼翠，蘭水一泓漣漪。", "容我放歌問渡，憑誰拄杖支頤。"]'),
('2676e137-0d28-4470-9ef8-a6df74641582','漫興  其七','鄭樵','宋','宋诗','song-poetry','','[]','空山無人堅卧，冷竈有飯晚餐。',28,'全唐诗/poet.song.113000.json','["空山無人堅卧，冷竈有飯晚餐。", "安得原憲與語，雪霜不受天寒。"]'),
('9102ed92-cf47-4a40-bd73-4fb8f57aac9d','漫興  其八','鄭樵','宋','宋诗','song-poetry','','[]','花下閒傾濁酒，人前莫道清貧。',28,'全唐诗/poet.song.113000.json','["花下閒傾濁酒，人前莫道清貧。", "殘生全無奢願，歲月徙倚竹筠。"]'),
('72aac76b-1320-4b5a-a52c-295f65e611da','漫興  其九','鄭樵','宋','宋诗','song-poetry','','[]','臨水時思下釣，閉門聊學吞羶。',28,'全唐诗/poet.song.113000.json','["臨水時思下釣，閉門聊學吞羶。", "一身苦樂無定，萬事安危有天。"]'),
('8fd9023d-ac5c-46f5-8290-06dfdebbb451','漫興  其一○','鄭樵','宋','宋诗','song-poetry','','[]','鄰沽數盞微醉，坦腹北窗短眠。',28,'全唐诗/poet.song.113000.json','["鄰沽數盞微醉，坦腹北窗短眠。", "風送松濤聒耳，驚回夢蝶翩翩。"]'),
('f014ecb0-992d-4412-b9c8-e6a613fbd82f','福寧州藍溪寺前蒙井','鄭樵','宋','宋诗','song-poetry','','[]','靜涵空碧色，瀉自翠微巔。',24,'全唐诗/poet.song.113000.json','["靜涵空碧色，瀉自翠微巔。", "品題當第一，不讓慧山泉。"]'),
('d88607a7-587a-4746-93ec-81f997cd6889','建炎初秋不得北狩消息作','鄭樵','宋','宋诗','song-poetry','','[]','昨夜西風到漢軍，塞鴻不敢傳殷勤。',64,'全唐诗/poet.song.113000.json','["昨夜西風到漢軍，塞鴻不敢傳殷勤。", "幾山衰草連天見，何處悲笳異地聞。", "犬馬有心雖許國，草茅無路可酬君。", "微臣一縷申胥淚，不落秦庭落暮雲。"]'),
('ea960bb1-af4d-47a0-86ef-4e10572ed498','觀除夕火爆','鄭樵','宋','宋诗','song-poetry','','[]','駒隙光陰歲已殘，門門竹爆共團欒。',64,'全唐诗/poet.song.113000.json','["駒隙光陰歲已殘，門門竹爆共團欒。", "燒成焰焰丹砂瑰，碎盡琅琅碧玉竿。", "喚轉韶光新景燠，辟除惡魅舊時寒。", "主人從此占佳瑞，再入爲霖灑旱乾。"]'),
('78a66f91-462d-4d47-b2da-accc885b0820','百丈山','鄭樵','宋','宋诗','song-poetry','','[]','疊嶂聯屏飛遠近，風情物色有餘涯。',32,'全唐诗/poet.song.113000.json','["疊嶂聯屏飛遠近，風情物色有餘涯。", "回頭四顧東西地，多少礪山壯帝家。"]'),
('49ebfb7e-77fc-44d1-a9b6-730ce40dbd20','句','鄭樵','宋','宋诗','song-poetry','','[]','官似馮唐能老去，節如蘇武不生還。',16,'全唐诗/poet.song.113000.json','["官似馮唐能老去，節如蘇武不生還。"]'),
('78be21f1-036a-4d40-8bbe-891c424256b4','避地傷春六絕句  其一','葛立方','宋','宋诗','song-poetry','','[]','一年春事又闌珊，可惜芳菲愁裏看。',32,'全唐诗/poet.song.113000.json','["一年春事又闌珊，可惜芳菲愁裏看。", "慎勿掃花供餵馬，惱人秀色自堪餐。"]'),
('4af60f2f-ec80-44cc-ae0b-901280e84c8e','避地傷春六絕句  其二','葛立方','宋','宋诗','song-poetry','','[]','洛陽宮闕半成灰，草草花枝濺淚開。',32,'全唐诗/poet.song.113000.json','["洛陽宮闕半成灰，草草花枝濺淚開。", "國色天香消息斷，粧臺誰奉紫金杯。"]'),
('561dae37-49cb-48ff-bcb0-40714efdb84d','避地傷春六絕句  其三','葛立方','宋','宋诗','song-poetry','','[]','枯藤六尺步長阡，客裏韶光絕可憐。',32,'全唐诗/poet.song.113000.json','["枯藤六尺步長阡，客裏韶光絕可憐。", "好著青楓重試火，西陽三日突無煙。"]'),
('2f465348-3167-4761-981f-7f51c0c47d31','避地傷春六絕句  其四','葛立方','宋','宋诗','song-poetry','','[]','碧羅天宇亂花稠，搔首花陰只重愁。',32,'全唐诗/poet.song.113000.json','["碧羅天宇亂花稠，搔首花陰只重愁。", "頭上無貂堪換酒，開箱頼有驌驦裘。"]'),
('3b2a2701-c5a9-4494-976a-3c5a4790361d','避地傷春六絕句  其五','葛立方','宋','宋诗','song-poetry','','[]','石門連日動征鼙，花柳無情自繞谿。',32,'全唐诗/poet.song.113000.json','["石門連日動征鼙，花柳無情自繞谿。", "回首故園今好在，杜鵑花落子規啼。"]'),
('0924cdc7-30b8-404b-b020-e616ed785889','避地傷春六絕句  其六','葛立方','宋','宋诗','song-poetry','','[]','菖葉青青杏蕊新，牛耕白水一犁勻。',32,'全唐诗/poet.song.113000.json','["菖葉青青杏蕊新，牛耕白水一犁勻。", "蒨裙窺愛疏籬晚，不是沉香倚太真。"]'),
('f2637998-c855-4428-841a-8b483c78096f','和盧叔才食蛹  其一','葛立方','宋','宋诗','song-poetry','','[]','綠柘林中聽晚繅，聞將煮蛹當持螯。',32,'全唐诗/poet.song.113000.json','["綠柘林中聽晚繅，聞將煮蛹當持螯。", "何須有繭大如甕，救得妻兒啼與號。"]'),
('9c708c76-8509-4acd-9f98-d993b454c726','和盧叔才食蛹  其二','葛立方','宋','宋诗','song-poetry','','[]','開箔團團雪滿床，桃漿灑盡煮蘭湯。',32,'全唐诗/poet.song.113000.json','["開箔團團雪滿床，桃漿灑盡煮蘭湯。", "微軀分合葬君腹，報答君家三畝桑。"]'),
('e1fb204c-d04f-4e0f-8d30-9d13ee6f78eb','天寶三絕  其一','葛立方','宋','宋诗','song-poetry','','[]','凝碧池頭弦管聲，秋槐落葉若爲情。',32,'全唐诗/poet.song.113000.json','["凝碧池頭弦管聲，秋槐落葉若爲情。", "王維空詠朝天句，誰似當年雷海青。"]'),
('bc98f304-edaf-466a-82c9-702a83618eca','天寶三絕  其二','葛立方','宋','宋诗','song-poetry','','[]','翠輦重登勤政樓，紅桃依舊唱凉州。',32,'全唐诗/poet.song.113000.json','["翠輦重登勤政樓，紅桃依舊唱凉州。", "但知玉笛傳佳曲，不記鈴聲動客愁。"]'),
('a3242fd0-54fe-4b68-9463-7c167255bcd9','天寶三絕  其三','葛立方','宋','宋诗','song-poetry','','[]','綷縩黄裙墮遊水，斕斑錦襪委嵬山。',32,'全唐诗/poet.song.113000.json','["綷縩黄裙墮遊水，斕斑錦襪委嵬山。", "臂環留得知何用，羞殺新豐謝阿蠻。"]'),
('0066d956-5b46-46e5-a057-c5cb5caa48a6','携家避地  其一','葛立方','宋','宋诗','song-poetry','','[]','菟裘真可老，飄寓失初心。',48,'全唐诗/poet.song.113000.json','["菟裘真可老，飄寓失初心。", "去去家山遠，行行澤國深。", "光陰三翼過，情緒二毛侵。", "何日干戈定，鷗盟得再尋。"]'),
('c02412b4-fd7c-41ea-9162-dbc427a51dc1','携家避地  其二','葛立方','宋','宋诗','song-poetry','','[]','生身恨晼晚，喪亂適吾遭。',48,'全唐诗/poet.song.113000.json','["生身恨晼晚，喪亂適吾遭。", "百歲大槐過，三年空谷逃。", "平羌無上策，醫國付羣豪。", "年大傷蓬轉，愁城破濁醪。"]'),
('422731a6-d503-4c88-8dd2-ece406e72a5d','避地復歸故鄉','葛立方','宋','宋诗','song-poetry','','[]','二老堂邊花作林，不愁酒竭貰貂金。',64,'全唐诗/poet.song.113000.json','["二老堂邊花作林，不愁酒竭貰貂金。", "宗人避世散還聚，才子哦詩絕復尋。", "莫話衣冠一酸鼻，回思戎虜幾寒心。", "半墩仙隠吾廬在，人認桃源雞犬音。"]'),
('a9589530-9176-4d53-96b5-b546748630e6','沿檄省親復還書呈叔能同官','葛立方','宋','宋诗','song-poetry','','[]','雲間霅水往來航，風雨幾番騰客裝。',64,'全唐诗/poet.song.113000.json','["雲間霅水往來航，風雨幾番騰客裝。", "子職廢供一旬劣，官事不了三春强。", "去時園花初放白，歸日江梅如許黄。", "少復須之又西指，薰風一舸在迴塘。"]'),
('df30d2a3-3d4f-4839-ab1a-7233b3c036a0','鹽倉作呈叔能同官','葛立方','宋','宋诗','song-poetry','','[]','平生懶作子公書，俛首銓曹一紀餘。',64,'全唐诗/poet.song.113000.json','["平生懶作子公書，俛首銓曹一紀餘。", "第有神馳招隠館，久無夢到承明廬。", "文字真宜覆醤瓿，技能只合服鹽車。", "清才弗悟亦塵役，早晚促君登石渠。"]'),
('d723e022-e6b7-4bd6-9b95-96cb12cd32c4','直孺叔用韵見贈再和爲謝','葛立方','宋','宋诗','song-poetry','','[]','異時黌舍共翻書，黄卷相從樂有餘。',64,'全唐诗/poet.song.113000.json','["異時黌舍共翻書，黄卷相從樂有餘。", "十載乖離馳別夢，半生漂蕩失吾廬。", "飲江偶脫胡人馬，並海欣逢長者車。", "軟語蟬聯相勞苦，羈遊無緒領勤渠。"]'),
('d176e4e6-30ed-48c7-a15b-cbd3c62161c6','次韵陳文仲探梅二絕  其一','葛立方','宋','宋诗','song-poetry','','[]','小園邈在古城陰，爲愛寒葩杖屨尋。',32,'全唐诗/poet.song.113000.json','["小園邈在古城陰，爲愛寒葩杖屨尋。", "却笑含章簷下客，對花熟睡亦何心。"]'),
('ff19fd26-f3f5-41b0-a6a3-ba38d83c6759','次韵陳文仲探梅二絕  其二','葛立方','宋','宋诗','song-poetry','','[]','低枝垂蕊逗疏陰，不學髯龍幹百尋。',32,'全唐诗/poet.song.113000.json','["低枝垂蕊逗疏陰，不學髯龍幹百尋。", "此去江南知幾驛，只今誰動故人心。"]'),
('9c30f513-4646-4f10-8db7-e464067d7bb4','張千里惠詩次韵  其一','葛立方','宋','宋诗','song-poetry','','[]','十年風攪海波翻，未報穹廬氣踴山。',32,'全唐诗/poet.song.113000.json','["十年風攪海波翻，未報穹廬氣踴山。", "且把毛錐覷天巧，異時方叔要威蠻。"]'),
('f8f1c499-d9e0-4f62-8053-1331506003e6','張千里惠詩次韵  其二','葛立方','宋','宋诗','song-poetry','','[]','筆端玉筯更銀鈎，胸次三墳復九丘。',32,'全唐诗/poet.song.113000.json','["筆端玉筯更銀鈎，胸次三墳復九丘。", "兒輩政憂書種斷，靈膠忽至鳳麟洲。"]'),
('c0c3483e-d77c-474e-86a6-8d03b564b59d','張千里惠詩次韵  其三','葛立方','宋','宋诗','song-poetry','','[]','芝蘭楚楚峙庭階，不集尋常村裏來。',32,'全唐诗/poet.song.113000.json','["芝蘭楚楚峙庭階，不集尋常村裏來。", "新蔡門前說甘露，也應入細視庭槐。"]'),
('2c3b82a1-e61f-434c-aa0d-9e44b96d0c22','大人遊千金訪張仲宗以守舍不得侍行用仲宗韵二首  其一','葛立方','宋','宋诗','song-poetry','','[]','古寺依煙艇，一篙春水深。',48,'全唐诗/poet.song.113000.json','["古寺依煙艇，一篙春水深。", "石壇幡轉影，玉殿磬流音。", "客有張公子，僧皆支道林。", "行行雲水窟，幽夢渺難尋。"]'),
('a48a8efa-1d4f-4733-8efd-0ca8040a43f9','大人遊千金訪張仲宗以守舍不得侍行用仲宗韵二首  其二','葛立方','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','聞道千金好，幽人已奠居。',48,'全唐诗/poet.song.113000.json','["聞道千金好，幽人已奠居。", "森森松繞寺，㶁㶁水循渠。", "旅泊未妨酒，長饑猶著書。", "謫仙詩酒地，今尚指匡廬。"]'),
('0bcd75e2-668c-435e-899f-4070d9beaef4','和叔才餉酒','葛立方','宋','宋诗','song-poetry','','[]','百事不掛眼，一尊難暫忘。',120,'全唐诗/poet.song.113000.json','["百事不掛眼，一尊難暫忘。", "伻來頒酒聖，客至引杯長。", "桑落開新甕，崑崙接舊觴。", "鵝兒黄液重，象鼻碧筩香。", "銀海俄增量，金罌可配漿。", "蟻浮甘瀲灧，石飲見溫良。", "世事紛忘去，詩情合得嘗。", "醉來庭宇眩，醒後竹陰凉。", "釀鄙平原縣，鄰防吏部郎。", "糟丘誠可老，不用爾殽將。"]'),
('69b467bc-21d2-4118-a350-bf636c483fae','次韵蔡仲平察院中秋  其一','葛立方','宋','宋诗','song-poetry','','[]','素魄經秋分外明，桂枝濃傍蕊淵清。',32,'全唐诗/poet.song.113000.json','["素魄經秋分外明，桂枝濃傍蕊淵清。", "人寰散影千山白，愁絕村村砧杵鳴。"]'),
('db68f909-a5e5-46eb-b0eb-bf922710614b','次韵蔡仲平察院中秋  其二','葛立方','宋','宋诗','song-poetry','','[]','不是銀河隠半輪，滿天散彩絕埃塵。',32,'全唐诗/poet.song.113000.json','["不是銀河隠半輪，滿天散彩絕埃塵。", "幽懷想得如羅隠，耿耿相看似故人。"]'),
('dbc6a765-7de1-4e9c-a7f0-9a177882e9e0','次韵仲平病間齋祠  其一','葛立方','宋','宋诗','song-poetry','','[]','居士彈一指，森羅萬象皆。',48,'全唐诗/poet.song.113000.json','["居士彈一指，森羅萬象皆。", "聊傾三昧酒，不奉八關齋。", "雨罷簾初捲，山迎闥自排。", "蕭然忘世慮，心境兩相諧。"]'),
('854af548-9b52-4930-b9dd-a20b720e3d06','次韵仲平病間齋祠  其二','葛立方','宋','宋诗','song-poetry','','[]','病間百念屏，寒窗無與皆。',48,'全唐诗/poet.song.113000.json','["病間百念屏，寒窗無與皆。", "吾公那窟室，學士且高齋。", "今日明粢徹，詰朝閶闔排。", "猶尋淡生話，泚筆當俳諧。"]'),
('317838b5-4c8c-43cc-bd0e-e5839ad57b9b','次韵林梅卿吏部遊湖','葛立方','宋','宋诗','song-poetry','','["\u897f\u6e56"]','竟日關心朱墨間，西湖好在且偷閑。',64,'全唐诗/poet.song.113000.json','["竟日關心朱墨間，西湖好在且偷閑。", "光凌萬頃摇銀海，興愜千鍾倒玉山。", "未辦綵毫書側理，只愁赤壁下烏蠻。", "客兒忽墮池塘句，格律都高漢以還。"]'),
('68f03a9f-f7ba-4d7b-8aff-dec32f94edfb','周元舉侍郎梅花次韵三首  其一','葛立方','宋','宋诗','song-poetry','','[]','不隨羣卉艷陽天，幾樹孤芳玉磵前。',64,'全唐诗/poet.song.113000.json','["不隨羣卉艷陽天，幾樹孤芳玉磵前。", "陸凱何妨餉范曄，綠華端合伴羊權。", "憂虞莫問兵戈滿，賞玩要須酒盞先。", "雖是廣平心似鐵，也應作賦詠蕃鮮。"]'),
('4b1eab58-1076-4cb3-968b-f399a11a5e04','周元舉侍郎梅花次韵三首  其二','葛立方','宋','宋诗','song-poetry','','[]','山村疑有散花天，五出瓊瑶忽滿前。',64,'全唐诗/poet.song.113000.json','["山村疑有散花天，五出瓊瑶忽滿前。", "閨女傳香得韓壽，宮娥濡蠟照公權。", "賞心共付尊中美，索笑誰爲席上先。", "它日成陰子如豆，不堪對酒割芳鮮。"]'),
('2f74a030-399d-45f7-b433-27690d1ef737','周元舉侍郎梅花次韵三首  其三','葛立方','宋','宋诗','song-poetry','','[]','怪底窮冬凜冽天，一枝香艷媚尊前。',64,'全唐诗/poet.song.113000.json','["怪底窮冬凜冽天，一枝香艷媚尊前。", "未應黑帝專司殺，誰道青陽獨斡權。", "冷伴素蟾斜弄影，輕飛么鳳欲相先。", "坐中人是王夷甫，幽韵清標兩鬭鮮。"]'),
('010a2e9e-faaa-4163-b89e-07fd3504dd89','次韵洪慶善同飲道祖家賞梅  其一','葛立方','宋','宋诗','song-poetry','','[]','末上風光驚老眼，斬新香韵惱騷人。',32,'全唐诗/poet.song.113000.json','["末上風光驚老眼，斬新香韵惱騷人。", "霜晴日淡虛庭裏，玉骨幽貞不嫁春。"]'),
('9d1e125a-bd25-4432-aa69-015deeb4a1ea','次韵洪慶善同飲道祖家賞梅  其二','葛立方','宋','宋诗','song-poetry','','[]','麝臍飄馥來疏蕊，霜女將寒墮瘦枝。',32,'全唐诗/poet.song.113000.json','["麝臍飄馥來疏蕊，霜女將寒墮瘦枝。", "數朵臘前舒冷艷，催花羯鼓未應知。"]'),
('688f4531-9998-4b0e-a172-383b3ccbd7ad','次韵洪慶善同飲道祖家賞梅  其三','葛立方','宋','宋诗','song-poetry','','[]','寒葩脈脈畫堂新，同是巡簷索笑人。',32,'全唐诗/poet.song.113000.json','["寒葩脈脈畫堂新，同是巡簷索笑人。", "獨把幽姿伴冰雪，舒花結蕊不關春。"]'),
('d93380aa-b920-4df5-97eb-1260eab5dae0','次韵洪慶善同飲道祖家賞梅  其四','葛立方','宋','宋诗','song-poetry','','[]','立盡黄昏賞玉肌，月華無語上疏枝。',32,'全唐诗/poet.song.113000.json','["立盡黄昏賞玉肌，月華無語上疏枝。", "絕憐熟睡含章畔，無限花飛總不知。"]'),
('56b48025-047b-4c29-9a1c-f704b2941ca2','遊衢州烏巨山乾明寺','葛立方','宋','宋诗','song-poetry','','[]','烏巨山前談實諦，江郎巖畔逗真機。',32,'全唐诗/poet.song.113000.json','["烏巨山前談實諦，江郎巖畔逗真機。", "白虹示滅知何處，去採山桃又不歸。"]'),
('f5bcea86-a9e5-4d7d-8b1c-4db7e316ef69','次韵劉卿任飲散感秋之作二首  其一','葛立方','宋','宋诗','song-poetry','','[]','雲子登場賽鼓讙，村南村北盡黄冠。',64,'全唐诗/poet.song.113000.json','["雲子登場賽鼓讙，村南村北盡黄冠。", "幾聲乾葉下碧甃，數尺瘦山浮畫欄。", "水落野橋魚網掛，月懸煙浦鵲枝寒。", "新秋愁絕他鄉客，衣带年來如沈寬。"]'),
('38465ea4-ce40-4237-9f7c-f3a99f247607','次韵劉卿任飲散感秋之作二首  其二','葛立方','宋','宋诗','song-poetry','','[]','華堂不料著野客，菲屨底同章甫冠。',64,'全唐诗/poet.song.113000.json','["華堂不料著野客，菲屨底同章甫冠。", "鷗外翠光清醉眼，尊前爽氣動危欄。", "霜沉紫荇玉奩闊，風脫丹林煙髺寒。", "百榼香醪消萬斛，酒中跌宕頼君寬。"]'),
('50e6c3fb-8869-47a6-bd1b-e4c4fa28ed14','小酌以詩招道祖分茶','葛立方','宋','宋诗','song-poetry','','[]','寶胯開緗葉，香塵墮柘羅。',48,'全唐诗/poet.song.113000.json','["寶胯開緗葉，香塵墮柘羅。", "湯鳴簷雨細，盞占隴雲多。", "連日伊蒲塞，今朝熱洛河。", "春風入詩腹，五字與君哦。"]'),
('762cc8d6-0842-4528-87e3-66b448d7aee6','九日慶善示詩次韵','葛立方','宋','宋诗','song-poetry','','[]','眼明逢九日，習氣自多生。',48,'全唐诗/poet.song.113000.json','["眼明逢九日，習氣自多生。", "官冷有閑趣，花開無世情。", "玄囂何許是，素滻第存名。", "百歲風狂似，東籬且掇英。"]'),
('95f1084a-1c25-4f93-9aa1-34280b815d05','比訪叔才旋蒙賜詩以貧不能留客爲愧次韵','葛立方','宋','宋诗','song-poetry','','[]','一舸風帆放晚秋，訪君幽巷卜淹留。',64,'全唐诗/poet.song.113000.json','["一舸風帆放晚秋，訪君幽巷卜淹留。", "綠摇岸柳容如舞，碧蘸溪毛美可羞。", "喜見林宗鑾爲輟，久欽阿大語難休。", "士貧雞黍無勞具，謀食何如道可謀。"]'),
('78d2f088-9899-487b-9f2e-8a4ba1d48c45','和道祖韵','葛立方','宋','宋诗','song-poetry','','[]','未落天狼未止戈，誰能頻擊唾壺歌。',64,'全唐诗/poet.song.113000.json','["未落天狼未止戈，誰能頻擊唾壺歌。", "弈棋聊欲消憂耳，飲酒無如作病何。", "孫紹那憂卿太少，退之莫歎日無多。", "菟裘已向菁山卜，從此棲遲到髮皤。"]'),
('f8f623a6-749c-4cc2-84de-50500113fbc1','大人築室將畢道祖亦作宅基治園作四詩示道祖  其一','葛立方','宋','宋诗','song-poetry','','[]','習隠肯回駕，求榮難著鞭。',48,'全唐诗/poet.song.113000.json','["習隠肯回駕，求榮難著鞭。", "有心營綠野，無夢到凌煙。", "盞斝花開裏，簷楹雁落邊。", "冰清仍玉潤，共此一山川。"]'),
('8a262dcc-a893-427f-be4a-09e911cec54e','大人築室將畢道祖亦作宅基治園作四詩示道祖  其二','葛立方','宋','宋诗','song-poetry','','[]','蓬轉欣小定，泛金非我鄉。',48,'全唐诗/poet.song.113000.json','["蓬轉欣小定，泛金非我鄉。", "買田無好畤，共宅有清漳。", "菱罷水天接，風來花草香。", "邗溝風月地，怊悵隔參商。"]'),
('511a553f-528b-4c13-bb3d-626d94392ef7','大人築室將畢道祖亦作宅基治園作四詩示道祖  其三','葛立方','宋','宋诗','song-poetry','','[]','兩第屹相向，幽園卑辟彊。',48,'全唐诗/poet.song.113000.json','["兩第屹相向，幽園卑辟彊。", "君方林上塢，吾亦沼橫洋。", "鑿翠闢窗戶，入天棲棟梁。", "東屯寒月夜，老杜只茅堂。"]'),
('6a15ac8a-a664-4bd3-a021-d8ff7a00ca89','大人築室將畢道祖亦作宅基治園作四詩示道祖  其四','葛立方','宋','宋诗','song-poetry','','[]','世事只如許，幽居誠樂哉。',48,'全唐诗/poet.song.113000.json','["世事只如許，幽居誠樂哉。", "報安知楚竹，索笑得江梅。", "岸放平湖入，窗邀遠岫來。", "兩家車馬地，莫遣染蒼苔。"]'),
('1751f350-4c47-495d-911a-85d6f5f763de','風起','葛立方','宋','宋诗','song-poetry','','[]','炎蒸困鉗釱，虎嘯漏天機。',48,'全唐诗/poet.song.113000.json','["炎蒸困鉗釱，虎嘯漏天機。", "樹杪忽垂髻，榴邊今污衣。", "草鳴溪水立，帆飽客船飛。", "更設琉璃簟，瓜茶遲落暉。"]'),
('bc1f8b7a-4ddf-4d9d-8ce3-46ca61193c9f','十月十四夜三鼓壺天月色佳甚以詩招道祖','葛立方','宋','宋诗','song-poetry','','[]','壺天有勝事，玉宇浄纖埃。',48,'全唐诗/poet.song.113000.json','["壺天有勝事，玉宇浄纖埃。", "有意嚼復嚼，今宵來不來。", "山公須酩酊，令史莫咍臺。", "明月隔溪共，只今腸九回。"]'),
('690292a7-6c90-438c-b547-21e61fbea1f3','次韵道祖書懷','葛立方','宋','宋诗','song-poetry','','[]','白雲深處縛柴荆，一壑灣環似有情。',64,'全唐诗/poet.song.113000.json','["白雲深處縛柴荆，一壑灣環似有情。", "志氣蕭娘並呂姥，年華張丈與殷兄。", "濁賢清聖時同酌，上尾平頭得共評。", "莫問鶴翎由啄菢，此心久與白鷗盟。"]'),
('5d6dd7a2-c9c2-474c-8e31-d680cdf427fc','次韵法觀送紅梅栽','葛立方','宋','宋诗','song-poetry','','[]','羅襪初凌一水間，霜深應怯夜來寒。',32,'全唐诗/poet.song.113000.json','["羅襪初凌一水間，霜深應怯夜來寒。", "含章簷下渾冰雪，却要騷人带醉看。"]'),
('34152931-9675-4397-8c9b-e060ab15e698','胡樞橫山堂  其一','葛立方','宋','宋诗','song-poetry','','[]','鬰葱佳氣龜食墨，霧閤雲窗丹雘新。',64,'全唐诗/poet.song.113000.json','["鬰葱佳氣龜食墨，霧閤雲窗丹雘新。", "玉碗金杯有微玷，瑶林瓊樹無纖塵。", "枕溪飽度國山日，橫海小乖朐水春。", "上古乾坤隨處有，素琴濁酒且關身。"]'),
('a519bfdc-1b50-4e3c-968a-43f34a9d9cab','胡樞橫山堂  其二','葛立方','宋','宋诗','song-poetry','','[]','雲夢胸中吞八九，了無官事苦相關。',64,'全唐诗/poet.song.113000.json','["雲夢胸中吞八九，了無官事苦相關。", "廟堂曾引五星縷，巖壑今疏八節灘。", "鳥織白雲機杼闊，溪喧蒼石杵碪寒。", "東山難戀山中相，梅子枝頭正著酸。"]'),
('977559a3-dde3-46b3-b93d-4eb3faba2919','胡樞橫山堂  其三','葛立方','宋','宋诗','song-poetry','','[]','朱甍碧瓦市廛遠，繞舍泉啼山復橫。',64,'全唐诗/poet.song.113000.json','["朱甍碧瓦市廛遠，繞舍泉啼山復橫。", "勝處爭長渾僕妾，亂來有此幾公卿。", "巳公茅屋實父子，裴氏午橋真弟兄。", "竟日倚欄天外眼，世間軒冕一毫輕。"]'),
('4b7d30e4-4f4a-43c6-a270-62391402e585','胡樞橫山堂  其四','葛立方','宋','宋诗','song-poetry','','[]','春過木濃山轉翠，旱餘湍減石添痕。',64,'全唐诗/poet.song.113000.json','["春過木濃山轉翠，旱餘湍減石添痕。", "主人正自笏拄頰，客子底容裾撇門。", "好鳥傍人窺野核，亂雲釋嶠落芳尊。", "真成命駕輕千里，李杜文章得細論。"]'),
('e07a16dc-ceef-4c21-ae21-170358fa2d92','胡樞橫山堂  其五','葛立方','宋','宋诗','song-poetry','','[]','天然平遠染百幅，泚筆底須東絹傳。',64,'全唐诗/poet.song.113000.json','["天然平遠染百幅，泚筆底須東絹傳。", "窗戶吐吞新日月，風煙出沒舊山川。", "白公築室地三一，楊子草玄文五千。", "筋力尚堪驅使在，異時重泛白蘋船。"]'),
('04745eb6-dd1a-47fe-bb2b-4a79d2512d5c','連日灌畦蒔菜廢作詩','葛立方','宋','宋诗','song-poetry','','[]','莫問新來額插犀，了無魂夢到金閨。',64,'全唐诗/poet.song.113000.json','["莫問新來額插犀，了無魂夢到金閨。", "平頭上尾慵搜句，重後輕前且灌畦。", "正自無人嘗鼎臠，不如有客辦萍虀。", "庾郎三九同芻豢，野薺從教施五溪。"]'),
('7d9b6b20-89f0-46db-a14c-03eabe77fff7','送李元孟赴湖南漕屬','葛立方','宋','宋诗','song-poetry','','[]','君忽湘潭去，斜陽催馬銜。',48,'全唐诗/poet.song.113000.json','["君忽湘潭去，斜陽催馬銜。", "將無衝白髮，正坐此青衫。", "暑雨驅魚婢，薰風入鱟帆。", "南來衡嶽雁，引領望書函。"]'),
('af057413-ee7e-4a0d-8bd0-5d9067093d6a','疏慵','葛立方','宋','宋诗','song-poetry','','[]','閑處著疏慵，鮮鮮幽桂叢。',48,'全唐诗/poet.song.113000.json','["閑處著疏慵，鮮鮮幽桂叢。", "讀書聊竈北，避世且牆東。", "市駿卑蘇代，求徵謝子公。", "丹心阻閶闔，欲付小心風。"]'),
('55a2e8ef-05ea-4241-b722-6dc6e9539976','題卧屏十八花 姚黄','葛立方','宋','宋诗','song-poetry','','[]','抗旌汾浦根移白，豎箔藍關花染紅。',32,'全唐诗/poet.song.113000.json','["抗旌汾浦根移白，豎箔藍關花染紅。", "欲識龍媒空萬馬，宮袍黄挾御爐風。"]'),
('b02ec4dc-5b1c-4bbb-a7bc-9d50fa71444f','題卧屏十八花 八仙','葛立方','宋','宋诗','song-poetry','','[]','瑶林瓊樹非人世，種得仙花雪作團。',32,'全唐诗/poet.song.113000.json','["瑶林瓊樹非人世，種得仙花雪作團。", "后土祠邊還寂寞，只今空對畫圖看。"]'),
('713d1158-3615-4c32-a872-cdd8e9524343','題卧屏十八花 榴花','葛立方','宋','宋诗','song-poetry','','[]','琴軫含房風未吹，盈盈脈脈度炎暉。',32,'全唐诗/poet.song.113000.json','["琴軫含房風未吹，盈盈脈脈度炎暉。", "怪來一夜丹鬚拆，杯酒新翻阿措衣。"]'),
('71c8be0a-8d46-4063-bf68-ea56fb9683fa','題卧屏十八花 薔薇','葛立方','宋','宋诗','song-poetry','','[]','香風細細入東榮，嫩刺柔條疊絳英。',32,'全唐诗/poet.song.113000.json','["香風細細入東榮，嫩刺柔條疊絳英。", "飛下神霞緣底事，剪來曾倩董雙成。"]'),
('3d3ae6f5-d86c-4e63-af7d-28bf1b45a5cd','題卧屏十八花 杜鵑花','葛立方','宋','宋诗','song-poetry','','[]','雲昏水暖草萋萋，空谷無人獨杖藜。',32,'全唐诗/poet.song.113000.json','["雲昏水暖草萋萋，空谷無人獨杖藜。", "却憶西江石樓老，送春花下子規啼。"]'),
('ee721b9b-a4ba-4c0a-9a4f-5ea1269b30d8','題卧屏十八花 牡丹','葛立方','宋','宋诗','song-poetry','','[]','北廊東院滿畦栽，嫩紫輕紅次第開。',32,'全唐诗/poet.song.113000.json','["北廊東院滿畦栽，嫩紫輕紅次第開。", "直與戎葵較多少，二千里外一枝來。"]'),
('7d8a844f-eab6-4373-810c-75101b5a2f5e','題卧屏十八花 山茶','葛立方','宋','宋诗','song-poetry','','[]','十月幽園開曉風，層層絳蕊艷芳叢。',32,'全唐诗/poet.song.113000.json','["十月幽園開曉風，層層絳蕊艷芳叢。", "江南只慣收鷹爪，誰顧山前鶴頂紅。"]'),
('16bb0e29-d1a0-4bfe-bad5-aab26262246f','題卧屏十八花 梅花','葛立方','宋','宋诗','song-poetry','','[]','含章英落佳人睡，却月香殘水部詩。',32,'全唐诗/poet.song.113000.json','["含章英落佳人睡，却月香殘水部詩。", "何似江南覓春信，和香先得最南枝。"]'),
('e7d7653b-3d90-466d-9ff4-27a5a86e2784','題卧屏十八花 蜀葵','葛立方','宋','宋诗','song-poetry','','[]','傾心小圃陽初照，束火中庭雨不霑。',32,'全唐诗/poet.song.113000.json','["傾心小圃陽初照，束火中庭雨不霑。", "裊那腰支渾欲舞，好令韓偓賦香奩。"]'),
('a886ba02-7f25-429f-9386-0524ddea44ea','題卧屏十八花 杏花','葛立方','宋','宋诗','song-poetry','','[]','頼鄉仙種手親栽，春閙枝頭滿意開。',32,'全唐诗/poet.song.113000.json','["頼鄉仙種手親栽，春閙枝頭滿意開。", "正拂文君酒壚上，莫教蜂蝶等閑來。"]'),
('4bb257ee-6277-44fd-8a5c-a6a8cd99a41f','題卧屏十八花 酴醿','葛立方','宋','宋诗','song-poetry','','[]','玉骨檀心不肯粧，牽絲引蔓過東牆。',32,'全唐诗/poet.song.113000.json','["玉骨檀心不肯粧，牽絲引蔓過東牆。", "政須把酒酬清艷，莫待幽香閟枕囊。"]'),
('12f54036-fdd8-44b6-be40-a6c2f1a1ce5c','題卧屏十八花 海棠','葛立方','宋','宋诗','song-poetry','','[]','濯錦江邊雨露勻，杜鵑啼血染香繒。',32,'全唐诗/poet.song.113000.json','["濯錦江邊雨露勻，杜鵑啼血染香繒。", "自緣佳處詩難貌，可是無花開杜陵。"]'),
('5f8ba5c4-9fa3-4c10-a240-4dc3d69c8e40','題卧屏十八花 黄菊','葛立方','宋','宋诗','song-poetry','','[]','秋入重陽氣倍清，東籬採菊眼偏明。',32,'全唐诗/poet.song.113000.json','["秋入重陽氣倍清，東籬採菊眼偏明。", "杯中要作茱萸伴，不是湘纍餐落英。"]'),
('f4588feb-3212-41b0-8c9c-4023889f2648','題卧屏十八花 芍藥','葛立方','宋','宋诗','song-poetry','','[]','沉水飄香透蕊塵，紅燈爍爍一枝春。',32,'全唐诗/poet.song.113000.json','["沉水飄香透蕊塵，紅燈爍爍一枝春。", "鼠姑倚檻雖無頼，未肯甘爲近侍臣。"]'),
('c5b462e4-5d4f-4e0f-9507-a01334bee265','題卧屏十八花 桃花','葛立方','宋','宋诗','song-poetry','','[]','細看裂錦又蒸霞，黄師塔前江上花。',32,'全唐诗/poet.song.113000.json','["細看裂錦又蒸霞，黄師塔前江上花。", "折得一枝明老眼，與兒洗面作容華。"]'),
('dc23f317-7590-4b0a-9803-739485f3312f','題卧屏十八花 苣霜','葛立方','宋','宋诗','song-poetry','','[]','密葉高叢傲歲寒，殷紅膩綠映江干。',32,'全唐诗/poet.song.113000.json','["密葉高叢傲歲寒，殷紅膩綠映江干。", "沉香亭畔無消息，頼有霜前秋牡丹。"]'),
('f24ed5c7-a82c-4308-b122-7486b4edc25b','題卧屏十八花 牽牛竹','葛立方','宋','宋诗','song-poetry','','[]','高節本爲青女伴，牽牛弗悟配龍孫。',32,'全唐诗/poet.song.113000.json','["高節本爲青女伴，牽牛弗悟配龍孫。", "孔融天下無雙士，並坐尊前對虎賁。"]'),
('609c0e71-681f-4fbb-baea-1adcc4a4d914','題卧屏十八花 白菊','葛立方','宋','宋诗','song-poetry','','[]','天上新栽琪樹枝，拖雲带月下瑶墀。',32,'全唐诗/poet.song.113000.json','["天上新栽琪樹枝，拖雲带月下瑶墀。", "須知正自真仙種，豈是金鈿未染時。"]'),
('6358cb3c-453e-4ad9-9d15-2a55126c8db7','不飲','葛立方','宋','宋诗','song-poetry','','[]','蒲團藜杖屋三間，世故真成觸與蠻。',64,'全唐诗/poet.song.113000.json','["蒲團藜杖屋三間，世故真成觸與蠻。", "但有雲山供送目，儻無尊酒亦開顔。", "吳宮雪紵鶴翎散，歷社風荷象鼻彎。", "老子何曾持入夢，百年鼎鼎鬢毛班。"]'),
('e04ee502-7a6f-4d7d-affe-2822a74527a9','月蝕','葛立方','宋','宋诗','song-poetry','','[]','六月炎歊氣鬰蒸，緣空寶鏡沒埃塵。',64,'全唐诗/poet.song.113000.json','["六月炎歊氣鬰蒸，緣空寶鏡沒埃塵。", "長歌不見徘徊影，並出初無齟齬輪。", "麟鬭何因識星度，鵲飛誰復見天津。", "春秋不著誠非異，毋惑東家號素臣。"]'),
('9810041e-fd0b-4756-bd08-79b9634a2840','十一月十日酒散已二鼓與千里步月因至水堂  其一','葛立方','宋','宋诗','song-poetry','','[]','雪後泥方凍，酒闌寒少威。',48,'全唐诗/poet.song.113000.json','["雪後泥方凍，酒闌寒少威。", "傍雲生夜月，喚客出柴扉。", "籬敗犬聲合，街閑人影稀。", "石欄山幾尺，暝靄只依依。"]'),
('374a2569-4147-4092-bd46-387963e17a5b','十一月十日酒散已二鼓與千里步月因至水堂  其二','葛立方','宋','宋诗','song-poetry','','[]','夢入千家枕，寒聲薄水堂。',48,'全唐诗/poet.song.113000.json','["夢入千家枕，寒聲薄水堂。", "溪山渾著月，梅竹半封霜。", "夜榜響葭浦，寒魚跳石塘。", "可憐清絕景，夜夜屬漁郎。"]'),
('6201843e-3958-4308-bedf-d740ec59f52a','十一月十日酒散已二鼓與千里步月因至水堂  其三','葛立方','宋','宋诗','song-poetry','','[]','杖策踏霜月，滿空煙霧浮。',48,'全唐诗/poet.song.113000.json','["杖策踏霜月，滿空煙霧浮。", "蒼顔酡蟻酒，黑帝避貂裘。", "太液池臺晚，廣寒宮殿秋。", "歸來清耿耿，未省喘吳牛。"]'),
('3d206c0a-a983-4068-afef-58b5a1443379','冬至小雨踏泥出謁','葛立方','宋','宋诗','song-poetry','','[]','葭灰動玉琯，絲雨慘良辰。',48,'全唐诗/poet.song.113000.json','["葭灰動玉琯，絲雨慘良辰。", "幽巷未通屐，高人猶墊巾。", "底忙持爵里，衝冷候比隣。", "猶勝邯鄲驛，燈前影伴身。"]'),
('5e3f2a18-c813-468d-8136-b0722cdd3029','聞歌二絕  其一','葛立方','宋','宋诗','song-poetry','','[]','初唱城闉雁影寒，玉喉䆗窱嚲雲簪。',32,'全唐诗/poet.song.113000.json','["初唱城闉雁影寒，玉喉䆗窱嚲雲簪。", "小叢底處傳歌樣，供奉梨園人姓南。"]'),
('5b5e2bd4-dee6-4937-a64f-473df2b60c83','聞歌二絕  其二','葛立方','宋','宋诗','song-poetry','','[]','月明如鏡酒如空，響谷清聲出漢宮。',32,'全唐诗/poet.song.113000.json','["月明如鏡酒如空，響谷清聲出漢宮。", "怪得中庭紅葉墮，琉璃帳底唱迴風。"]'),
('cb4c87b4-a0bf-4f85-ba10-53c4f2ac5fd2','有感  其一','葛立方','宋','宋诗','song-poetry','','[]','將軍塞上誇三箭，學士堂中記八磚。',32,'全唐诗/poet.song.113000.json','["將軍塞上誇三箭，學士堂中記八磚。", "正眼觀來都是幻，月明羣蟻在花氈。"]'),
('317c5772-38e9-4e76-b790-552a744ce687','有感  其二','葛立方','宋','宋诗','song-poetry','','[]','莫將橫笛衒柯亭，豈解穿雲裂石聲。',32,'全唐诗/poet.song.113000.json','["莫將橫笛衒柯亭，豈解穿雲裂石聲。", "湘水老翁那復見，世間誰數呂筠卿。"]');
